ght\";i:600;s:8:\"filesize\";i:76826;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:93:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/KIPM-IMPORTANT-ANNOUNCEMENT-1000x600.jpg\";}s:14:\"mvp-post-thumb\";a:6:{s:4:\"file\";s:40:\"KIPM-IMPORTANT-ANNOUNCEMENT-1000x600.jpg\";s:5:\"width\";i:1000;s:6:\"height\";i:600;s:8:\"filesize\";i:76826;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:93:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/KIPM-IMPORTANT-ANNOUNCEMENT-1000x600.jpg\";}s:14:\"mvp-port-thumb\";a:6:{s:4:\"file\";s:39:\"KIPM-IMPORTANT-ANNOUNCEMENT-560x600.jpg\";s:5:\"width\";i:560;s:6:\"height\";i:600;s:8:\"filesize\";i:63710;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:92:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/KIPM-IMPORTANT-ANNOUNCEMENT-560x600.jpg\";}s:15:\"mvp-large-thumb\";a:6:{s:4:\"file\";s:39:\"KIPM-IMPORTANT-ANNOUNCEMENT-590x354.jpg\";s:5:\"width\";i:590;s:6:\"height\";i:354;s:8:\"filesize\";i:36760;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:92:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/KIPM-IMPORTANT-ANNOUNCEMENT-590x354.jpg\";}s:13:\"mvp-mid-thumb\";a:6:{s:4:\"file\";s:39:\"KIPM-IMPORTANT-ANNOUNCEMENT-400x240.jpg\";s:5:\"width\";i:400;s:6:\"height\";i:240;s:8:\"filesize\";i:21201;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:92:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/KIPM-IMPORTANT-ANNOUNCEMENT-400x240.jpg\";}s:15:\"mvp-small-thumb\";a:6:{s:4:\"file\";s:37:\"KIPM-IMPORTANT-ANNOUNCEMENT-80x80.jpg\";s:5:\"width\";i:80;s:6:\"height\";i:80;s:8:\"filesize\";i:6111;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:90:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/KIPM-IMPORTANT-ANNOUNCEMENT-80x80.jpg\";}s:4:\"full\";a:5:{s:4:\"file\";s:31:\"KIPM-IMPORTANT-ANNOUNCEMENT.jpg\";s:5:\"width\";i:1920;s:6:\"height\";i:1080;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:84:\"https://blog.kenfinly.com/wp-conte