re.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:15:{s:2:\"id\";i:5562;s:4:\"date\";s:19:\"2025-07-15T14:44:54\";s:4:\"slug\";s:35:\"harley-finkelstein-lam-moi-ban-than\";s:4:\"type\";s:10:\"attachment\";s:4:\"link\";s:100:\"https://blog.kenfinly.com/ky-nang/phat-trien-ca-nhan/attachment/harley-finkelstein-lam-moi-ban-than/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:79:\"Shopify entrepreneurship journey: keys to personal growth and business success.\";}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:7:\"caption\";a:1:{s:8:\"rendered\";s:236:\"<p>Phát triển cá nhân through entrepreneurship with Shopify, highlighting essential secrets to discovering passion and achieving career success as shown by the smiling individual embracing business transformation opportunities</p>\n\";}s:8:\"alt_text\";s:54:\"harley finkelstein smiling in front of a Shopify logo.\";s:10:\"media_type\";s:5:\"image\";s:9:\"mime_type\";s:9:\"image/png\";s:13:\"media_details\";a:6:{s:5:\"width\";i:960;s:6:\"height\";i:540;s:4:\"file\";s:47:\"2025/07/harley-finkelstein-Lam-Moi-Ban-Than.png\";s:8:\"filesize\";i:203319;s:5:\"sizes\";a:11:{s:21:\"woocommerce_thumbnail\";a:6:{s:4:\"file\";s:47:\"harley-finkelstein-Lam-Moi-Ban-Than-450x450.png\";s:5:\"width\";i:450;s:6:\"height\";i:450;s:8:\"filesize\";i:310772;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:100:\"https://blog.kenfinly.com/wp-content/uploads/2025/07/harley-finkelstein-Lam-Moi-Ban-Than-450x450.png\";}s:29:\"woocommerce_gallery_thumbnail\";a:6:{s:4:\"file\";s:47:\"harley-finkelstein-Lam-Moi-Ban-Than-100x100.png\";s:5:\"width\";i:100;s:6:\"height\";i:100;s:8