/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24&d=mm&r=g\";i:48;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=48&d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:15:{s:2:\"id\";i:5313;s:4:\"date\";s:19:\"2025-06-28T10:55:46\";s:4:\"slug\";s:23:\"tuduynguoigiaukipmtuduy\";s:4:\"type\";s:10:\"attachment\";s:4:\"link\";s:110:\"https://blog.kenfinly.com/ky-nang/t-harv-eker-chia-se-ve-tu-duy-nguoi-giau/attachment/tuduynguoigiaukipmtuduy/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:23:\"TuduyNguoiGiauKipmtuduy\";}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:7:\"caption\";a:1:{s:8:\"rendered\";s:94:\"<p>Embrace tư duy người giàu: Transform your mindset, achieve extraordinary results.</p>\n\";}s:8:\"alt_text\";s:94:\"New mindset leads to new results, illustrating tư duy người giàu (rich people\'s mindset).\";s:10:\"media_type\";s:5:\"image\";s:9:\"mime_type\";s:10:\"image/jpeg\";s:13:\"media_details\";a:6:{s:5:\"width\";i:800;s:6:\"height\";i:534;s:4:\"file\";s:35:\"2025/06/TuduyNguoiGiauKipmtuduy.jpg\";s:8:\"filesize\";i:64357;s:5:\"sizes\";a:7:{s:21:\"woocommerce_thumbnail\";a:6:{s:4:\"file\";s:35:\"TuduyNguoiGiauKipmtuduy-450x450.jpg\";s:5:\"width\";i:450;s:6:\"height\";i:450;s:8:\"filesize\";i:34804;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:88:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/TuduyNguoiGiauKipmtuduy-450x450.jpg\";}s:29:\"woocommerce_gallery_thumbnail\";a:6:{s:4:\"file\";s:35:\"TuduyNguoiGiauKipmtuduy-100x100.jpg\";s:5:\"width\";