p/v2/tags?post=5306\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}s:9:\"_embedded\";a:3:{s:6:\"author\";a:1:{i:0;a:8:{s:2:\"id\";i:1;s:4:\"name\";s:9:\"Dieter R.\";s:3:\"url\";s:16:\"http://kenkai.vn\";s:11:\"description\";s:401:\"Xin chào, tôi là Dieter R., một cây bút đam mê tại KenkAI.vn, đang sinh sống và làm việc tại Thành phố Hồ Chí Minh sôi động. Với niềm đam mê mãnh liệt về lĩnh vực lãnh đạo, tâm lý học, trí tuệ nhân tạo, công nghệ và phát triển bản thân, tôi luôn nỗ lực mang đến những nội dung giá trị và sâu sắc cho độc giả.\";s:4:\"link\";s:40:\"https://blog.kenfinly.com/author/dieter/\";s:4:\"slug\";s:6:\"dieter\";s:11:\"avatar_urls\";a:3:{i:24;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24&d=mm&r=g\";i:48;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=48&d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:15:{s:2:\"id\";i:5310;s:4:\"date\";s:19:\"2025-06-27T09:31:14\";s:4:\"slug\";s:35:\"think-creative-creativity-kipmtuduy\";s:4:\"type\";s:10:\"attachment\";s:4:\"link\";s:62:\"https://blog.kenfinly.com/think-creative-creativity-kipmtuduy/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:35:\"Think Creative Creativity kipmtuduy\";}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:7:\"caption\";a:1:{s:8:\"rendered\";s:64:\"<p>Tư duy sáng tạo: Khai phóng tiềm năng trí tuệ</p>\n\";}s:8:\"alt_text\";s:23:\"Bóng đèn sáng tạo\";s:10:\"media_type\";s:5:\"image\";s:9:\"mime_type\";s:10:\"image/jpeg\";s:13:\"media_details\";a:6:{s:5:\"width\";i:1024;s:6:\"height\";i:649;s:4:\"file\";s:47:\"2025/06/Think-Creative-Creativity-kipmtuduy.jpg\";s:8:\"filesize\";i:85511;s:5:\"sizes\";a:7:{s:21:\"woocommerce_thumbnail\";a:6:{s:4:\"file\";s:47:\"Think-Creative-Creativity-kipmtuduy-450x450.jpg\";s:5:\"width\";i:450;s:6:\"height\";i:450;s:8:\"filesize\";i:34141;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:100:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/Think-Creative-Creativity-kipmtuduy-450x450.jpg\";}s:29:\"woocommerce_gallery_thumbnail\";a:6:{s:4:\"file\";s:47:\"Think-Creative-Creativity-kipmtuduy-100x100.jpg\";s:5:\"width\";i:100;s:6:\"height\";i:100;s:8:\"filesize\";i:3574;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:100:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/Think-Creative-Creativity-kipmtuduy-100x100.jpg\";}s:18:\"woocommerce_single\";a:6:{s:4:\"file\";s:47:\"Think-Creative-Creativity-kipmtuduy-600x380.jpg\";s:5:\"width\";i:600;s:6:\"height\";i:380;s:8:\"filesize\";i:36233;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:100:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/Think-Creative-Creativity-kipmtuduy-600x380.jpg\";}s:6:\"medium\";a:6:{s:4:\"file\";s:47:\"Think-Creative-Creativity-kipmtuduy-300x190.jpg\";s:5:\"width\";i:300;s:6:\"height\";i:190;s:8:\"filesize\";i:25219;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:100:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/Think-Creative-Creativity-kipmtuduy-300x190.jpg\";}s:9:\"thumbnail\";a:6:{s:4:\"file\";s:47:\"Think-Creative-Creativity-kipmtuduy-150x150.jpg\";s:5:\"width\";i:150;s:6:\"height\";i:150;s:8:\"filesize\";i:17976;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:100:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/Think-Creative-Creativity-kipmtuduy-150x150.jpg\";}s:12:\"medium_large\";a:6:{s:4:\"file\";s:47:\"Think-Creative-Creativity-kipmtuduy-768x4