\";s:4:\"slug\";s:3:\"seo\";s:8:\"taxonomy\";s:8:\"category\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/categories/729\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/categories\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/category\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?categories=729\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}i:1;a:0:{}}}}i:1;a:26:{s:2:\"id\";i:4632;s:4:\"date\";s:19:\"2025-05-07T18:19:52\";s:8:\"date_gmt\";s:19:\"2025-05-07T11:19:52\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=4632\";}s:8:\"modified\";s:19:\"2025-05-07T18:29:15\";s:12:\"modified_gmt\";s:19:\"2025-05-07T11:29:15\";s:4:\"slug\";s:20:\"suc-manh-moi-quan-he\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:52:\"https://blog.kenfinly.com/sach/suc-manh-moi-quan-he/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:28:\"Sức Mạnh Mối Quan Hệ\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:16230:\"\n<p>Tìm hiểu tại sao mối quan hệ là chìa khóa mở mọi cánh cửa thành công. Bài viết hướng dẫn cách xây dựng có chủ đích mạng lưới mối quan hệ tích cực, giúp bạn thăng tiến trong sự nghiệp và cuộc sống.</p>\n\n\n\n<figure class=\"wp-block-audio\"><audio controls src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/money-matter.mp3\" loop></audio><figcaption class=\"wp-element-caption\">Nghe đọc bài</figcaption></figure>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-20-1024x683.png\" alt=\"Cái bắt tay chân thành, biểu tượng cho sự khởi đầu hoặc củng cố mối quan hệ trong kinh doanh và cuộc sống\" class=\"wp-image-4635\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-20-1024x683.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-20-600x400.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-20-300x200.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-20-768x512.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-20-1536x1024.png 1536w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-20.png 1600w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></figure>\n\n\n\n<style>\n.toc-content {\n    color: #000;\n    font-size: 24px;\n    margin-bottom: 20px;\n    display: flex;\n    align-items: center;\n}\n\n#toggleButton_4632 {\n    margin-left: 15px;\n    padding: 3px 8px;\n    background-color: #ffA500;\n    color: #fff;\n    border: none;\n    cursor: pointer;\n    border-radius: 3px;\n    text-transform: uppercase;\n    letter-spacing: 0.5px;\n    opacity: 0.8;\n    transition: opacity 0.3s ease;\n}\n\n#toggleButton_4632:hover {\n    opacity: 1;\n}\n\n#contentList_4632 {\n    display: none;\n    transition: all 0.3s ease;\n}\n\n#contentList_4632 > .toc-item {\n    color: #ffa500;\n    font-size: 16px;\n    margin-bottom: 10px;\n    line-height: 1.5;\n}\n\n#contentList_4632 .toc-subitem {\n    color: #ffA500;\n    font-size: 14px;\n    margin-left: 20px;\n    opacity: 0.8;\n}\n\n#contentList_4632 a {\n    color: #ffA500;\n}\n</style>\n\n<div class=\"toc-content\">\n    Nội dung\n    <button id=\"toggleButton_4632\">Xem</button>\n</div>\n\n<div id=\"contentList_4632\">\n    <div class=\"toc-item\"><a href=\"#relationships-key\">Mối Quan Hệ &#8211; Chìa Khóa Mở Mọi Cánh Cửa</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#practical-actions\">NHỮNG HÀNH ĐỘNG THỰC TIỄN</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#principle-7-money\">Nguyên tắc 7 &#8211; Vấn đề Tiền bạc</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#wealth-origin\">Nguồn Gốc Thực Sự của Sự Giàu Có</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#everyone-starts-zero\">Mọi Người Đều Bắt Đầu Từ Con Số Không</a></div>\n</div>\n\n<script>\nconst toggleButton_4632 = document.getElementById(\"toggleButton_4632\");\nconst contentList_4632 = document.getElementById(\"contentList_4632\");\nlet isVisible = false;\n\ntoggleButton_4632.addEventListener(\'click\', () => {\n    if (!isVisible) {\n        contentList_4632.style.display = \"block\";\n        toggleButton_4632.textContent = \"Ẩn\";\n        isVisible = true;\n    } else {\n        contentList_4632.style.display = \"none\";\n        toggleButton_4632.textContent = \"Xem\";\n        isVisible = false;\n    }\n});\n</script>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"relationships-key\">Mối Quan Hệ &#8211; Chìa Khóa Mở Mọi Cánh Cửa</h2>\n\n\n\n<p>Chìa khóa để thành công trong cuộc sống là bạn phải xây dựng nhiều mối quan hệ hơn và tốt hơn, và để bạn trở nên được biết đến và tôn trọng bởi nhiều người hơn. Bạn phải làm điều này một cách có chủ đích, cẩn thận lựa chọn những người và tổ chức mà bạn muốn liên kết. Sau đó, hãy dốc hết tâm huyết của mình vào việc đóng góp có giá trị cho những người và tổ chức đó.</p>\n\n\n\n<p>Con người luôn tìm cách đi theo con đường ít trở ngại nhất. Và con đường ít trở ngại nhất trong các mối quan hệ con người là giới thiệu và làm ăn với những người mà chúng ta đã biết, thích và tin tưởng. Công việc của bạn là xây dựng mạng lưới rộng nhất có thể của các mối quan hệ ảnh hưởng khi bạn tiến bước trong cuộc sống.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"683\" height=\"1024\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-22-683x1024.png\" alt=\"Hai phụ nữ cười rạng rỡ và bắt tay thân thiện, thể hiện sự hài lòng và tin tưởng trong mối quan hệ tích cực.\" class=\"wp-image-4637\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-22-683x1024.png 683w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-22-600x900.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-22-200x300.png 200w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-22-768x1152.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-22-1024x1536.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-22.png 1067w\" sizes=\"auto, (max-width: 683px) 100vw, 683px\" /></figure>\n\n\n\n<p>Càng nhiều người biết bạn và bạn biết họ theo cách tích cực, càng có khả năng bạn sẽ biết đúng người vào đúng thời điểm vì đúng lý do để tận dụng đúng cơ hội. Các cánh cửa sẽ liên tục mở ra cho bạn, cho phép bạn mở rộng và cải thiện mọi phần trong cuộc sống của mình. Khi bạn đạt đến đỉnh cao trong lĩnh vực của mình bằng cách giành được sự tôn trọng và quý mến của tất cả mọi người xung quanh, đó sẽ là vì bạn đã có mục tiêu và kế hoạch, không phải vì may mắn.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"practical-actions\">NHỮNG HÀNH ĐỘNG THỰC TIỄN</h2>\n\n\n\n<p><strong>Những Điều Bạn Có Thể Làm Ngay</strong>:</p>\n\n\n\n<p>1. Lập một danh sách tất cả những người quan trọng trong ngành của bạn, cộng đồng của bạn, và quốc gia của bạn mà sẽ có ích nếu bạn biết họ; tìm cách để giao tiếp với họ, hoặc trực tiếp hoặc bằng thư.</p>\n\n\n\n<p>2. Tìm cách để làm việc cho người khác, hoặc giúp đỡ họ hoặc tổ chức của họ bằng cách nào đó; nó luôn quay trở lại với bạn.</p>\n\n\n\n<p>3. &#8220;Câu cá nơi có cá&#8221;; tham gia các tổ chức và hiệp hội mà những người bạn muốn biết và muốn được biết đến thường lui tới.</p>\n\n\n\n<p>4. Hãy là một người cho đi; tình nguyện giúp đỡ ở mọi cơ hội. Tạo thói quen cho đi mà không mong đợi được đáp lại.</p>\n\n\n\n<p>5. Chọn sếp của bạn một cách cẩn thận; người mà bạn quyết định làm việc cho có thể có tác động lớn đến sự nghiệp và mức độ hài lòng của bạn.</p>\n\n\n\n<p>6. Kết nối liên tục; tìm cách giới thiệu công việc cho những người bạn gặp. Viết thư cho họ và gửi một cuốn sách, một bài báo cắt ra, hoặc một mẫu của những gì bạn làm. Giữ liên lạc.</p>\n\n\n\n<p>7. Thực hành nguyên tắc có đi có lại trong tất cả các mối quan hệ của bạn; làm việc cho người khác, và trả ơn họ khi họ làm điều gì đó cho bạn.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"683\" height=\"1024\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-23-683x1024.png\" alt=\"Nhóm sinh viên đa dạng tụ tập cùng nhau, học tập và trao đổi, thể hiện mối quan hệ hỗ trợ và hợp tác trong môi trường giáo dục.\" class=\"wp-image-4638\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-23-683x1024.png 683w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-23-600x900.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-23-200x300.png 200w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-23-768x1152.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-23-1024x1536.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-23.png 1067w\" sizes=\"auto, (max-width: 683px) 100vw, 683px\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"principle-7-money\">Nguyên tắc 7 &#8211; Vấn đề Tiền bạc</h2>\n\n\n\n<p>&#8220;Nhiều vàng đã được khai thác từ suy nghĩ của con người hơn là từ trái đất.&#8221; —Napoleon Hill</p>\n\n\n\n<p>Một trong những mục tiêu quan trọng nhất trong cuộc sống của bạn là trở nên độc lập về tài chính. Có đủ tiền là điều cần thiết để bạn tận hưởng sự tự do, hạnh phúc, cơ hội và sự thể hiện bản thân đầy đủ mà bạn muốn trong tương lai. Và không có lĩnh vực nào mà khái niệm may mắn phổ biến hoặc được ưa chuộng hơn trong việc đạt được thành công về tài chính.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"512\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-21-1024x512.png\" alt=\"Nhân vật hoạt hình cầm nam châm khổng lồ, hút tiền về phía mình, minh họa sáng tạo cho vấn đề tiền bạc và sức hấp dẫn của sự giàu có.\" class=\"wp-image-4636\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-21-1024x512.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-21-600x300.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-21-300x150.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-21-768x384.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-21-1536x768.png 1536w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-21.png 1600w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></figure>\n\n\n\n<p>Tin tốt là chúng ta đang sống trong thời điểm tốt nhất trong toàn bộ lịch sử loài người để đạt được thành công về tài chính. Nhờ thông tin và kiến thức mới, đổi mới công nghệ, và nhu cầu khách hàng ngày càng tăng, ngày nay có nhiều cơ hội hơn bao giờ hết để bạn đạt được độc lập tài chính, và thậm chí trở nên giàu có. Hoa Kỳ là quốc gia tốt nhất, cung cấp nhiều con đường tạo ra của cải hơn bất kỳ quốc gia nào khác.</p>\n\n\n\n<p>Chỉ vài thập kỷ trước, để trở nên giàu có, bạn cần đất đai, lao động, vốn, đồ đạc, thiết bị cố định, tòa nhà, máy móc và các nguồn lực vật chất khác. Ngày nay, bạn có thể bắt đầu con đường đến độc lập tài chính chỉ với trí tuệ thuần túy. Bạn thậm chí có một số lợi thế so với những người có toàn bộ tài sản bị ràng buộc trong các nhà máy và thiết bị. Tất cả những gì họ có có thể nhanh chóng trở nên lỗi thời bởi sự thay đổi trong công nghệ hoặc nhu cầu của người tiêu dùng. Ngày nay ai mua máy Betamax hay thú nhồi bông Beanie Babies?</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"wealth-origin\">Nguồn Gốc Thực Sự của Sự Giàu Có</h2>\n\n\n\n<p>Một yếu tố may mắn quan trọng trong việc tích lũy của cải được giải thích bởi Quy luật Dồi dào. Nó nói rằng, chúng ta sống trong một vũ trụ của sự dồi dào vô hạn, nơi có rất nhiều cho bất cứ ai biết cách để có được nó.</p>\n\n\n\n<p>Khả năng suy nghĩ và tạo ra những ý tưởng và đổi mới mới đại diện cho sự giàu có thực sự của bạn. Những khả năng tài chính của bạn chỉ bị giới hạn bởi <a href=\"https://blog.kenfinly.com/sach/tri-tuong-tuong-buoc-thu-nam-huong-toi-su-giau-co/\">trí tưởng tượng</a> của chính bạn và cách bạn áp dụng nó vào thế giới bạn đang sống.</p>\n\n\n\n<p>Khi tôi còn là một người đàn ông trẻ, không có bằng trung học, sống trong xe hơi của mình, ngủ trên mặt đất, và làm những công việc lao động với mức lương tối thiểu, tôi thường cảm thấy thương hại cho bản thân vì tôi không có tiền. Tôi ghen tị với những người dường như đang làm tốt hơn tôi, và tôi ước rằng tôi đã có cùng may mắn mà họ dường như đang tận hưởng. Tôi đã bị thuyết phục bởi câu nói cũ rằng &#8220;người giàu càng giàu và người nghèo càng nghèo.&#8221; Tôi đã bị dẫn dắt để tin rằng những người thành công đã bắt đầu với những lợi thế lớn trong cuộc sống. Tôi đã tin rằng không có nhiều hy vọng nếu bạn không xuất thân từ một gia đình tốt, không được học hành tử tế, và không có tất cả các loại cơ hội tài chính mở ra cho bạn.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"everyone-starts-zero\">Mọi Người Đều Bắt Đầu Từ Con Số Không</h2>\n\n\n\n<p>Đó là một cú sốc thực sự đối với tôi khi tôi biết được rằng hầu như tất cả những người thành công ở Mỹ đều bắt đầu với rất ít hoặc không có gì. Ít hơn 1 phần trăm người Mỹ thành công về tài chính bắt đầu với một khoản thừa kế gia đình dưới bất kỳ hình thức nào. Hầu hết mọi thành công tài chính đều đạt được trong một thế hệ. Người giàu nhất ở Mỹ là Bill Gates 42 tuổi, người đã bỏ học ở Harvard để bắt đầu kinh doanh riêng ở tuổi hai mươi.</p>\n\n\n\n<p>Mọi người thường xuyên hỏi tôi làm thế nào họ có thể thay đổi cuộc sống của mình hoặc bắt đầu một doanh nghiệp mới nếu họ không có tiền. Tôi nói với họ rằng có hàng trăm nếu không phải hàng nghìn doanh nghiệp mà bạn có thể bắt đầu với ít hơn 100 đô la. Nhưng những doanh nghiệp này đòi hỏi vốn trí tuệ và thể chất hơn là vốn tài chính để xây dựng. Vốn quan trọng nhất mà bạn phải đầu tư vào sự nghiệp của mình hoặc vào bất kỳ doanh nghiệp mới nào là vốn mồ hôi. Vốn này đại diện cho sự sẵn sàng làm việc và làm việc rất chăm chỉ của bạn để đạt được mục tiêu của mình. Mọi thứ khác bạn cần cuối cùng sẽ đến với bạn.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"716\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-24-1024x716.png\" alt=\"\" class=\"wp-image-4639\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-24-1024x716.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-24-600x420.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-24-300x210.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-24-768x537.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-24-1536x1074.png 1536w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-24.png 1600w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></figure>\n\n\n\n<p><strong>Tài liệu tham khảo</strong>:</p>\n\n\n\n<p>Tracy, B. (2002).&nbsp;<a href=\"https://www.amazon.com/Create-Your-Own-Future-Unlimited/dp/0471251070\"><em>Create Your Own Future</em>.</a>&nbsp;New Jersey: John Wiley &amp; Sons. Chương 7: “Nguyên tắc 6 – Các mối quan hệ là thiết yếu”.</p>\n\n\n\n<p>Bản dịch:&nbsp;Dieter R.</p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:348:\"<p>Tìm hiểu tại sao mối quan hệ là chìa khóa mở mọi cánh cửa thành công. Bài viết hướng dẫn cách xây dựng có chủ đích mạng lưới mối quan hệ tích cực, giúp bạn thăng tiến trong sự nghiệp và cuộc sống. Nội dung Xem Mối Quan Hệ &#8211; Chìa Khóa Mở Mọi Cánh [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:4633;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:40;}s:4:\"tags\";a:2:{i:0;i:724;i:1;i:725;}s:10:\"class_list\";a:10:{i:0;s:9:\"post-4632\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:18:\"has-post-thumbnail\";i:6;s:6:\"hentry\";i:7;s:13:\"category-sach\";i:8;s:15:\"tag-brian-tracy\";i:9;s:26:\"tag-create-your-own-future\";}s:6:\"_links\";a:11:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4632\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=4632\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:3;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4632/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:4644;s:4:\"href\";s:65:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4632/revisions/4644\";}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/media/4633\";}}s:13:\"wp:attachment\";a:1:{i:0;a:1:{s:4:\"href\";s:57:\"https://blog.kenfinly.com/wp-json/wp/v2/media?parent=4632\";}}s:7:\"wp:term\";a:2:{i:0;a:3:{s:8:\"taxonomy\";s:8:\"category\";s:10:\"embeddable\";b:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/categories?post=4632\";}i:1;a:3:{s:8:\"taxonomy\";s:8:\"post_tag\";s:10:\"embeddable\";b:1;s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/tags?post=4632\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2: