\";s:22:\"Create Your Own Future\";s:4:\"slug\";s:22:\"create-your-own-future\";s:8:\"taxonomy\";s:8:\"post_tag\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:48:\"https://blog.kenfinly.com/wp-json/wp/v2/tags/725\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:44:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=725\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}}}}i:2;a:26:{s:2:\"id\";i:4626;s:4:\"date\";s:19:\"2025-05-06T19:58:13\";s:8:\"date_gmt\";s:19:\"2025-05-06T12:58:13\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=4626\";}s:8:\"modified\";s:19:\"2025-05-06T19:59:58\";s:12:\"modified_gmt\";s:19:\"2025-05-06T12:59:58\";s:4:\"slug\";s:42:\"nguyen-tac-co-di-co-lai-thanh-cong-quan-he\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:74:\"https://blog.kenfinly.com/sach/nguyen-tac-co-di-co-lai-thanh-cong-quan-he/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:97:\"Nguyên Tắc Có Đi Có Lại: Bí Quyết Thành Công Trong Mối Quan Hệ Và Sự Nghiệp\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:16803:\"\n<p>Khám phá sức mạnh của nguyên tắc có đi có lại, quy luật tự nhiên giúp xây dựng mối quan hệ bền vững và tạo cơ hội thành công không ngờ trong cuộc sống.</p>\n\n\n\n<p><em>Phần trước: <a href=\"https://blog.kenfinly.com/sach/chon-sep-tot-brian-tracy/\">Chọn Cho Mình Một Người Sếp Tốt – Lời Khuyên từ Brian Tracy</a></em></p>\n\n\n\n<figure class=\"wp-block-audio\"><audio controls src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/nguyen-tac-co-di-co-lai.mp3\" loop></audio><figcaption class=\"wp-element-caption\">Nghe đọc bài</figcaption></figure>\n\n\n\n<style>\n.toc-content {\n    color: #000;\n    font-size: 24px;\n    margin-bottom: 20px;\n    display: flex;\n    align-items: center;\n}\n\n#toggleButton_4626 {\n    margin-left: 15px;\n    padding: 3px 8px;\n    background-color: #ffA500;\n    color: #fff;\n    border: none;\n    cursor: pointer;\n    border-radius: 3px;\n    text-transform: uppercase;\n    letter-spacing: 0.5px;\n    opacity: 0.8;\n    transition: opacity 0.3s ease;\n}\n\n#toggleButton_4626:hover {\n    opacity: 1;\n}\n\n#contentList_4626 {\n    display: none;\n    transition: all 0.3s ease;\n}\n\n#contentList_4626 > .toc-item {\n    color: #ffa500;\n    font-size: 16px;\n    margin-bottom: 10px;\n    line-height: 1.5;\n}\n\n#contentList_4626 .toc-subitem {\n    color: #ffA500;\n    font-size: 14px;\n    margin-left: 20px;\n    opacity: 0.8;\n}\n\n#contentList_4626 a {\n    color: #ffA500;\n}\n</style>\n\n<div class=\"toc-content\">\n    Nội dung\n    <button id=\"toggleButton_4626\">Xem</button>\n</div>\n\n<div id=\"contentList_4626\">\n    <div class=\"toc-item\"><a href=\"#volunteer-tasks\">Tình nguyện nhận Nhiệm vụ</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#my-network\">Câu chuyện Xây dựng Mạng lưới của Tôi</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#your-success\">Bạn Cũng Có Thể Thành Công Như Vậy</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#create-goodwill\">Tạo Thiện Cảm &#8211; Yếu Tố Quan Trọng Trong Gây Ảnh Hưởng</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#reciprocity\">Quy luật Có đi có lại</a></div>\n    \n   \n</div>\n\n<script>\nconst toggleButton_4626 = document.getElementById(\"toggleButton_4626\");\nconst contentList_4626 = document.getElementById(\"contentList_4626\");\nlet isVisible = false;\n\ntoggleButton_4626.addEventListener(\'click\', () => {\n    if (!isVisible) {\n        contentList_4626.style.display = \"block\";\n        toggleButton_4626.textContent = \"Ẩn\";\n        isVisible = true;\n    } else {\n        contentList_4626.style.display = \"none\";\n        toggleButton_4626.textContent = \"Xem\";\n        isVisible = false;\n    }\n});\n</script>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"volunteer-tasks\">Tình nguyện nhận Nhiệm vụ</h2>\n\n\n\n<p>Chiến lược của bạn khác biệt. Khi bạn tham gia, bạn không chỉ đảm nhận trách nhiệm, mà còn tích cực tham gia. Bạn tình nguyện nhận thêm nhiệm vụ. Bạn giơ tay khi có việc cần làm, và bạn thực hiện bất kỳ nhiệm vụ nào được giao cho bạn. Bạn tham dự mọi cuộc họp và đóng góp vào mọi cuộc thảo luận. Bạn chuẩn bị kỹ lưỡng trước mỗi cuộc họp và nhanh chóng theo dõi tiến độ sau đó.</p>\n\n\n\n<p>Chẳng mấy chốc, những người chủ chốt trong ủy ban sẽ chú ý đến bạn. Bằng cách không ngừng cống hiến mà không đòi hỏi đáp lại, bạn sẽ dần giành được sự tôn trọng và tin tưởng của họ. Uy tín của bạn sẽ ngày càng tăng. Họ sẽ trở nên tự tin hơn vào khả năng thực hiện những nhiệm vụ ngày càng quan trọng của bạn. Chẳng mấy chốc, họ sẽ yêu cầu bạn giúp đỡ trong các lĩnh vực quan trọng và tin tưởng giao cho bạn những nhiệm vụ quan trọng. Bạn sẽ sớm trở thành một người chủ chốt trong ủy ban và là một thành viên có giá trị của tổ chức.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"my-network\">Câu chuyện Xây dựng Mạng lưới của Tôi</h2>\n\n\n\n<p>Vài năm trước, tôi đã tham gia Phòng Thương mại với mục đích rõ ràng là để tham gia vào cộng đồng doanh nghiệp và đóng góp một cách nào đó. Tôi nhận thấy vấn đề chính mà Phòng Thương mại đang tham gia là tình hình doanh nghiệp-chính phủ-giáo dục tồn tại vào thời điểm đó.&nbsp; Do đó, tôi đã tình nguyện phục vụ trong ủy ban doanh nghiệp/giáo dục liên lạc với chính phủ.</p>\n\n\n\n<p>Tôi đã đầu tư nhiều giờ để nghiên cứu và viết báo cáo cho ủy ban. Tôi tham dự mọi cuộc họp. Tôi đề xuất các chiến lược và chiến thuật khác nhau mà cộng đồng doanh nghiệp có thể sử dụng để đóng vai trò tích cực hơn với chính phủ trong việc tăng cường tính liên quan và chất lượng giáo dục trong tiểu bang. Trong vòng sáu tháng, tôi đã được bổ nhiệm làm phó chủ tịch ủy ban và được giao tất cả các trách nhiệm chính của Phòng Thương mại trong lĩnh vực doanh nghiệp-giáo dục.</p>\n\n\n\n<p>Chủ tịch ủy ban là một trong những doanh nhân kỳ cựu trong cộng đồng. Ông ấy cực kỳ có quyền lực và liên kết với nhiều tổ chức kinh doanh và chính phủ ở khắp nơi. Tôi làm việc dưới quyền ông ấy và tuân theo sự hướng dẫn và chỉ dẫn của ông. Ông bắt đầu mở ra những cơ hội cho tôi và giới thiệu tôi với những doanh nhân chủ chốt khác, những người có thể cung cấp cho tôi ý kiến và lời khuyên về các hoạt động kinh doanh và giáo dục của Phòng Thương mại.</p>\n\n\n\n<p>Sáu tháng sau, cuộc họp thường niên của của Phòng Thương mại được tổ chức tại một khu nghỉ dưỡng lớn. Nó có sự tham dự của hàng trăm đại biểu, mỗi người đều là một giám đốc điều hành cấp cao từ một công ty lớn. Họ hỏi tôi liệu tôi có muốn đảm nhận trách nhiệm chuẩn bị chương trình cho các diễn giả và làm người dẫn chương trình cho cuộc họp thường niên không.</p>\n\n\n\n<p>Một lần nữa, tôi chấp nhận với sự nhiệt tình. Tôi đã dành nhiều giờ để chuẩn bị và nghiên cứu phần giới thiệu của các diễn giả khác nhau. Tại cuộc họp, tôi đứng ở vị trí trung tâm với vai trò người dẫn chương trình và chủ tọa trong suốt cả ngày, trước mặt hàng trăm đại biểu doanh nghiệp hàng đầu. Vì tôi đã làm bài tập về nhà, tôi đã được chuẩn bị kỹ lưỡng để thực hiện công việc một cách có năng lực.</p>\n\n\n\n<p>Sau cuộc họp, tôi được mời tham gia vào nhóm nòng cốt của ủy ban quan hệ doanh nghiệp và chính phủ. Đến năm sau, tôi đã tổ chức và chủ trì các cuộc họp giữa các nhóm giám đốc điều hành cấp cao của doanh nghiệp và các quan chức chính phủ cấp cao. Một số cuộc họp này được viết trên báo, bao gồm cả một số bình luận mà tôi đã đưa ra và các chính trị gia đã phản hồi. Một doanh nhân hàng đầu trong thành phố của tôi đã đọc những bình luận đó và quyết định rằng ông ấy muốn tôi làm việc cho ông. Ông ấy đã thuê tôi rời khỏi công việc của mình với mức lương gấp đôi cộng với quyền chọn mua cổ phiếu.</p>\n\n\n\n<p>Trước khi mọi thứ lắng xuống, tôi đã trở thành một trong những doanh nhân trẻ được biết đến và tôn trọng nhất trong tiểu bang. Tôi được gọi bằng tên với các chính trị gia cấp cao, những doanh nhân hàng đầu và lãnh đạo của nhiều tổ chức tư nhân và công. Tôi được mời trở thành một nhân vật chủ chốt trong chiến dịch gây quỹ hàng năm của United Way. Điều này khiến tôi được chú ý bởi nhiều doanh nhân cấp cao hơn và mang lại cho tôi thêm nhiều cơ hội để mở rộng các mối quan hệ.</p>\n\n\n\n<p>Trong vòng hai năm, thu nhập của tôi lại tăng gấp đôi. Dường như có một mối quan hệ trực tiếp giữa những vòng tròn quan hệ ngày càng mở rộng mà tôi đang hình thành và những cơ hội tôi có để làm việc, đầu tư, phát triển bất động sản, du lịch, và tương tác với ngày càng nhiều người quan trọng.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"your-success\">Bạn Cũng Có Thể Thành Công Như Vậy</h2>\n\n\n\n<p>Và câu chuyện của tôi không phải là duy nhất. Vô số người đã có trải nghiệm tương tự. Nhưng nó phụ thuộc vào bạn. Việc ra ngoài kia và tham gia vào những gì đang diễn ra trong cộng đồng của bạn là tùy thuộc vào bạn. Luôn có nhiều cơ hội hơn rất nhiều để bạn phục vụ cộng đồng của mình trong các tổ chức xã hội, kinh doanh hoặc từ thiện so với số người tài năng để lấp đầy những vị trí đó. Không có giới hạn nào cho mức độ mà bạn có thể mở rộng các mối quan hệ của mình nếu bạn tiếp cận tình huống như một người cho đi hơn là một người nhận lấy.</p>\n\n\n\n<p>Khi bạn gặp một người mới mà bạn cảm thấy sẽ có giá trị khi biết họ, hãy nhớ câu nói cũ, &#8220;Người đặt câu hỏi là người kiểm soát.&#8221; Sử dụng Quy luật Nỗ lực Gián tiếp. Thay vì cố gắng gây ấn tượng với người khác, hãy hỏi họ những câu hỏi rồi ấn tượng với những gì họ nói với bạn.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"639\" height=\"354\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/brian-tracy.jpg\" alt=\"\" class=\"wp-image-4628\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/brian-tracy.jpg 639w, https://blog.kenfinly.com/wp-content/uploads/2025/05/brian-tracy-600x332.jpg 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/brian-tracy-300x166.jpg 300w\" sizes=\"auto, (max-width: 639px) 100vw, 639px\" /></figure>\n\n\n\n<p>Tìm kiếm cơ hội để giúp đỡ, để đóng góp hơn là lấy đi. Hãy nhớ rằng Quy luật Gieo và Gặt là một nguyên tắc phổ quát. Nó hoạt động ở mọi nơi và trong hầu hết mọi điều kiện. Nếu bạn đầu tư đủ lâu và đủ chăm chỉ, cuối cùng bạn sẽ nhận được tất cả những gì bạn có thể muốn.</p>\n\n\n\n<p>Mọi doanh nhân bạn gặp đều nghĩ về doanh số và doanh thu của họ phần lớn thời gian. Họ đo lường và phân tích chúng hàng ngày, và đôi khi thường xuyên hơn. Mọi người thích nói về những gì họ làm và tại sao công ty của họ là độc đáo và khác biệt. Họ thích giải thích tại sao mọi người mua từ họ và những lợi ích họ nhận được. Bạn không bao giờ sai khi hỏi, &#8220;Công việc kinh doanh của bạn dạo này thế nào?&#8221;</p>\n\n\n\n<p>Một câu hỏi thậm chí còn tốt hơn bạn có thể hỏi là, &#8220;Tôi cần biết gì về doanh nghiệp của bạn để giới thiệu bạn với một khách hàng tiềm năng?&#8221;</p>\n\n\n\n<p>Không có gì xây dựng mối quan hệ giữa bạn và một doanh nhân khác nhanh hơn việc giới thiệu một khách hàng cho doanh nhân đó. Khi bạn giúp người khác xây dựng doanh nghiệp của họ và đạt được mục tiêu nghề nghiệp và tài chính của riêng họ, họ sẽ sẵn sàng giúp bạn cải thiện cuộc sống và công việc kinh doanh của bạn. Hãy tìm cơ hội để gửi cho họ một khách hàng càng sớm càng tốt.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"create-goodwill\">Tạo Thiện Cảm &#8211; Yếu Tố Quan Trọng Trong Gây Ảnh Hưởng</h2>\n\n\n\n<p>Hãy nhớ rằng, một trong những nguyên tắc thành công mạnh mẽ nhất được chứa đựng trong nguyên tắc của sự yêu thích, nói rằng, &#8220;Một người càng thích bạn, thì càng dễ dàng hơn cho bạn để ảnh hưởng đến họ theo cách nào đó.&#8221;</p>\n\n\n\n<p>Quy luật là cảm xúc thường làm méo mó đánh giá. Nếu một người thực sự thích bạn, họ sẽ ít quan tâm hơn về những điểm yếu trong bản thân bạn hoặc sản phẩm của bạn. Mặt khác, nếu ai đó trung lập hoặc tiêu cực đối với bạn, họ sẽ hoài nghi hoặc nghi ngờ hơn về bất cứ điều gì bạn nói.</p>\n\n\n\n<p>Mọi người thích làm việc với những người họ thích. Mọi người thích giao tiếp xã hội với những người họ thích. Mọi người thích mở cửa cho những người họ thích. Mọi người thích mua hàng từ những người họ thích. Mọi người thích thuê và thăng chức cho những người họ thích. Càng nhiều người thích bạn, họ sẽ càng mở nhiều cánh cửa cho bạn và bạn sẽ tiến nhanh hơn trong sự nghiệp của mình.</p>\n\n\n\n<p>Hãy luôn sẵn sàng giúp đỡ những người bạn gặp. Tôi đã chứng kiến nhiều doanh nhân giàu có và quyền lực nhất thế giới làm việc. Điều luôn khiến tôi ngạc nhiên là họ rất lịch sự và chú ý lắng nghe người khác. Và hầu như lúc nào họ cũng hỏi: &#8220;Tôi có thể giúp gì cho bạn không?&#8221;</p>\n\n\n\n<p>Đôi khi họ sẽ nghĩ ra điều gì đó mà bạn có thể giúp. Trong hầu hết các trường hợp, họ có thể không nghĩ ra cách nào bạn có thể giúp họ ngay lúc đó. Nhưng việc bạn đề nghị giúp đỡ sẽ để lại ấn tượng tốt về bạn trong tâm trí họ. &nbsp;Đâu đó trong tương lai, họ có thể gọi cho bạn.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"reciprocity\">Quy luật Có đi có lại</h2>\n\n\n\n<p>Quy luật Có đi có lại là một trong những động lực mạnh mẽ và quan trọng nhất của con người. Việc thường xuyên áp dụng quy luật này sẽ mang đến cho bạn những cơ hội mà hiện tại bạn không thể nào tưởng tượng được. Nguyên tắc này nói rằng, &#8220;Khi bạn làm điều gì đó cho người khác, họ sẽ muốn làm điều gì đó cho bạn. Họ sẽ muốn đáp lại bằng cách nào đó để không cảm thấy mắc nợ.&#8221;</p>\n\n\n\n<p>Hầu hết con người đều công bằng trong cách đối xử với người khác. Khi ai đó làm điều gì đó tốt đẹp cho một người, người đó cảm thấy có nghĩa vụ phải bù đắp, trả ơn người kia bằng cách nào đó. Tác động của một ân huệ hoặc lòng tốt là là làm mất cân bằng phương trình bình đẳng giữa họ. Kết quả là, họ tìm cách cân bằng lại. Họ tìm cách trả ơn bạn bằng cách làm điều gì đó tốt đẹp cho bạn.</p>\n\n\n\n<p>Nếu bạn đi ăn trưa với một người bạn và bạn trả tiền, anh ấy hoặc cô ấy sẽ khăng khăng trả tiền vào lần sau. Nếu bạn mời một người bạn đến nhà bạn ăn tối, anh ấy hoặc cô ấy sẽ khăng khăng mời bạn đến nhà họ vào một dịp khác. Khi bạn gửi thiệp Giáng sinh cho ai đó, cô ấy sẽ gửi lại thiệp Giáng sinh, ngay cả khi cô ấy không biết hoặc không nhớ bạn rõ lắm.</p>\n\n\n\n<p>Khi bạn sống hài hòa với các quy luật tự nhiên, bạn sẽ luôn ngạc nhiên về tốc độ mà những điều tốt đẹp bắt đầu xảy đến với mình. Và Quy luật Có đi có lại trong các mối quan hệ giữa người với người là một trong những nguyên tắc mạnh mẽ nhất mà bạn sẽ học được trong đời.</p>\n\n\n\n<p><strong>Tài liệu tham khảo</strong>:</p>\n\n\n\n<p>Tracy, B. (2002).&nbsp;<a href=\"https://www.amazon.com/Create-Your-Own-Future-Unlimited/dp/0471251070\"><em>Create Your Own Future</em>.</a>&nbsp;New Jersey: John Wiley &amp; Sons. Chương 7: “Nguyên tắc 6 – Các mối quan hệ là thiết yếu”.</p>\n\n\n\n<p>Bản dịch:&nbsp;Dieter R.</p>\n\n\n\n<p></p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:351:\"<p>Khám phá sức mạnh của nguyên tắc có đi có lại, quy luật tự nhiên giúp xây dựng mối quan hệ bền vững và tạo cơ hội thành công không ngờ trong cuộc sống. Phần trước: Chọn Cho Mình Một Người Sếp Tốt – Lời Khuyên từ Brian Tracy Nội dung Xem Tình nguyện nhận [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:4627;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:40;}s:4:\"tags\";a:2:{i:0;i:724;i:1;i:725;}s:10:\"class_list\";a:10:{i:0;s:9:\"post-4626\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:18:\"has-post-thumbnail\";i:6;s:6:\"hentry\";i:7;s:13:\"category-sach\";i:8;s:15:\"tag-brian-tracy\";i:9;s:26:\"tag-create-your-own-future\";}s:6:\"_links\";a:11:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4626\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=4626\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4626/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:4630;s:4:\"href\";s:65:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4626/revisions/4630\";}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/media/4627\";}}s:13:\"wp:attachment\";a:1:{i:0;a:1:{s:4:\"href\";s:57:\"https://blog.kenfinly.com/wp-json/wp/v2/media?parent=4626\";}}s:7:\"wp:term\";a:2:{i:0;a:3:{s:8:\"taxonomy\";s:8:\"category\";s:10:\"embeddable\";b:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/categories?post=4626\";}i:1;a:3:{s:8:\"taxonomy\";s:8:\"post_tag\";s:10:\"embeddable\";b:1;s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/tags?post=4626\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}s:9:\"_embedded\";a:3:{s:6:\"author\";a:1:{i:0;a:8:{s:2:\"id\";i:1;s:4:\"name\";s:9:\"Dieter R.\";s:3:\"url\";s:16:\"http://kenkai.vn\";s:11:\"description\";s:401:\"Xin chào, tôi là Dieter R., một cây bút đam mê tại KenkAI.vn, đang sinh sống và làm việc tại Thành phố Hồ Chí Minh sôi động. Với niềm đam mê mãnh liệt về lĩnh vực lãnh đạo, tâm lý học, trí tuệ nhân tạo, công nghệ và phát triển bản thân, tôi luôn nỗ lực mang đến những nội dung giá trị và sâu sắc cho độc giả.\";s:4:\"link\";s:40:\"https://blog.kenfinly.com/author/dieter/\";s:4:\"slug\";s:6:\"dieter\";s:11:\"avatar_urls\";a:3:{i:24;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24&d=mm&r=g\";i:48;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=48&d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:15:{s:2:\"id\";i:4627;s:4:\"date\";s:19:\"2025-05-06T19:22:46\";s:4:\"slug\";s:11:\"tinh-nguyen\";s:4:\"type\";s:10:\"attachment\";s:4:\"link\";s:97:\"https://blog.kenfinly.com/sach/nguyen-tac-co-di-co-lai-thanh-cong-quan-he/attachment/tinh-nguyen/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:14:\"Tình Nguyện\";}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:7:\"caption\";a:1:{s:8:\"rendered\";s:0:\"\";}s:8:\"alt_text\";s:0:\"\";s:10:\"media_type\";s:5:\"image\";s:9:\"mime_type\";s:9:\"image/png\";s:13:\"media_details\";a:6:{s:5:\"width\";i:800;s:6:\"height\";i:450;s:4:\"file\";s:23:\"2025/05/Tinh-Nguyen.png\";s:8:\"filesize\";i:144717;s:5:\"sizes\";a:11:{s:21:\"woocommerce_thumbnail\";a:6:{s:4:\"file\";s:23:\"Tinh-Nguyen-450x450.png\";s:5:\"width\";i:450;s:6:\"height\";i:450;s:8:\"filesize\";i:84350;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:76:\"https://blog.kenfinly.com/wp-content/uploads/2025/