:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=4624\";}}}}}s:7:\"wp:term\";a:2:{i:0;a:1:{i:0;a:6:{s:2:\"id\";i:6;s:4:\"link\";s:43:\"https://blog.kenfinly.com/category/tin-tuc/\";s:4:\"name\";s:9:\"Tin tức\";s:4:\"slug\";s:7:\"tin-tuc\";s:8:\"taxonomy\";s:8:\"category\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:52:\"https://blog.kenfinly.com/wp-json/wp/v2/categories/6\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/categories\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/category\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?categories=6\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}i:1;a:1:{i:0;a:6:{s:2:\"id\";i:728;s:4:\"link\";s:46:\"https://blog.kenfinly.com/tag/doanh-thu-apple/\";s:4:\"name\";s:15:\"Doanh thu Apple\";s:4:\"slug\";s:15:\"doanh-thu-apple\";s:8:\"taxonomy\";s:8:\"post_tag\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:48:\"https://blog.kenfinly.com/wp-json/wp/v2/tags/728\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:44:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=728\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}}}}i:4;a:26:{s:2:\"id\";i:4606;s:4:\"date\";s:19:\"2025-05-05T12:48:54\";s:8:\"date_gmt\";s:19:\"2025-05-05T05:48:54\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=4606\";}s:8:\"modified\";s:19:\"2025-05-05T13:18:25\";s:12:\"modified_gmt\";s:19:\"2025-05-05T06:18:25\";s:4:\"slug\";s:24:\"chon-sep-tot-brian-tracy\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:56:\"https://blog.kenfinly.com/sach/chon-sep-tot-brian-tracy/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:82:\"Chọn Cho Mình Một Người Sếp Tốt &#8211; Lời Khuyên từ Brian Tracy\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:15479:\"\n<p>Khám phá cách tìm người sếp tốt cho sự nghiệp thành công. Học bí quyết xây dựng mối quan hệ tích cực và chọn môi trường làm việc phù hợp từ Brian Tracy.</p>\n\n\n\n<figure class=\"wp-block-audio\"><audio controls src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/chon-nha-lanh-dao.mp3\" loop></audio><figcaption class=\"wp-element-caption\">Nghe Đọc bài</figcaption></figure>\n\n\n\n<style>\n.toc-content {\n    color: #000;\n    font-size: 24px;\n    margin-bottom: 20px;\n    display: flex;\n    align-items: center;\n}\n\n#toggleButton_4606 {\n    margin-left: 15px;\n    padding: 3px 8px;\n    background-color: #ffA500;\n    color: #fff;\n    border: none;\n    cursor: pointer;\n    border-radius: 3px;\n    text-transform: uppercase;\n    letter-spacing: 0.5px;\n    opacity: 0.8;\n    transition: opacity 0.3s ease;\n}\n\n#toggleButton_4606:hover {\n    opacity: 1;\n}\n\n#contentList_4606 {\n    display: none;\n    transition: all 0.3s ease;\n}\n\n#contentList_4606 > .toc-item {\n    color: #ffa500;\n    font-size: 16px;\n    margin-bottom: 10px;\n    line-height: 1.5;\n}\n\n#contentList_4606 .toc-subitem {\n    color: #ffA500;\n    font-size: 14px;\n    margin-left: 20px;\n    opacity: 0.8;\n}\n\n#contentList_4606 a {\n    color: #ffA500;\n}\n</style>\n\n<div class=\"toc-content\">\n    Nội dung\n    <button id=\"toggleButton_4606\">Xem</button>\n</div>\n\n<div id=\"contentList_4606\">\n    <div class=\"toc-item\"><a href=\"#best-boss\">Tìm Người Sếp Tốt Nhất Cho Bạn</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#right-people\">Gần gũi với Những Người Phù hợp</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#meet-people\">Đi ra ngoài và Gặp gỡ Mọi người</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#networking-strategy\">Chiến lược Networking Không bao giờ Thất bại</a></div>\n</div>\n\n<script>\nconst toggleButton_4606 = document.getElementById(\"toggleButton_4606\");\nconst contentList_4606 = document.getElementById(\"contentList_4606\");\nlet isVisible = false;\n\ntoggleButton_4606.addEventListener(\'click\', () => {\n    if (!isVisible) {\n        contentList_4606.style.display = \"block\";\n        toggleButton_4606.textContent = \"Ẩn\";\n        isVisible = true;\n    } else {\n        contentList_4606.style.display = \"none\";\n        toggleButton_4606.textContent = \"Xem\";\n        isVisible = false;\n    }\n});\n</script>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"best-boss\">Tìm Người Sếp Tốt Nhất Cho Bạn</h3>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"653\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-15-1024x653.png\" alt=\"người sếp tốt\" class=\"wp-image-4612\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-15-1024x653.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-15-600x383.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-15-300x191.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-15-768x490.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-15-1536x979.png 1536w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-15.png 1600w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></figure>\n\n\n\n<p>Khi bạn đã đưa ra một số quyết định về những gì bạn muốn trong cuộc sống cá nhân của mình, đã đến lúc bạn quyết định loại mối quan hệ nào bạn muốn trong công việc kinh doanh và sự nghiệp của mình. Một trong những bí quyết thành công trong thế giới công việc là chọn lựa cẩn thận người sếp của bạn. Khi bạn đi tìm việc làm, hãy nhớ rằng bạn sẽ đang trao đổi cuộc sống của mình, tài sản quý giá nhất của bạn, để có cơ hội làm việc và đạt được kết quả, cùng với thu nhập đi kèm với nó.</p>\n\n\n\n<p>Chìa khóa dẫn đến thành công của bạn trong công việc sẽ là chất lượng mối quan hệ mà bạn có với sếp, đồng nghiệp và khách hàng của mình. Hãy chọn sếp của bạn một cách cẩn thận. Phỏng vấn kỹ lưỡng cho đến khi bạn tìm thấy kiểu người mà bạn sẽ thích làm việc cùng. Tìm kiếm một người mà bạn thích, tôn trọng và ngưỡng mộ. Bạn muốn làm việc cho một người có nhiều điều để dạy bạn, và người sẽ khuyến khích và hỗ trợ bạn làm tốt nhất công việc mà bạn có thể.</p>\n\n\n\n<p>Mặt khác, nếu bạn thấy mình đang làm việc cho một sếp tiêu cực hoặc trong một tình huống khó khăn, bạn sẽ không bao giờ hạnh phúc hoặc thành công. Cuối cùng, bạn sẽ bỏ việc hoặc bị sa thải và phải đi tìm một công việc mới, ở nơi khác, làm việc với và cho những người khác. Những người thông minh là những người từ chối tiếp tục làm việc trong một tình huống mà họ không hạnh phúc. Họ biết rằng một công việc mà họ không thích là lãng phí thời gian và lãng phí cuộc sống.</p>\n\n\n\n<p>Tôi đã thấy nhiều tình huống mà một người giỏi đã rời bỏ môi trường làm việc tiêu cực và gia nhập một công ty khác với một sếp tích cực, lạc quan, khuyến khích và một nhóm đồng nghiệp thực sự tuyệt vời. Trong thời gian ngắn, người đã làm việc kém trong một môi trường bắt đầu phát triển mạnh mẽ và trưởng thành trong môi trường mới.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"right-people\">Gần gũi với Những Người Phù hợp</h3>\n\n\n\n<p>Một trong những quyết định quan trọng nhất mà bạn đưa ra trong cuộc sống là lựa chọn những người mà bạn thường xuyên giao tiếp. Hãy giao tiếp với những người phù hợp. Dành thời gian bên cạnh những người chiến thắng, và tránh xa những người tiêu cực. Tránh xa những người luôn phàn nàn, lên án và chỉ trích. Những người độc hại này khiến bạn chán nản và lấy đi niềm vui sống. Sau khi dành thời gian với họ, bạn cảm thấy nản lòng và mất động lực.</p>\n\n\n\n<p>Thay vào đó, hãy chọn bạn bè và người quen một cách cẩn thận. Như Baron de Rothschild đã nói, &#8220;Đừng kết giao vô ích.&#8221; Hãy hoàn toàn ích kỷ về những người mà bạn chọn để làm việc và giao tiếp. Nghiên cứu của Tiến sĩ <a href=\"https://www.toolshero.com/toolsheroes/david-mcclelland/\">David McClellan</a> về thành tích tại <a href=\"https://vi.wikipedia.org/wiki/%C4%90%E1%BA%A1i_h%E1%BB%8Dc_Harvard\">Đại học Harvard</a> sau 25 năm đã kết luận rằng các thành viên trong &#8220;nhóm tham chiếu&#8221; của bạn sẽ có tác động lớn hơn đến sự thành công và hạnh phúc của bạn so với bất kỳ lựa chọn nào khác bạn đưa ra trong cuộc sống.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"401\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-12.png\" alt=\"\" class=\"wp-image-4609\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-12.png 800w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-12-600x301.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-12-300x150.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-12-768x385.png 768w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /><figcaption class=\"wp-element-caption\"><strong>Tiến sĩ David McClellan.</strong> toolshero.com</figcaption></figure>\n\n\n\n<p>Nhóm tham chiếu của bạn bao gồm những người mà bạn đồng nhất và giao tiếp nhiều nhất. Nếu bạn bay cùng đại bàng, bạn sẽ suy nghĩ và cảm nhận như một đại bàng. Nếu bạn giao tiếp với gà tây, bạn sẽ suy nghĩ, đi lại, nói chuyện và hành động như một con gà tây. Những người xung quanh bạn có ảnh hưởng to lớn đến tính cách, quan điểm, mục tiêu và mọi thứ bạn đạt được.</p>\n\n\n\n<p>Người thành công thường được mô tả là những người thích ở một mình. Điều này không có nghĩa là họ là những người cô độc. Họ có nhiều bạn bè, nhưng không phải ai rủ đi ăn trưa cũng đi. Họ có chọn lọc trong các mối quan hệ của mình. Họ khăng khăng chỉ dành thời gian với những người họ thích và những người mà họ có thể được hưởng lợi từ việc giao tiếp. Bạn phải làm như vậy.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"meet-people\">Đi ra ngoài và Gặp gỡ Mọi người</h3>\n\n\n\n<p>Một trong những đặc điểm phổ biến nhất của những triệu phú tự thân ở Mỹ là họ liên tục mở rộng mạng lưới quan hệ. Họ biết rằng càng quen biết nhiều người, và càng nhiều người biết đến họ, họ sẽ càng gặp may mắn khi bán hàng và khám phá cơ hội. Họ nắm bắt mọi cơ hội để kết nối với người khác và mở rộng mạng lưới các mối quan hệ chồng chéo trong tất cả các lĩnh vực của cuộc sống mà họ cho là quan trọng.</p>\n\n\n\n<p>Một người bạn tốt của tôi, Sylvie Begin, đã chuyển từ Ottawa, Ontario đến San Diego để bắt đầu một doanh nghiệp mới. Cô ấy không quen biết ai khi đến nơi. Trong vòng vài tháng, cô ấy đã trở thành một trong những người năng động và nổi tiếng nhất trong ngành của mình. Làm thế nào cô ấy làm được điều đó? Câu trả lời là mở rộng mạng lưới quan hệ!</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"200\" height=\"256\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-14.png\" alt=\"\" class=\"wp-image-4611\"/><figcaption class=\"wp-element-caption\"><strong>SYLVIE BEGIN &#8211; Người Môi Giới</strong> <strong>Bất Động Sản</strong>. realtor.ca</figcaption></figure>\n\n\n\n<p>Cô ấy ngay lập tức tham gia vào các hiệp hội và tổ chức trong ngành. Cô ấy tham gia đầy đủ và đóng góp hết mình vào các hoạt động của nhóm, và vì chỉ có một vài người làm điều này, cô ấy sớm nổi lên ở vị trí nổi bật trong việc lập kế hoạch và tổ chức các ủy ban và chức năng chính. Cô ấy sớm được công nhận và tôn trọng bởi những người quan trọng trong các tổ chức này. Cô ấy nhanh chóng xây dựng được danh tiếng là người giúp đỡ và hoàn thành công việc. Các cơ hội bắt đầu đến với cô ấy. Cô ấy có được sự ủng hộ và hậu thuẫn của những người quan trọng trong và ngoài doanh nghiệp của mình, và đạt được nhiều tiến bộ trong vài tháng hơn hầu hết những người khác đã làm trong nhiều năm.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"networking-strategy\">Chiến lược Networking Không bao giờ Thất bại</h3>\n\n\n\n<p>Chìa khóa để xây dựng mạng lưới quan hệ thành công là bạn phải có chủ đích lựa chọn một hoặc hai tổ chức có các thành viên có thể hỗ trợ bạn và những người mà bạn cũng có thể giúp đỡ, trong việc đạt được mục tiêu cá nhân và kinh doanh của bạn.</p>\n\n\n\n<p>Quy luật Uy tín là một yếu tố là một yếu tố may mắn quan trọng. Quy luật này chỉ ra rằng, khi càng nhiều người tin tưởng bạn, họ càng dễ dàng hợp tác với bạn.</p>\n\n\n\n<p>Đây là một lĩnh vực khác mà mọi thứ đều quan trọng. Mọi điều bạn làm trong các mối quan hệ của mình hoặc giúp ích hoặc làm tổn hại đến uy tín và mức độ tin cậy mà bạn có với người khác. Một trong những lý do chính để bạn tham gia các tổ chức quan trọng là để bắt đầu xây dựng uy tín của bạn với những người có thể giúp đỡ bạn trong tương lai.</p>\n\n\n\n<p>Đây là công thức để xây dựng mạng lưới quan hệ thành công trong kinh doanh. Thứ nhất, trước khi bạn tham gia một tổ chức, hãy nghiên cứu nó cẩn thận. Làm bài tập về nhà của bạn. Tìm hiểu lý do tổ chức tồn tại và nó làm gì. Tìm hiểu những phần nào của tổ chức là năng động nhất và quan trọng nhất đối với sự thành công của tổ chức.</p>\n\n\n\n<p>Thứ hai, nghiên cứu danh sách thành viên và cơ cấu ủy ban. Hãy chắc chắn rằng bạn đang tham gia một tổ chức có những người đi trước bạn trong sự nghiệp và trong kinh doanh. Họ phải là những người mà bạn có thể học hỏi và thu được lợi ích. Họ phải là những người có khả năng kéo bạn lên những cấp độ cao hơn mà bạn chưa đạt được một mình. Chỉ khi bạn vừa hài lòng vừa phấn khích về tổ chức và những gì nó làm, bạn mới nên tham gia.</p>\n\n\n\n<p>Thứ ba, khi bạn đã là thành viên, hãy tìm hiểu những ủy ban nào quan trọng nhất đối với hoạt động của tổ chức. Đặt câu hỏi và lắng nghe cẩn thận. Khi bạn đã xác định được một ủy ban quan trọng mà bạn cảm thấy mình có thể đóng góp có giá trị, hãy tình nguyện tham gia ủy ban đó. Vì mọi thứ được thực hiện trong các tổ chức kinh doanh và xã hội phần lớn là tự nguyện, sự sẵn sàng đóng góp thời gian và công sức của bạn sẽ luôn được chào đón.</p>\n\n\n\n<p>Hầu hết những người tham gia các hiệp hội chỉ tham dự các cuộc họp và các chức năng rồi về nhà. Họ xem các cuộc họp như một phần mở rộng của đời sống xã hội của họ hơn là một phần quan trọng trong đời sống kinh doanh của họ.</p>\n\n\n\n<p><em><strong>Ghi chú</strong>: Bài viết này là một phần trong Chương 7: “Nguyên tắc 6 – Các mối quan hệ là thiết yếu” của cuốn sách “Create Your Own Future” của Brian Tracy. Do chương sách khá dài, mình đã chia thành nhiều phần nhỏ để dễ đọc và tiếp thu. Phần này tập trung vào “Chọn cho mình một người sếp tốt ”  Nội dung này có liên quan mật thiết đến phần <a href=\"https://blog.kenfinly.com/sach/quy-luat-cho-di-thu-hut-thanh-cong/\">“Quy luật của việc cho đi: Bí Quyết Thu Hút May Mắn Và Thành Công Trong Cuộc Sống”</a> đã được chia sẻ trước đó.</em></p>\n\n\n\n<p><strong>Tài liệu tham khảo:</strong></p>\n\n\n\n<p>Tracy, B. (2002).&nbsp;<a href=\"https://www.amazon.com/Create-Your-Own-Future-Unlimited/dp/0471251070\"><em>Create Your Own Future</em>.</a>&nbsp;New Jersey: John Wiley &amp; Sons. Chương 7: “Nguyên tắc 6 – Các mối quan hệ là thiết yếu”.</p>\n\n\n\n<p>Bản dịch:&nbsp;Dieter R.</p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:345:\"<p>Khám phá cách tìm người sếp tốt cho sự nghiệp thành công. Học bí quyết xây dựng mối quan hệ tích cực và chọn môi trường làm việc phù hợp từ Brian Tracy. Nội dung Xem Tìm Người Sếp Tốt Nhất Cho Bạn Gần gũi với Những Người Phù hợp Đi ra ngoài và Gặp [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:4607;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:40;}s:4:\"tags\";a:2:{i:0;i:724;i:1;i:725;}s:10:\"class_list\";a:10:{i:0;s:9:\"post-4606\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:18:\"has-post-thumbnail\";i:6;s:6:\"hentry\";i:7;s:13:\"category-sach\";i:8;s:15:\"tag-brian-tracy\";i:9;s:26:\"tag-create-your-own-future\";}s:6:\"_links\";a:11:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4606\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=4606\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:5;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4606/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:4618;s:4:\"href\";s:65:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4606/revisions/4618\";}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/media/4607\";}}s:13:\"wp:attachment\";a:1:{i:0;a:1:{s:4:\"href\";s:57:\"https://blog.kenfinly.com/wp-json/wp/v2/media?parent=4606\";}}s:7:\"wp:term\";a:2:{i:0;a:3:{s:8:\"taxonomy\";s:8:\"category\";s:10:\"embeddable\";b:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/categories?post=4606\";}i:1;a:3:{s:8:\"taxonomy\";s:8:\"post_tag\";s:10:\"embeddable\";b:1;s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp