taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=724\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}i:1;a:6:{s:2:\"id\";i:725;s:4:\"link\";s:53:\"https://blog.kenfinly.com/tag/create-your-own-future/\";s:4:\"name\";s:22:\"Create Your Own Future\";s:4:\"slug\";s:22:\"create-your-own-future\";s:8:\"taxonomy\";s:8:\"post_tag\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:48:\"https://blog.kenfinly.com/wp-json/wp/v2/tags/725\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:44:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=725\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}}}}i:5;a:26:{s:2:\"id\";i:4594;s:4:\"date\";s:19:\"2025-05-04T20:01:10\";s:8:\"date_gmt\";s:19:\"2025-05-04T13:01:10\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=4594\";}s:8:\"modified\";s:19:\"2025-05-04T20:16:33\";s:12:\"modified_gmt\";s:19:\"2025-05-04T13:16:33\";s:4:\"slug\";s:28:\"nhung-ky-nang-song-can-thiet\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:63:\"https://blog.kenfinly.com/ky-nang/nhung-ky-nang-song-can-thiet/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:93:\"Kỹ năng cần thiết để đạt kết quả tốt trong cuộc việc và cuộc sống\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:7516:\"\n<p>Bạn muốn thành công trong công việc và cuộc sống? Khám phá kỹ năng cần thiết giúp bạn đạt kết quả tốt, phát triển bản thân và vượt qua mọi thử thách.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"Sức Mạnh Của Lòng Can Đảm: Bí Mật Mở Rộng Giới Hạn Cuộc Đời\" width=\"500\" height=\"281\" src=\"https://www.youtube.com/embed/uTH1lrePlcg?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\n</div></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Suy nghĩ Nhỏ</h2>\n\n\n\n<p>*</p>\n\n\n\n<p>Kỹ năng quý giá nhất không phải là nguồn cảm hứng, mà là khả năng làm việc khi không có nó.</p>\n\n\n\n<p>**</p>\n\n\n\n<p>“Những gì bạn thấy thú vị” là một yếu tố dự đoán thành công tốt hơn những gì bạn giỏi.</p>\n\n\n\n<p>Sự tò mò không phải ngẫu nhiên; nó là một la bàn.</p>\n\n\n\n<p>***</p>\n\n\n\n<p>Điều phân biệt công việc tốt với công việc tuyệt vời không phải là tài năng mà là sự kiên trì.</p>\n\n\n\n<p>Những người thành công nhất không phải là những người luôn cảm thấy có động lực; họ là những người làm việc ngay cả khi họ không muốn. Quá thường xuyên, việc chờ đợi để cảm thấy sẵn sàng đồng nghĩa với việc không bao giờ bắt đầu.</p>\n\n\n\n<p>Những người xuất chúng hành động bất chấp cảm xúc của họ, không phải vì cảm xúc đó.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Những Hiểu biết Sâu sắc</h2>\n\n\n\n<p>*</p>\n\n\n\n<p><a href=\"https://vi.wikipedia.org/wiki/Steve_Jobs\">Steve Jobs</a> giải thích tại sao động lực không thể bị ép buộc:</p>\n\n\n\n<p><em>&#8220;Trong suốt cuộc đời, tôi chưa bao giờ thấy ai có thể thuyết phục được người không muốn làm việc chăm chỉ trở nên chăm chỉ.&#8221;</em></p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"682\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-9-1024x682.png\" alt=\"\" class=\"wp-image-4597\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-9-1024x682.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-9-600x400.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-9-300x200.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-9-768x512.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-9.png 1280w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /><figcaption class=\"wp-element-caption\"><strong><em>Steve Jobs</em>.</strong> kaizen.vn</figcaption></figure>\n\n\n\n<p>**</p>\n\n\n\n<p>Một lời nhắc nhở đúng lúc từ <em>Tư duy Rõ ràng (<a href=\"https://www.amazon.com/Clear-Thinking-Turning-Ordinary-Extraordinary/dp/0593086112?tag=farnamstreet-20&amp;geniuslink=true\">Clear Thinking</a>)</em>:</p>\n\n\n\n<p><em>&#8220;Một lý do khiến những người giỏi nhất thế giới đưa ra quyết định tốt một cách nhất quán là họ hiếm khi thấy mình bị buộc phải đưa ra quyết định bởi hoàn cảnh.&#8221;</em></p>\n\n\n\n<p>***</p>\n\n\n\n<p><a href=\"https://en.wikipedia.org/wiki/Alexi_Pappas\">Alexi Pappas</a> về cuộc chiến mà tất cả chúng ta đều đang chiến đấu:</p>\n\n\n\n<p><em>&#8220;Chúng ta sống cuộc đời nghĩ rằng mọi người khác đều có cuộc sống tốt hơn chúng ta cho đến khi chúng ta trưởng thành và nhận ra tất cả chúng ta đều đang ở trong những con thuyền nhỏ của sự tự nghi ngờ và do dự.&#8221;</em></p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"640\" height=\"480\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-11.png\" alt=\"\" class=\"wp-image-4599\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-11.png 640w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-11-600x450.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-11-300x225.png 300w\" sizes=\"auto, (max-width: 640px) 100vw, 640px\" /><figcaption class=\"wp-element-caption\"><strong>Alexi Pappas.</strong> self.com </figcaption></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Dự án Kiến thức</h2>\n\n\n\n<p>Mất bao lâu để phát hiện ra một ý tưởng trị giá hàng tỷ đô la? Theo Chủ tịch <a href=\"https://www.ycombinator.com/\">Y Combinator</a> <a href=\"https://en.wikipedia.org/wiki/Garry_Tan\">Garry Tan</a>, 10 phút.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"300\" height=\"300\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-10.png\" alt=\"\" class=\"wp-image-4598\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-10.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-10-100x100.png 100w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-10-150x150.png 150w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-10-80x80.png 80w\" sizes=\"auto, (max-width: 300px) 100vw, 300px\" /><figcaption class=\"wp-element-caption\"><strong>Garry Tan.</strong> gic.com.sg</figcaption></figure>\n\n\n\n<p><em>&#8220;Nếu sau 10 phút bạn vẫn không hiểu chuyện gì đang diễn ra, có nghĩa là người đối diện cũng không hiểu, và chẳng có gì để hiểu cả.&#8221;</em></p>\n\n\n\n<p>Trong tập này của <a href=\"https://www.youtube.com/@tkppodcast\">TKP</a>, ông phân tích các cuộc phỏng vấn 10 phút nổi tiếng của YC, chỉ ra tại sao những nhà sáng lập chân thành vượt trội hơn những người khéo léo, giải thích cách một số nhà xây dựng được trang bị AI có thể chiến thắng trước những công ty lớn nhất thế giới, và nhiều điều khác nữa.</p>\n\n\n\n<p>+ Listen on:&nbsp;<a href=\"https://podcasts.apple.com/us/podcast/226-garry-tan-billion-dollar-misfits-inside-y-combinators/id990149481?i=1000705388164\" target=\"_blank\" rel=\"noreferrer noopener\">Apple Podcasts</a>&nbsp;|&nbsp;<a href=\"https://open.spotify.com/episode/2pjMClMDaNeNyEUyJFuA8L?si=e9c7786f47d24a2c&amp;nd=1&amp;dlsi=e898ac5f61414ccf\" target=\"_blank\" rel=\"noreferrer noopener\">Spotify</a>&nbsp;|&nbsp;<a href=\"https://fs.blog/knowledge-project-podcast/garry-tan/\" target=\"_blank\" rel=\"noreferrer noopener\">Web</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Kho lưu trữ</h2>\n\n\n\n<p>Được tìm thấy trong một lá thư gửi cho <a href=\"https://en.wikipedia.org/wiki/Peter_Cundill\">Peter Cundill</a>, lời nhắc nhở này nắm bắt sức mạnh thầm lặng đằng sau những con người thực sự đáng ngưỡng mộ:</p>\n\n\n\n<p>&#8220;Thước đo của một con người <em>là sự nhất quán giữa lời nói và hành động của họ, lòng tốt của họ, sự tự tin của họ, và sự quyết đoán về việc họ là ai trên thế giới này và họ dự định sẽ tiếp tục là ai.&#8221;</em></p>\n\n\n\n<p>Nguồn: FS | BRAIN FOOD <a href=\"https://fs.blog/brain-food/may-4-2025/\">https://fs.blog/brain-food/may-4-2025/</a></p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:347:\"<p>Bạn muốn thành công trong công việc và cuộc sống? Khám phá kỹ năng cần thiết giúp bạn đạt kết quả tốt, phát triển bản thân và vượt qua mọi thử thách. Suy nghĩ Nhỏ * Kỹ năng quý giá nhất không phải là nguồn cảm hứng, mà là khả năng làm việc khi không [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:4600;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:4;}s:4:\"tags\";a:1:{i:0;i:727;}s:10:\"class_list\";a:9:{i:0;s:9:\"post-4594\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:18:\"has-post-thumbnail\";i:6;s:6:\"hentry\";i:7;s:16:\"category-ky-nang\";i:8;s:23:\"tag-vitamin-cho-tri-tue\";}s:6:\"_links\";a:11:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4594\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=4594\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:3;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4594/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:4603;s:4:\"href\";s:65:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4594/revisions/4603\";}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/media/4600\";}}s:13:\"wp:attachment\";a:1:{i:0;a:1:{s:4:\"href\";s:57:\"https://blog.kenfinly.com/wp-json/wp/v2/media?parent=4594\";}}s:7:\"wp:term\";a:2:{i:0;a:3:{s:8:\"taxonomy\";s:8:\"category\";s:10:\"embeddable\";b:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/categories?post=4594\";}i:1;a:3:{s:8:\"taxonomy\";s:8:\"post_tag\";s:10:\"embeddable\";b:1;s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/tags?post=4594\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}s:9:\"_embedded\";a:3:{s:6:\"author\";a:1:{i:0;a:8:{s:2:\"id\";i:1;s:4:\"name\";s:9:\"Dieter R.\";s:3:\"url\";s:16:\"http://kenkai.vn\";s:11:\"description\";s:401:\"Xin chào, tôi là Dieter R., một cây bút đam mê tại KenkAI.vn, đang sinh sống và làm việc tại Thành phố Hồ Chí Minh sôi động. Với niềm đam mê mãnh liệt về lĩnh vực lãnh đạo, tâm lý học, trí tuệ nhân tạo, công nghệ và phát triển bản thân, tôi luôn nỗ lực mang đến những nội dung giá trị và sâu sắc cho độc giả.\";s:4:\"link\";s:40:\"https://blog.kenfinly.com/author/dieter/\";s:4:\"slug\";s:6:\"dieter\";s:11:\"avatar_urls\";a:3:{i:24;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24