/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=724\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}i:1;a:6:{s:2:\"id\";i:725;s:4:\"link\";s:53:\"https://blog.kenfinly.com/tag/create-your-own-future/\";s:4:\"name\";s:22:\"Create Your Own Future\";s:4:\"slug\";s:22:\"create-your-own-future\";s:8:\"taxonomy\";s:8:\"post_tag\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:48:\"https://blog.kenfinly.com/wp-json/wp/v2/tags/725\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:44:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=725\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}}}}i:8;a:26:{s:2:\"id\";i:4554;s:4:\"date\";s:19:\"2025-05-02T14:33:28\";s:8:\"date_gmt\";s:19:\"2025-05-02T07:33:28\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=4554\";}s:8:\"modified\";s:19:\"2025-05-02T17:23:04\";s:12:\"modified_gmt\";s:19:\"2025-05-02T10:23:04\";s:4:\"slug\";s:17:\"moi-quan-he-la-gi\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:49:\"https://blog.kenfinly.com/sach/moi-quan-he-la-gi/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:77:\"Mối quan hệ là gì? Ý nghĩa và tầm quan trọng trong cuộc sống\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:19740:\"\n<p>Khám phá bí quyết xây dựng mối quan hệ bền vững từ Brian Tracy. Tìm hiểu Luật Mối quan hệ giúp mở rộng mạng lưới và tạo cơ hội thành công trong cuộc sống.</p>\n\n\n\n<figure class=\"wp-block-audio\"><audio controls src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/kenkai-vn-moi-quan-he.mp3\" loop></audio><figcaption class=\"wp-element-caption\">Nghe đọc bài</figcaption></figure>\n\n\n\n<style>\n.toc-content {\n    color: #000;\n    font-size: 24px;\n    margin-bottom: 20px;\n    display: flex;\n    align-items: center;\n}\n\n#toggleButton_4554 {\n    margin-left: 15px;\n    padding: 3px 8px;\n    background-color: #ffA500;\n    color: #fff;\n    border: none;\n    cursor: pointer;\n    border-radius: 3px;\n    text-transform: uppercase;\n    letter-spacing: 0.5px;\n    opacity: 0.8;\n    transition: opacity 0.3s ease;\n}\n\n#toggleButton_4554:hover {\n    opacity: 1;\n}\n\n#contentList_4554 {\n    display: none;\n    transition: all 0.3s ease;\n}\n\n#contentList_4554 > .toc-item {\n    color: #ffa500;\n    font-size: 16px;\n    margin-bottom: 10px;\n    line-height: 1.5;\n}\n\n#contentList_4554 .toc-subitem {\n    color: #ffA500;\n    font-size: 14px;\n    margin-left: 20px;\n    opacity: 0.8;\n}\n\n#contentList_4554 a {\n    color: #ffA500;\n}\n</style>\n\n<div class=\"toc-content\">\n    Nội dung\n    <button id=\"toggleButton_4554\">Xem</button>\n</div>\n\n<div id=\"contentList_4554\">\n    <div class=\"toc-item\"><a href=\"#the-law\">Luật Mối Quan Hệ: Bí Quyết Xây Dựng Mạng Lưới Người Biết Đến Bạn Để Mở Cánh Cửa Thành Công</a></div>\n    <div class=\"toc-item\"><a href=\"#relationship-law\">Luật Mối quan hệ trong Thực tế</a></div>\n    <div class=\"toc-subitem\"><a href=\"#improve-odds\">Cải thiện Cơ hội Có lợi cho Bạn</a></div>\n    <div class=\"toc-subitem\"><a href=\"#attracting-important\">Tập trung vào Việc Thu hút Những Người Quan trọng</a></div>\n    <div class=\"toc-subitem\"><a href=\"#indirect-effort\">Áp dụng Luật Nỗ lực Gián tiếp (the Law of Indirect Effort)</a></div>\n    <div class=\"toc-subitem\"><a href=\"#likes-praise\">Ai cũng Thích được Khen ngợi</a></div>\n    <div class=\"toc-subitem\"><a href=\"#deep-needs\">Đáp ứng Một trong những Nhu cầu Sâu sắc nhất của Con người</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#references\">Tài liệu tham khảo</a></div>\n</div>\n\n<script>\nconst toggleButton_4554 = document.getElementById(\"toggleButton_4554\");\nconst contentList_4554 = document.getElementById(\"contentList_4554\");\nlet isVisible = false;\n\ntoggleButton_4554.addEventListener(\'click\', () => {\n    if (!isVisible) {\n        contentList_4554.style.display = \"block\";\n        toggleButton_4554.textContent = \"Ẩn\";\n        isVisible = true;\n    } else {\n        contentList_4554.style.display = \"none\";\n        toggleButton_4554.textContent = \"Xem\";\n        isVisible = false;\n    }\n});\n</script>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p>“Phần quý giá nhất trong đời một người tốt chính là những hành động nhỏ nhặt, âm thầm của lòng nhân ái và tình yêu thương.” &#8211; William Wordsworth</p>\n</blockquote>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"800\" height=\"399\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image.png\" alt=\"Brian Tracy - Mối quan hệ là thiết yếu\" class=\"wp-image-4558\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image.png 800w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-600x299.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-300x150.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-768x383.png 768w\" sizes=\"auto, (max-width: 800px) 100vw, 800px\" /><figcaption class=\"wp-element-caption\"><strong>Brian Tracy.</strong> toolshero.com</figcaption></figure>\n\n\n\n<p class=\"has-small-font-size\"><strong>Được trích từ cuốn sách &#8220;<em>Create Your Own Future</em>&#8221; của tác giả Brian Tracy, Chương 7, Nguyên tắc 6: &#8220;Các mối quan hệ là thiết yếu&#8221;.</strong></p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"the-law\"><strong>Luật Mối Quan Hệ: Bí Quyết Xây Dựng Mạng Lưới Người Biết Đến Bạn Để Mở Cánh Cửa Thành Công</strong></h2>\n\n\n\n<p>Thành công của bạn phụ thuộc rất lớn, thậm chí có thể là nhiều nhất, vào chất lượng và số lượng các mối quan hệ bạn xây dựng được. Ở chương trước, bạn đã tìm hiểu cách trở thành một người tích cực, lạc quan và dễ mến hơn. Chương này sẽ hướng dẫn bạn cách mở rộng mạng lưới quan hệ một cách có hệ thống. Chiến lược này sẽ giúp bạn tăng cơ hội gặp gỡ đúng người, đúng lúc, với những thông tin và cơ hội phù hợp cho mình.</p>\n\n\n\n<p>Luật Mối quan hệ (The Law of Relationships) giải thích một trong những yếu tố thành công quan trọng nhất. Nó nói rằng, các mối quan hệ là thiết yếu; càng nhiều người biết đến bạn và nghĩ về bạn theo cách tích cực, bạn càng có nhiều cơ hội để đạt được mục tiêu của mình.</p>\n\n\n\n<p>Mọi thay đổi quan trọng trong cuộc sống của bạn đều sẽ liên quan đến người khác. Nếu bạn muốn đạt được những mục tiêu lớn, bạn sẽ cần sự tham gia tích cực và hợp tác của nhiều người khác. Thường thì, hướng đi của cuộc đời bạn sẽ được thay đổi bởi một lời bình luận đơn giản, một lời khuyên, hoặc một hành động đơn lẻ của một người. Càng có nhiều mối quan hệ tốt, và càng biết nhiều người hữu ích, bạn càng thường xuyên gặp được những cơ hội đúng đắn.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"relationship-law\">Luật Mối quan hệ trong Thực tế</h2>\n\n\n\n<p>Một người bạn của tôi đang phát triển doanh nghiệp của mình trong một thị trường cực kỳ cạnh tranh. Anh ấy cần thêm tiền để mở rộng. Anh ấy bắt đầu gọi điện đến các ngân hàng địa phương với kế hoạch kinh doanh của mình. Lần lượt từng ngân hàng từ chối anh ấy và nói rằng doanh nghiệp của anh ấy sẽ không bao giờ thành công.</p>\n\n\n\n<p>Tuy nhiên, anh ấy là một người lạc quan. Anh ấy vẽ một loạt các vòng tròn đồng tâm ngày càng mở rộng xung quanh địa chỉ và vị trí của doanh nghiệp của mình và bắt đầu gọi điện đến những khoảng cách ngày càng xa hơn. Cuối cùng, anh ấy tìm thấy một ngân hàng và một nhân viên ngân hàng cách 95 dặm, người thích kế hoạch kinh doanh của anh ấy và cho anh ấy vay số tiền cần thiết để mở rộng. Ngày nay, anh ấy là một trong những doanh nhân giàu có và thành công nhất ở Mỹ.</p>\n\n\n\n<p>Tôi hỏi anh ấy liệu anh ấy có bao giờ nghĩ đến việc từ bỏ việc tìm kiếm số tiền mình cần không. Anh ấy nói, &#8220;Tuyệt đối không! Tôi biết rằng cuối cùng tôi sẽ có được tiền nếu tôi nói chuyện với đủ người. Tôi đã sẵn sàng đến thăm các ngân hàng cách văn phòng của tôi 500 dặm nếu đó là những gì cần thiết để tìm được nhân viên ngân hàng phù hợp với thái độ phù hợp cho những gì tôi cần.&#8221;</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"improve-odds\">Cải thiện Cơ hội Có lợi cho Bạn</h3>\n\n\n\n<p>Đây là một yếu tố may mắn quan trọng và một phần quan trọng của thành công: Hãy nhớ Luật Xác suất, nó nói rằng, càng thử nhiều thứ khác nhau, càng có khả năng bạn sẽ thử đúng thứ vào đúng thời điểm.</p>\n\n\n\n<p>Luật này cũng áp dụng cho các mối quan hệ. Càng biết nhiều người, và càng mở rộng phạm vi liên hệ của bạn một cách nhất quán, càng có khả năng bạn sẽ gặp được người bạn cần, vào đúng thời điểm, với đúng nguồn lực bạn cần. Khi điều đó xảy ra, như nó luôn xảy ra, đó sẽ không phải là một phép màu, và nó sẽ không liên quan gì đến may mắn.</p>\n\n\n\n<p>Những người thành công nhất trong xã hội chúng ta, ở mọi cấp độ, là những người biết và được biết đến bởi số lượng lớn nhất những người thành công khác. Nhưng đây rất giống tình huống con gà và quả trứng. Liệu người ta trở nên thành công và sau đó gặp những người thành công khác? Hay họ gặp những người thành công khác, và sau đó trở nên thành công?</p>\n\n\n\n<p>Thực tế là nó có thể hoạt động theo cả hai cách. Mọi người mắc sai lầm khi nghĩ rằng bằng cách ở bên cạnh những người thành công khác, họ sẽ có thể dựa vào kiến thức, lời khuyên và nguồn lực của họ. Tuy nhiên, điều này chỉ có hiệu quả trong thời gian ngắn. Về lâu dài, bạn không bao giờ có thể có và giữ được bất cứ thứ gì mà bạn không xứng đáng như là kết quả của những thành tích, tài năng và tính cách của chính bạn.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"attracting-important\">Tập trung vào Việc Thu hút Những Người Quan trọng</h3>\n\n\n\n<p>Luật Hấp dẫn có lẽ là yếu tố may mắn quan trọng nhất. &#8220;Bạn không thể tránh khỏi việc thu hút vào cuộc sống của mình những người và hoàn cảnh hài hòa với những suy nghĩ chủ đạo của bạn.&#8221;</p>\n\n\n\n<p>Đối lập với Luật Hấp dẫn là Luật Đẩy lùi, nó nói rằng, &#8220;Bạn tự động đẩy đi hoặc đẩy lùi những người và hoàn cảnh không hài hòa với những suy nghĩ chủ đạo của bạn.&#8221;</p>\n\n\n\n<p>Khi bạn suy nghĩ tích cực phần lớn thời gian, bạn tạo ra một trường lực của năng lượng tích cực thu hút những người và tình huống tích cực khác đến với bạn. Nếu bạn suy nghĩ tiêu cực, bạn tạo ra một trường năng lượng tiêu cực đẩy đi những lực lượng này.</p>\n\n\n\n<p>Chim cùng một loại bay cùng đàn. Những người ở cùng mức độ thành công trong mọi doanh nghiệp hoặc nghề nghiệp thường bị thu hút bởi nhau. Và bạn không thể giả vờ được lâu.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"indirect-effort\">Áp dụng Luật Nỗ lực Gián tiếp (the Law of Indirect Effort)</h3>\n\n\n\n<p>Điều này dẫn chúng ta đến một yếu tố may mắn quan trọng &#8211; Luật Nỗ lực Gián tiếp. Luật này nói rằng thường thì bạn đạt được điều mình muốn từ người khác một cách gián tiếp hơn là trực tiếp. Thực tế, nếu bạn cố gắng khiến người khác giúp đỡ hoặc hợp tác với bạn một cách trực tiếp, bạn thường sẽ trông có vẻ ngớ ngẩn. Bạn thực sự sẽ khiến những người đó tránh xa bạn.</p>\n\n\n\n<p>Nhưng nếu bạn sử dụng Luật Nỗ lực Gián tiếp, bạn sẽ ngạc nhiên về mức độ thành công của mình. Ví dụ, nếu bạn muốn có nhiều bạn bè hơn, làm thế nào để bạn sử dụng Luật Nỗ lực Gián tiếp? Rất đơn giản. Tập trung vào việc trở thành một người bạn tốt cho người khác. Quan tâm đến họ. Hỏi họ những câu hỏi và lắng nghe những gì họ nói. Hãy đồng cảm. Thể hiện sự quan tâm và lo lắng về vấn đề và tình huống của họ. Tìm cách giúp đỡ họ, ngay cả khi chỉ là bằng cách trở thành một người bạn lắng nghe. Càng tập trung vào việc trở thành một người bạn tốt, bạn sẽ càng có nhiều bạn bè. Bạn sẽ thu hút mọi người vào cuộc sống của mình như ong đến với mật.</p>\n\n\n\n<p>Bạn muốn gây ấn tượng với người khác? Cách tồi tệ nhất để làm điều đó là cách trực tiếp, bằng cách cố gắng gây ấn tượng với họ. Cách tốt nhất là cách gián tiếp, bằng cách bị ấn tượng bởi người khác. Bạn càng ấn tượng với người khác và thành tích của họ, họ sẽ càng quan tâm và ấn tượng với bạn và thành tích của bạn. Mọi người đều đã làm điều gì đó đáng chú ý và ấn tượng. Khi bạn gặp một người mới, nhiệm vụ của bạn là tìm ra điều đó.</p>\n\n\n\n<p>Hỏi mọi người họ làm gì. Hỏi mọi người làm thế nào họ tham gia vào lĩnh vực cụ thể của họ. Hỏi mọi người mọi thứ đang diễn ra như thế nào trong công việc của họ. Nếu bạn lắng nghe cẩn thận, mọi người sẽ nói với bạn về cả thành công hiện tại và vấn đề hiện tại của họ. Khi một người đề cập rằng họ vừa đạt được điều gì đó đáng giá, hãy chắc chắn chúc mừng họ.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"likes-praise\">Ai cũng Thích được Khen ngợi</h3>\n\n\n\n<p>Abraham Lincoln từng nói, &#8220;Ai cũng thích được khen ngợi.&#8221; Mọi người đều yêu thích được công nhận và ngưỡng mộ vì những điều họ đã đạt được. Hãy đặt ra chính sách tìm hiểu những gì họ đã đạt được và sau đó khen ngợi họ về những thành công của họ.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-1-1024x683.png\" alt=\"\" class=\"wp-image-4560\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-1-1024x683.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-1-600x400.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-1-300x200.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-1-768x512.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-1.png 1050w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /><figcaption class=\"wp-element-caption\"><strong>Abraham Lincoln.</strong> daily.jstor.org </figcaption></figure>\n\n\n\n<p>Một doanh nhân thành đạt mà tôi biết đã có thói quen gửi mười bức điện tín mỗi tuần cho những người ông đã gặp qua nhiều năm. Các bức điện tín chỉ chứa một từ duy nhất, &#8220;Chúc mừng!&#8221;</p>\n\n\n\n<p>Qua nhiều năm, ông đã xây dựng được một mạng lưới rộng lớn gồm những người đàn ông và phụ nữ quý mến và tôn trọng ông. Họ luôn ngạc nhiên rằng bằng cách nào đó ông đã biết họ vừa hoàn thành điều gì đó đáng giá và đã ghi nhận họ bằng bức điện tín của mình.</p>\n\n\n\n<p>Khi được hỏi, sau này trong đời, làm thế nào ông có thể biết được thành tích của rất nhiều bạn bè của mình, ông nói rằng ông không hề biết họ đang làm gì. Ông chỉ biết rằng mọi người đều đang hoàn thành điều gì đó mỗi ngày và mỗi tuần. Khi bạn gửi cho họ một thông điệp nói rằng &#8220;Chúc mừng!&#8221; họ sẽ tự động áp dụng thông điệp đó vào bất kỳ tình huống nào trong cuộc sống của họ vừa diễn ra thành công.</p>\n\n\n\n<p>Bằng cách sử dụng Luật Nỗ lực Gián tiếp, bạn liên tục tìm kiếm cách để khen ngợi và chúc mừng mọi người về những gì họ đang làm, những gì họ đã hoàn thành, cách họ ăn mặc, những quyết định gần đây họ đã đưa ra, hoặc thậm chí là việc họ đã giảm được vài cân.</p>\n\n\n\n<p>Trong xã hội chúng ta, một trong những lời khen tốt nhất mà bạn có thể dành cho bất kỳ ai là, &#8220;Trông bạn có vẻ đã giảm cân!&#8221; Ngay cả khi điều đó không đúng, mọi người luôn thích có người nhận ra, đúng hay sai, rằng họ đã giảm cân. Tại sao? Bởi vì ai cũng muốn có vẻ ngoài hấp dẫn, và sự hấp dẫn về mặt thể chất gắn liền với việc thon gọn, săn chắc và khỏe mạnh. Bạn không bao giờ sai khi khen ngợi ai đó về vẻ ngoài tốt của họ.</p>\n\n\n\n<h3 class=\"wp-block-heading\" id=\"deep-needs\">Đáp ứng Một trong những Nhu cầu Sâu sắc nhất của Con người</h3>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-2-1024x683.png\" alt=\"Respect - \" class=\"wp-image-4562\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-2-1024x683.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-2-600x400.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-2-300x200.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-2-768x512.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-2-1536x1024.png 1536w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-2.png 1600w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></figure>\n\n\n\n<p>Bạn có muốn mọi người tôn trọng bạn không? Đây là một trong những nhu cầu sâu sắc nhất. Gần như mọi thứ bạn làm đều là để kiếm được sự tôn trọng từ những người bạn tôn trọng, hoặc ít nhất là để không mất đi sự tôn trọng của những người bạn tôn trọng. Vì vậy, nếu bạn muốn mọi người tôn trọng bạn, cách tốt nhất là bạn hãy tôn trọng họ trước.</p>\n\n\n\n<p>Chúng ta đã rời xa thời đại của người &#8220;đi lấy&#8221; và hiện đang ở trong thời đại của &#8220;người đi cho&#8221;. Những người thành công luôn tìm cách làm điều gì đó cho người khác. Phần lớn những người kém thành đạt và không hạnh phúc là những người đang chờ đợi người khác làm điều gì đó cho họ trước. Họ muốn nhận được điều gì đó trước khi họ bỏ ra điều gì đó.</p>\n\n\n\n<p>Nhưng thái độ này vi phạm Luật Gieo và Gặt. Bạn không thể gặt hái cho đến khi bạn đã gieo trồng. Do đó, bạn tập trung vào việc gieo những suy nghĩ tốt, ý tưởng tốt và cảm xúc tốt trong các mối quan hệ của bạn với người khác. Bạn biết, như một quy luật phổ quát, rằng những điều tương tự sẽ quay trở lại với bạn theo những cách đáng kinh ngạc nhất.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"references\"><strong>Tài liệu tham khảo:</strong></h2>\n\n\n\n<p>Tracy, B. (2002). <a href=\"https://www.amazon.com/Create-Your-Own-Future-Unlimited/dp/0471251070\"><em>Create Your Own Future</em>.</a> New Jersey: John Wiley &amp; Sons. Chương 7: &#8220;Nguyên tắc 6 &#8211; Các mối quan hệ là thiết yếu&#8221;.</p>\n\n\n\n<p>Bản dịch: <a href=\"https://blog.kenfinly.com/author/dieter/\">Dieter R.</a></p>\n\n\n\n<p></p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:352:\"<p>Khám phá bí quyết xây dựng mối quan hệ bền vững từ Brian Tracy. Tìm hiểu Luật Mối quan hệ giúp mở rộng mạng lưới và tạo cơ hội thành công trong cuộc sống. Nội dung Xem Luật Mối Quan Hệ: Bí Quyết Xây Dựng Mạng Lưới Người Biết Đến Bạn Để Mở Cánh Cửa [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:4555;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:40;}s:4:\"tags\";a:2:{i:0;i:724;i:1;i:725;}s:10:\"class_list\";a:10:{i:0;s:9:\"post-4554\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:18:\"has-post-thumbnail\";i:6;s:6:\"hentry\";i:7;s:13:\"category-sach\";i:8;s:15:\"tag-brian-tracy\";i:9;s:26:\"tag-create-your-own-future\";}s:6:\"_links\";a:11:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4554\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=4554\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:8;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4554/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:4572;s:4:\"href\";s:65:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4554/revisions/4572\";}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/media/4555\";}}s:13:\"wp:attachment\";a:1:{i:0;a:1:{s:4:\"href\";s:57:\"https://blog.kenfinly.com/wp-json/wp/v2/media?parent=4554\";}}s:7:\"wp:term\";a:2:{i:0;a:3:{s:8:\"taxonomy\";s:8:\"category\";s:10:\"embeddable\";b:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/categories?post=4554\";}i:1;a:3:{s:8:\"taxonomy\";s:8:\"post_tag\";s:10:\"embeddable\";b:1;s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/tags?post=4554\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}s:9:\"_embedded\";a:3:{s:6:\"author\";a:1:{i:0;a:8:{s:2:\"id\";i:1;s:4:\"name\";s:9:\"Dieter R.\";s:3:\"url\";s:16:\"http://kenkai.vn\";s:11:\"description\";s:401:\"Xin chào, tôi là Dieter R., một cây bút đam mê tại KenkAI.vn, đang sinh sống và làm việc tại Thành phố Hồ Chí Minh sôi động. Với niềm đam mê mãnh liệt về lĩnh vực lãnh đạo, tâm lý học, trí tuệ nhân tạo, công nghệ và phát triển bản thân, tôi luôn nỗ lực mang đến những nội dung giá trị và sâu sắc cho độc giả.\";s:4:\"link\";s:40:\"https://blog.kenfinly.com/author/dieter/\";s:4:\"slug\";s:6:\"dieter\";s:11:\"avatar_urls\";a:3:{i:24;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24&d=mm&r=g\";i:48;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=48&d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"