tion\";a:1:{s:8:\"rendered\";s:163:\"<p>Khám phá chi phí cơ hội &#8211; phân tích sâu về các quyết định kinh tế, so sánh lựa chọn và đánh giá giá trị bị bỏ qua.</p>\n\";}s:8:\"alt_text\";s:128:\"Stacked coins under a magnifying glass illustrating economic decision-making and opportunity cost (Chi phí cơ hội) analysis.\";s:10:\"media_type\";s:5:\"image\";s:9:\"mime_type\";s:10:\"image/jpeg\";s:13:\"media_details\";a:6:{s:5:\"width\";i:960;s:6:\"height\";i:540;s:4:\"file\";s:45:\"2025/08/chi-phi-co-hoi-quyet-dinh-kinh-te.jpg\";s:8:\"filesize\";i:50837;s:5:\"sizes\";a:7:{s:6:\"medium\";a:6:{s:4:\"file\";s:45:\"chi-phi-co-hoi-quyet-dinh-kinh-te-300x169.jpg\";s:5:\"width\";i:300;s:6:\"height\";i:169;s:8:\"filesize\";i:10874;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:98:\"https://blog.kenfinly.com/wp-content/uploads/2025/08/chi-phi-co-hoi-quyet-dinh-kinh-te-300x169.jpg\";}s:9:\"thumbnail\";a:6:{s:4:\"file\";s:45:\"chi-phi-co-hoi-quyet-dinh-kinh-te-150x150.jpg\";s:5:\"width\";i:150;s:6:\"height\";i:150;s:8:\"filesize\";i:7900;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:98:\"https://blog.kenfinly.com/wp-content/uploads/2025/08/chi-phi-co-hoi-quyet-dinh-kinh-te-150x150.jpg\";}s:12:\"medium_large\";a:6:{s:4:\"file\";s:45:\"chi-phi-co-hoi-quyet-dinh-kinh-te-768x432.jpg\";s:5:\"width\";i:768;s:6:\"height\";i:432;s:8:\"filesize\";i:34442;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:98:\"https://blog.kenfinly.com/wp-content/uploads/2025/08/chi-phi-co-hoi-quyet-dinh-kinh-te-768x432.jpg\";}s:21:\"woocommerce_thumbnail\";a:6:{s:4:\"file\";s:45:\"chi-phi-co-hoi-quyet-dinh-kinh-te-450x450.jpg\";s:5:\"width\";i:450;s:6:\"height\";i:450;s:8:\"filesize\";i:25998;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:98:\"https://blog.kenfinly.com/wp-content/uploads/2025/08/chi-phi-co-hoi-quyet-dinh-kinh-te-450x450.jpg\";}s:18:\"woocommerce_single\";a:6:{s:4:\"file\";s:45:\"chi-phi-co-hoi-quyet-dinh-kinh-te-600x338.jpg\";s:5:\"width\";i