finly.com/wp-json/wp/v2/posts?tags=741\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}i:1;a:6:{s:2:\"id\";i:864;s:4:\"link\";s:69:\"https://blog.kenfinly.com/tag/suc-manh-cang-lon-trach-nhiem-cang-cao/\";s:4:\"name\";s:49:\"Sức mạnh càng lớn trách nhiệm càng cao\";s:4:\"slug\";s:38:\"suc-manh-cang-lon-trach-nhiem-cang-cao\";s:8:\"taxonomy\";s:8:\"post_tag\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:48:\"https://blog.kenfinly.com/wp-json/wp/v2/tags/864\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:44:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=864\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}i:2;a:6:{s:2:\"id\";i:865;s:4:\"link\";s:61:\"https://blog.kenfinly.com/tag/trach-nhiem-cua-nguoi-lanh-dao/\";s:4:\"name\";s:42:\"Trách nhiệm của người lãnh đạo\";s:4:\"slug\";s:30:\"trach-nhiem-cua-nguoi-lanh-dao\";s:8:\"taxonomy\";s:8:\"post_tag\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:48:\"https://blog.kenfinly.com/wp-json/wp/v2/tags/865\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:44:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=865\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}i:3;a:6:{s:2:\"id\";i:863;s:4:\"link\";s:46:\"https://blog.kenfinly.com/tag/van-hoa-cong-ty/\";s:4:\"name\";s:18:\"Văn hóa công ty\";s:4:\"slug\";s:15:\"van-hoa-cong-ty\";s:8:\"taxonomy\";s:8:\"post_tag\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:48:\"https://blog.kenfinly.com/wp-json/wp/v2/tags/863\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:44:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=863\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}}}}i:8;a:26:{s:2:\"id\";i:5330;s:4:\"date\";s:19:\"2025-07-28T19:00:00\";s:8:\"date_gmt\";s:19:\"2025-07-28T12:00:00\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=5330\";}s:8:\"modified\";s:19:\"2025-07-01T15:56:50\";s:12:\"modified_gmt\";s:19:\"2025-07-01T08:56:50\";s:4:\"slug\";s:36:\"muc-dich-la-nen-tang-cho-su-lanh-dao\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:71:\"https://blog.kenfinly.com/ky-nang/muc-dich-la-nen-tang-cho-su-lanh-dao/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:64:\"Mục Đích Là Nền Tảng Cho Sự Lãnh Đạo Hiệu Quả\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:14729:\"\n<p>Khám phá bí quyết lãnh đạo hiệu quả từ bức thư của Rockefeller. &#8220;Mục đích là nền tảng cho sự lãnh đạo của tôi, và mục đích là tất cả&#8221;</p>\n\n\n\n<h2 class=\"wp-block-heading\">Giới thiệu</h2>\n\n\n\n<p>Khi bạn đang trên con đường trở thành một nhà lãnh đạo, bạn có bao giờ tự hỏi, điều gì tạo nên sự khác biệt giữa một người lãnh đạo xuất sắc và một người lãnh đạo tầm thường? </p>\n\n\n\n<p>Câu trả lời nằm ở mục đích.</p>\n\n\n\n<p>Mục đích không chỉ là động lực thúc đẩy tiềm năng, mà còn là sức mạnh chi phối mọi hành động và quyết định của nhà lãnh đạo.</p>\n\n\n\n<p>Bài viết sau sẽ đưa bạn khám phá cách mục đích định hình phong cánh lãnh đạo, tạo dựng lòng tin, truyền cảm hứng cho đội ngũ, dựa trên bài học quý giá từ một trong những nhà lãnh đạo kinh doanh vĩ đại nhất lịch sử.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Bức thư số 31: Mục đích là nền tảng cho sự lãnh đạo của tôi, và mục đích là tất cả</h2>\n\n\n\n<p>Ngày 11 tháng 5 năm 1902</p>\n\n\n\n<p>John thân mến,</p>\n\n\n\n<p>Vinh quang của con và vinh quang của cha là con đang ở vị trí trung tâm của Standard Oil. Tuy nhiên, con cần biết rằng, khi con đang tận hưởng vinh quang này, con chắc chắn sẽ phải gánh vác những trách nhiệm đi kèm với nó. </p>\n\n\n\n<p>Nếu không, con sẽ xấu hổ về vinh quang này, và sẽ làm thất vọng hy vọng và sự tin tưởng của mọi người dành cho con.</p>\n\n\n\n<p>Đừng quên rằng con là xương sống của Công ty Standard Oil. </p>\n\n\n\n<p>Thành công hay thất bại cuối cùng của doanh nghiệp chúng ta có liên quan mật thiết đến con.</p>\n\n\n\n<p>Con nên có những đòi hỏi cao hơn đối với bản thân khi nói đến sức mạnh và sự hy sinh.</p>\n\n\n\n<p>Nói thẳng ra, nếu con muốn làm tốt công việc ở vị trí đó, và để mọi người công nhận con và ngưỡng mộ con, con vẫn cần phải học hỏi rất nhiều. </p>\n\n\n\n<p>Bây giờ, con cần suy nghĩ về một câu hỏi: Liệu con có thể tự mình đảm nhận thành công vai trò này không.</p>\n\n\n\n<p>Mỗi nhà lãnh đạo là một đại sứ của hy vọng, và là một người thầy cho cấp dưới trên con đường gai góc không thể tránh khỏi phía trước.</p>\n\n\n\n<p>Nhưng việc không bị thất vọng là khó khăn.</p>\n\n\n\n<p>Là một nhà lãnh đạo, bất kể con là ai, con sẽ đối mặt với nhiều vấn đề, chẳng hạn như núi công việc, núi thông tin, những thay đổi đột ngột, vô số yêu cầu từ ban quản lý cấp cao, nhà đầu tư và khách hàng, và những nhân viên khó đào tạo.</p>\n\n\n\n<p>Những thách thức luôn thay đổi, có thể khiến con kiệt sức, cảm thấy thất vọng, sợ hãi, lo lắng, và choáng ngợp, điều này có thể làm tan vỡ ước mơ đạt được thành công trong kinh doanh và cá nhân của con.</p>\n\n\n\n<p>Tuy nhiên, đôi khi việc trở thành một nhà lãnh đạo xuất sắc đầy tự tin và sức sống dễ dàng hơn việc trở thành một nhà lãnh đạo mất sức sống, và đang vật lộn và bất lực, với điều kiện là anh ta cần biết cách làm cho cấp dưới của mình sẵn sàng hy sinh.</p>\n\n\n\n<p>Là nhà lãnh đạo của công ty Standard Oil, cha được hưởng cả quyền lực lẫn niềm vui, bởi vì cha biết rằng, tìm được người có thể đảm bảo hoàn thành nhiệm vụ tương đương với việc tạo ra thời gian cho bản thân.</p>\n\n\n\n<p>Nói cách khác, nó sẽ không chỉ làm cho cha tràn đầy năng lượng, mà quan trọng hơn, nó sẽ cho cha thêm thời gian để suy nghĩ về cách kiếm được nhiều tiền hơn cho công ty.</p>\n\n\n\n<p>Có một vấn đề về thái độ ở đây.</p>\n\n\n\n<p>Hành động được thúc đẩy bởi thái độ.</p>\n\n\n\n<p>Thái độ mà chúng ta chọn, quyết định hành vi nào chúng ta muốn thực hiện.</p>\n\n\n\n<p>Về kết quả, nó sẽ sớm hiện rõ với chúng ta.</p>\n\n\n\n<p>Con người có thể thay đổi cuộc sống của họ bằng cách thay đổi thái độ.</p>\n\n\n\n<p>Nếu con tin rằng con có thể thay đổi thái độ, con có thể thay đổi nó.</p>\n\n\n\n<p>Người thông minh luôn chọn thái độ tốt nhất cho họ. </p>\n\n\n\n<p>Những người biết nghệ thuật lãnh đạo sẽ luôn tự hỏi: Loại thái độ nào có thể giúp họ đạt được kết quả mà họ thực sự muốn? Có phải là một thái độ truyền cảm hứng? Hay là thái độ đồng cảm? Họ sẽ không bao giờ chọn một thái độ lạnh lùng hoặc thù địch.</p>\n\n\n\n<p>Nếu con tự coi mình là một vị vua tối cao, tuyệt vọng, con có khả năng trở thành vua Louis XVI tiếp theo.</p>\n\n\n\n<p>Thay vào đó, cha có thói quen trao cho cấp dưới sự tin tưởng, nâng cao tinh thần cho họ, và đổi lại, đạt được những thành tựu kinh doanh mà cha mong đợi.</p>\n\n\n\n<p>Thói quen này sẽ giúp cha đạt được mục đích cha muốn bằng cách sử dụng cấp dưới.</p>\n\n\n\n<p>Cách làm này rất đơn giản, đó là biết cách sử dụng sức mạnh của việc đặt mục tiêu.</p>\n\n\n\n<p>Cha là một nhà mục đích luận. </p>\n\n\n\n<p>Cha không bao giờ phóng đại chức năng của việc có một mục tiêu như một số người làm, nhưng cha rất coi trọng chức năng của nó.</p>\n\n\n\n<p>Theo quan điểm của cha, mục đích là động lực đằng sau tiềm năng của chúng ta, và nó là sức mạnh chi phối mọi thứ.</p>\n\n\n\n<p>Nó có thể ảnh hưởng đến hành vi của chúng ta, và truyền cảm hứng cho chúng ta tạo ra các phương tiện để đạt được mục tiêu của mình.</p>\n\n\n\n<p>Một mục đích rõ ràng và quyết đoán sẽ cho phép chúng ta tập trung vào hướng đã chọn và cho phép chúng ta cố gắng hết sức để đạt được mục tiêu.</p>\n\n\n\n<p>Kinh nghiệm của cha cho cha biết rằng, những nhiệm vụ mà một người hoàn thành và hiệu suất cuối cùng của anh ta có liên quan chặt chẽ đến bản chất và sức mạnh của mục đích của anh ta, và hầu như không liên quan gì đến những gì anh ta làm cho mục tiêu của mình.</p>\n\n\n\n<p>Hãy nghĩ về điều đó, không có trò chơi golf nào có thể hoàn thành trong một cú đánh.</p>\n\n\n\n<p>Con cần phải hoàn thành từng lỗ một.</p>\n\n\n\n<p>Mục tiêu của mỗi cú đánh là đến càng gần lỗ càng tốt.</p>\n\n\n\n<p>Có một mục đích là cơ sở của sự lãnh đạo của cha, và nó là tất cả.</p>\n\n\n\n<p>Cha quen với việc thiết lập mục tiêu trước khi làm bất cứ điều gì, và mỗi ngày cha phải đặt ra mục tiêu, vô số mục tiêu, chẳng hạn như mục đích của việc nói chuyện với đối tác, mục đích của việc triệu tập các cuộc họp, mục đích của việc lập kế hoạch, và v.v. </p>\n\n\n\n<p>Trước khi làm điều gì đó, cha cũng sẽ xem xét lại mục đích mà cha đã đặt ra.</p>\n\n\n\n<p>Thông thường khi cha đến công ty, cha đã chuẩn bị mọi thứ.</p>\n\n\n\n<p>Do đó, cha chưa bao giờ &#8220;nuốt&#8221; những giọng nói như &#8220;tôi không thể làm gì khác&#8221;, &#8220;tôi không quan tâm nữa&#8221;, &#8220;không còn hy vọng nữa&#8221; trong lòng mình.</p>\n\n\n\n<p>Mục đích mà cha thiết lập mỗi ngày đã bù đắp những thất bại này.</p>\n\n\n\n<p>Nếu con không thể chủ động thiết lập các mục tiêu của chính mình, con sẽ bị động, hoặc vô thức chọn các mục tiêu khác.</p>\n\n\n\n<p>Kết quả là, con có thể mất kiểm soát tình hình tổng thể.</p>\n\n\n\n<p>Đồng thời, con sẽ bị chi phối bởi những người hoặc sự kiện có thể làm con mất tập trung hoặc làm phiền con.</p>\n\n\n\n<p>Giống như việc nới lỏng một chiếc du thuyền khỏi bến cảng, và quên khởi động động cơ, con sẽ đi theo dòng chảy, và gió biển, dòng chảy hoặc những con tàu khác có thể đâm vào con, và khiến con chìm xuống đáy biển bất cứ lúc nào.</p>\n\n\n\n<p>Có thể điều gì đó tốt đẹp đang chờ đợi con ở phía bên kia, nhưng trừ khi một phép màu xảy ra, con sẽ không thể đến được bên kia một cách suôn sẻ.</p>\n\n\n\n<p>Thiết lập một mục đích giống như bật động cơ của một chiếc du thuyền, con có thể đẩy con hướng tới con đường con chọn.</p>\n\n\n\n<p>Mục đích có thể thêm hướng đi và sức mạnh cho nỗ lực con người.</p>\n\n\n\n<p>Tuy nhiên, việc thiết lập một mục đích chỉ đưa con đến giữa con đường để trở thành một nhà mục đích luận, và con phải hoàn thành nửa còn lại của hành trình.</p>\n\n\n\n<p>Con cần phải không ngần ngại nêu rõ mục đích của mình cho cấp dưới &#8211; ý định cá nhân, động cơ và kế hoạch chiến lược bên trong con. Đối với mọi người, cần hiểu những gì cha muốn đạt được, cha sẽ giải thích mục đích của cha cho họ. Trong mọi cuộc họp, báo cáo hoặc vào đầu vấn đề, cha sẽ trước tiên bày tỏ động lực, suy nghĩ và mong đợi của mình.</p>\n\n\n\n<p>Lợi ích của điều này sẽ làm con ngạc nhiên. Nó không chỉ cho phép cấp dưới của con biết mục đích của con và mang đến cho họ hướng đi đúng đắn để tiến lên, mà quan trọng nhất, khi con có can đảm trung thực về mục đích của mình, con sẽ đạt được lòng trung thành về mặt cảm xúc. Hãy biết rằng lòng trung thành là khởi đầu của sự sẵn lòng phục vụ.</p>\n\n\n\n<p>Những nhà lãnh đạo xuất sắc giỏi sử dụng hai lực lượng vô hình: tin tưởng và tôn trọng. Khi con trung thực nêu rõ mục đích của mình, con cũng sẽ truyền tải thông điệp này: &#8220;Vì tôi có đủ tin tưởng vào bạn, tôi sẵn lòng thú nhận với bạn.&#8221; Nó sẽ mở cánh cửa cho mọi người tin tưởng con, và những gì con ôm ấp không chỉ là khả năng của cấp dưới, mà còn là lòng trung thành vô giá từ họ &#8211; lòng trung thành phải được tập hợp để giúp đỡ con.</p>\n\n\n\n<p>Tin tưởng người khác và làm cho người khác tin tưởng vào bản thân cha là những lý do quan trọng cho những thành tựu của cha trong cuộc sống.</p>\n\n\n\n<p>Việc bộc lộ mục đích của con có thể tránh được những suy luận không hữu ích.</p>\n\n\n\n<p>Nếu con không nói cho cấp dưới về mục đích của mình, họ sẽ dành thời gian đoán xem nó là gì dựa trên những manh mối mà họ có thể thu thập được, và thông tin này dễ bị bóp méo.</p>\n\n\n\n<p>Chỉ khi họ không cần phải diễn giải động cơ của con, tinh thần và khả năng của cấp dưới mới có cơ hội được cải thiện. Do đó, dường như có lợi hơn khi đối xử với cấp dưới như &#8220;những kẻ ngốc&#8221;.</p>\n\n\n\n<p>Sức mạnh được thể hiện bởi mục đích là không thể thay thế.</p>\n\n\n\n<p>Những gì nó truyền tải không chỉ là một tuyên bố, mà còn là lời thề dũng cảm và kiên quyết của nhà lãnh đạo đối với hành vi cá nhân.</p>\n\n\n\n<p>Mục đích của ý chí kiên quyết và sự kiên trì tuyệt đối thường có thể truyền cảm hứng và khuyến khích cấp dưới, để họ có thể mang lại hiệu suất xuất sắc hơn trong công việc tương lai.</p>\n\n\n\n<p>Nhiệm vụ của một nhà lãnh đạo là phát hiện vấn đề và giải quyết vấn đề phụ thuộc vào cấp dưới.</p>\n\n\n\n<p>Làm thế nào để huy động cấp dưới và hoàn thành nhiệm vụ của họ là ưu tiên hàng đầu đối với các nhà lãnh đạo.</p>\n\n\n\n<p>Cha nghĩ rằng bằng cách thể hiện mục đích của mình và đối xử với mọi người bằng sự nhiệt tình, con có thể đạt được những gì con muốn.</p>\n\n\n\n<p>Mục đích giống như một viên kim cương: nếu nó có giá trị, nó phải là thật. </p>\n\n\n\n<p>Một lời thú nhận mục đích không chân thành sẽ chỉ làm hại.</p>\n\n\n\n<p>Nếu một người lạm dụng sức mạnh của mục đích, anh ta sẽ chỉ phá hủy sự tin tưởng lẫn nhau và mất đi sự tin tưởng của người khác. Đây là rủi ro của việc bộc lộ mục đích.</p>\n\n\n\n<p>John, con đường đến địa ngục được lát bằng lòng tốt. Trừ khi con đã chuẩn bị đầy đủ, câu nói này có khả năng trở thành sự thật.</p>\n\n\n\n<p>Yêu thương,</p>\n\n\n\n<p>Cha của con.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Kết luận</h2>\n\n\n\n<p>Mục đích không chỉ là kim chỉ nam mà còn là động lực thúc đẩy mọi nhà lãnh đạo vượt qua thử thách. Như bức thư đã chỉ ra, việc thiết lập và chia sẻ mục đích một cách chân thành chính là chìa khóa để xây dựng lòng tin, tạo nên sự gắn kết và thúc đẩy hiệu suất làm việc.</p>\n\n\n\n<p>Một nhà lãnh đạo có mục đích sẽ không bao giờ cảm thấy bất lực trước khó khăn, bởi vì họ luôn biết mình đang hướng đến điều gì.</p>\n\n\n\n<p>Bạn nghĩ gì về triết lý lãnh đạo này? Liệu mục đích có thực sự là nền tảng cho mọi thành công trong lãnh đạo? </p>\n\n\n\n<p>Nếu bạn thấy bài viết này hữu ích, hãy giúp đội ngũ kipmtuduy chia sẻ thông điệp ý nghĩa này đến nhiều người hơn nhé!</p>\n\n\n\n<p>Xin cám ơn!</p>\n\n\n\n<p>Dieter R.</p>\n\n\n\n<p>#LãnhĐạoCóMụcĐích #NghệThuậtLãnhĐạo #XâyDựngLòngTin #PhátTriểnBảnThân #KinhNghiệmLãnhĐạo</p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:361:\"<p>Khám phá bí quyết lãnh đạo hiệu quả từ bức thư của Rockefeller. &#8220;Mục đích là nền tảng cho sự lãnh đạo của tôi, và mục đích là tất cả&#8221; Giới thiệu Khi bạn đang trên con đường trở thành một nhà lãnh đạo, bạn có bao giờ tự hỏi, điều gì tạo nên sự [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:4;}s:4:\"tags\";a:5:{i:0;i:862;i:1;i:625;i:2;i:468;i:3;i:741;i:4;i:803;}s:10:\"class_list\";a:12:{i:0;s:9:\"post-5330\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:6:\"hentry\";i:6;s:16:\"category-ky-nang\";i:7;s:24:\"tag-lanh-dao-co-muc-dich\";i:8;s:23:\"tag-nghe-thuat-lanh-dao\";i:9;s:23:\"tag-phat-trien-ban-than\";i:10;s:15:\"tag-rockefeller\";i:11;s:21:\"tag-xay-dung-long-tin\";}s:6:\"_links\";a:10:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/5330\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=5330\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/5330/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:5331;s:4:\"href\";s:65:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/5330/revisions/5331\";}}s:13:\"wp:attachment\";a:1:{i:0;a:1:{s:4:\"href\";s:57:\"https://blog.kenfinly.com/wp-json/wp/v2/media?parent=5330\";}}s:7:\"wp:term\";a:2:{i:0;a:3:{s:8:\"taxonomy\";s:8:\"category\";s:10:\"embeddable\";b:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/categories?post=5330\";}i:1;a:3:{s:8:\"taxonomy\";s:8:\"post_tag\";s:10:\"embeddable\";b:1;s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/tags?post=5330\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}s:9:\"_embedded\";a:2:{s:6:\"author\";a:1:{i:0;a:8:{s:2:\"id\";i:1;s:4:\"name\";s:9:\"Dieter R.\";s:3:\"url\";s:16:\"http://kenkai.vn\";s:11:\"description\";s:401:\"Xin chào, tôi là Dieter R., một cây bút đam mê tại KenkAI.vn, đang sinh sống và làm việc tại Thành phố Hồ Chí Minh sôi động. Với niềm đam mê mãnh liệt về lĩnh vực lãnh đạo, tâm lý học, trí tuệ nhân tạo, công nghệ và phát triển bản thân, tôi luôn nỗ lực mang đến những nội dung giá trị và sâu sắc cho độc giả.\";s:4:\"link\";s:40:\"https://blog.kenfinly.com/author/dieter/\";s:4:\"slug\";s:6:\"dieter\";s:11:\"avatar_urls\";a:3:{i:24;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24&d=mm&r=g\";i:48;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=48&d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:7:\"wp:term\";a:2:{i:0;a:1:{i:0;a:6:{s:2:\"id\";i:4;s:4:\"link\";s:43:\"https://blog.kenfinly.com/category/ky-nang/\";s:4:\"name\";s:10:\"Kỹ năng\";s:4:\"slug\";s:7:\"ky-nang\";s:8:\"taxonomy\";s:8:\"category\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:52:\"https://blog.kenfinly.com/wp-json/wp/v2/categories/4\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/categories\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/category\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?categories=4\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}i:1;a:5:{i:0;a:6:{s:2:\"id\";i:862;s:4:\"link\";s:51:\"https://blog.kenfinly.com/tag/lanh-dao-co-muc-dich/\";s:4:\"name\";s:29:\"Lãnh Đạo Có Mục Đích\";s:4:\"slug\";s:20:\"lanh-dao-co-muc-dich\";s:8:\"taxonomy\";s:8:\"pos