\"thumbnail\";a:6:{s:4:\"file\";s:22:\"CANH-TRANH-150x150.png\";s:5:\"width\";i:150;s:6:\"height\";i:150;s:8:\"filesize\";i:42641;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:75:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/CANH-TRANH-150x150.png\";}s:14:\"mvp-port-thumb\";a:6:{s:4:\"file\";s:22:\"CANH-TRANH-560x360.png\";s:5:\"width\";i:560;s:6:\"height\";i:360;s:8:\"filesize\";i:291924;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:75:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/CANH-TRANH-560x360.png\";}s:15:\"mvp-large-thumb\";a:6:{s:4:\"file\";s:22:\"CANH-TRANH-590x354.png\";s:5:\"width\";i:590;s:6:\"height\";i:354;s:8:\"filesize\";i:287203;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:75:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/CANH-TRANH-590x354.png\";}s:13:\"mvp-mid-thumb\";a:6:{s:4:\"file\";s:22:\"CANH-TRANH-400x240.png\";s:5:\"width\";i:400;s:6:\"height\";i:240;s:8:\"filesize\";i:152267;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:75:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/CANH-TRANH-400x240.png\";}s:15:\"mvp-small-thumb\";a:6:{s:4:\"file\";s:20:\"CANH-TRANH-80x80.png\";s:5:\"width\";i:80;s:6:\"height\";i:80;s:8:\"filesize\";i:14573;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:73:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/CANH-TRANH-80x80.png\";}s:4:\"full\";a:5:{s:4:\"file\";s:14:\"CANH-TRANH.png\";s:5:\"width\";i:640;s:6:\"height\";i:360;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:67:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/CANH-TRANH.png\";}}s:10:\"image_meta\";a:12:{s:8:\"aperture\";s:1:\"0\";s:6:\"credit\";s:0:\"\";s:6:\"camera\";s:0:\"\";s:7:\"caption\";s:0:\"\";s:17:\"created_timestamp\";s:1:\"0\";s:9:\"copyright\";s:0:\"\";s:12:\"focal_length\";s:1:\"0\";s:3:\"iso\";s:1:\"0\";s:13:\"shutter_speed\";s:1:\"0\";s:5:\"title\";s:0:\"\";s:11:\"orientation\";s:1:\"0\";s:8:\"keywords\";a:0:{}}}s:10:\"source_u