:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}}}}i:7;a:26:{s:2:\"id\";i:4781;s:4:\"date\";s:19:\"2025-05-14T16:22:54\";s:8:\"date_gmt\";s:19:\"2025-05-14T09:22:54\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=4781\";}s:8:\"modified\";s:19:\"2025-05-14T16:35:42\";s:12:\"modified_gmt\";s:19:\"2025-05-14T09:35:42\";s:4:\"slug\";s:28:\"6-cap-do-tu-duy-ceo-hang-dau\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:64:\"https://blog.kenfinly.com/goc-nhin/6-cap-do-tu-duy-ceo-hang-dau/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:127:\"6 Cấp độ Tư Duy CEO Hàng đầu: Bí quyết xây dựng &#8220;Thương Hiệu Cá Nhân&#8221; Đỉnh Cao | Matt Gray\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:3452:\"\n<p>Trong video này, Matt Gray chia sẻ 6 cấp độ tư duy CEO mà anh đã khám phá qua nghiên cứu về Carl Icahn &#8211; tỷ phú quản lý 4 tỷ đô la trong khi vẫn duy trì hạnh phúc thực sự.</p>\n\n\n\n<p><img loading=\"lazy\" decoding=\"async\" height=\"16\" width=\"16\" alt=\"🚀\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tc6/1/16/1f680.png\">&nbsp;Hãy cùng nhau khám phá những bí mật đằng sau của những CEO hàng đầu, và học cách áp dụng chúng để xây dựng thương hiệu cá nhân của bạn!</p>\n\n\n\n<iframe loading=\"lazy\" src=\"https://www.facebook.com/plugins/video.php?height=314&#038;href=https%3A%2F%2Fwww.facebook.com%2F61573603022542%2Fvideos%2F1181399047051676%2F&#038;show_text=false&#038;width=560&#038;t=0\" width=\"560\" height=\"314\" style=\"border:none;overflow:hidden\" scrolling=\"no\" frameborder=\"0\" allowfullscreen=\"true\" allow=\"autoplay; clipboard-write; encrypted-media; picture-in-picture; web-share\" allowFullScreen=\"true\"></iframe>\n\n\n\n<p>Bây giờ là năm 2025, thế giới đang thay đổi nhanh hơn bao giờ hết. Và bạn và tôi cũng nên thay đổi để theo kịp thế giới. Xây dựng thương hiệu cá nhân đang trở nên phổ biến. Trong video này, Matt Gray chia sẻ 6 cấp độ tư duy CEO mà anh đã khám phá qua nghiên cứu về <a href=\"https://en.wikipedia.org/wiki/Carl_Icahn\">Carl Icahn</a> &#8211; tỷ phú quản lý 4 tỷ đô la trong khi vẫn duy trì hạnh phúc thực sự.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"416\" height=\"416\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-55.png\" alt=\"\" class=\"wp-image-4785\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-55.png 416w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-55-100x100.png 100w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-55-300x300.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-55-150x150.png 150w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-55-80x80.png 80w\" sizes=\"auto, (max-width: 416px) 100vw, 416px\" /><figcaption class=\"wp-element-caption\"><strong>Carl Icahn.</strong> forbes.com</figcaption></figure>\n\n\n\n<p><img loading=\"lazy\" decoding=\"async\" height=\"16\" width=\"16\" alt=\"🔑\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tad/1/16/1f511.png\">&nbsp;Bạn sẽ học được:</p>\n\n\n\n<p>• Cách ngừng gắn kết danh tính với một doanh nghiệp cụ thể</p>\n\n\n\n<p>• Bí quyết để trở thành nhà quản lý tài sản cho cuộc sống của chính mình</p>\n\n\n\n<p>• Phương pháp xây dựng thương hiệu cá nhân mạnh mẽ như các CEO hàng đầu</p>\n\n\n\n<p>Đừng bỏ lỡ cơ hội nâng cao tư duy và thương hiệu cá nhân của bạn! Xem ngay và chia sẻ với những người bạn quan tâm đến sự phát triển cá nhân.</p>\n\n\n\n<p><a href=\"https://www.facebook.com/watch/hashtag/personalbranding?__eep__=6%2F&amp;__tn__=*NK\">#personalbranding</a>&nbsp;<a href=\"https://www.facebook.com/watch/hashtag/tuduythanhcong?__eep__=6%2F&amp;__tn__=*NK\">#tuduythanhcong</a>&nbsp;<a href=\"https://www.facebook.com/watch/hashtag/phattrienbanthan?__eep__=6%2F&amp;__tn__=*NK\">#phattrienbanthan</a></p>\n\n\n\n<p>NGUỒN: <a href=\"https://www.youtube.com/watch?v=0MAVcXNNWSU\">https://www.youtube.com/watch?v=0MAVcXNNWSU</a></p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:316:\"<p>Trong video này, Matt Gray chia sẻ 6 cấp độ tư duy CEO mà anh đã khám phá qua nghiên cứu về Carl Icahn &#8211; tỷ phú quản lý 4 tỷ đô la trong khi vẫn duy trì hạnh phúc thực sự. &nbsp;Hãy cùng nhau khám phá những bí mật đằng sau của những CEO [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:4782;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:164;}s:4:\"tags\";a:1:{i:0;i:730;}s:10:\"class_list\";a:9:{i:0;s:9:\"post-4781\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:18:\"has-post-thumbnail\";i:6;s:6:\"hentry\";i:7;s:17:\"category-goc-nhin\";i:8;s:13:\"tag-matt-gray\";}s:6:\"_links\";a:11:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4781\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=4781\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:2;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4781/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:4786;s:4:\"href\";s:65:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4781/revisions/4786\";}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/media/4782\";}}s:13:\"wp:attachment\";a:1:{i:0;a:1:{s:4:\"href\";s:57:\"https://blog.kenfinly.com/wp-json/wp/v2/media?parent=4781\";}}s:7:\"wp:term\";a:2:{i:0;a:3:{s:8:\"taxonomy\";s:8:\"category\";s:10:\"embeddable\";b:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/categories?post=4781\";}i:1;a:3:{s:8:\"taxonomy\";s:8:\"post_tag\";s:10:\"embeddable\";b:1;s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/tags?post=4781\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}s:9:\"_embedded\";a:3:{s:6:\"author\";a:1:{i:0;a:8:{s:2:\"id\";i:1;s:4:\"name\";s:9:\"Dieter R.\";s:3:\"url\";s:16:\"http://kenkai.vn\";s:11:\"description\";s:401:\"Xin chào, tôi là Dieter R., một cây bút đam mê tại KenkAI.vn, đang sinh sống và làm việc tại Thành phố Hồ Chí Minh sôi động. Với niềm đam mê mãnh liệt về lĩnh vực lãnh đạo, tâm lý học, trí tuệ nhân tạo, công nghệ và phát triển bản thân, tôi luôn nỗ lực mang đến những nội dung giá trị và sâu sắc cho độc giả.\";s:4:\"link\";s:40:\"https://blog.kenfinly.com/author/dieter/\";s:4:\"slug\";s:6:\"dieter\";s:11:\"avatar_urls\";a:3:{i:24;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24&d=mm&r=g\";i:48;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=48&d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:15:{s:2:\"id\";i:4782;s:4:\"date\";s:19:\"2025-05-14T16:20:26\";s:4:\"slug\";s:28:\"6-cap-do-tu-duy-ceo-hang-dau\"