g. Với niềm đam mê mãnh liệt về lĩnh vực lãnh đạo, tâm lý học, trí tuệ nhân tạo, công nghệ và phát triển bản thân, tôi luôn nỗ lực mang đến những nội dung giá trị và sâu sắc cho độc giả.\";s:4:\"link\";s:40:\"https://blog.kenfinly.com/author/dieter/\";s:4:\"slug\";s:6:\"dieter\";s:11:\"avatar_urls\";a:3:{i:24;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24&d=mm&r=g\";i:48;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=48&d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:15:{s:2:\"id\";i:4769;s:4:\"date\";s:19:\"2025-05-14T12:34:52\";s:4:\"slug\";s:24:\"lap-ke-hoach-cho-may-man\";s:4:\"type\";s:10:\"attachment\";s:4:\"link\";s:88:\"https://blog.kenfinly.com/sach/lap-ke-hoach-van-may/attachment/lap-ke-hoach-cho-may-man/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:32:\"lập kế hoạch cho may mắn\";}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:7:\"caption\";a:1:{s:8:\"rendered\";s:0:\"\";}s:8:\"alt_text\";s:0:\"\";s:10:\"media_type\";s:5:\"image\";s:9:\"mime_type\";s:9:\"image/png\";s:13:\"media_details\";a:6:{s:5:\"width\";i:800;s:6:\"height\";i:450;s:4:\"file\";s:36:\"2025/05/lap-ke-hoach-cho-may-man.png\";s:8:\"filesize\";i:285463;s:5:\"sizes\";a:11:{s:21:\"woocommerce_thumbnail\";a:6:{s:4:\"file\";s:36:\"lap-ke-hoach-cho-may-man-450x450.png\";s:5:\"width\";i:450;s:6:\"height\";i:450;s:8:\"filesize\";i:173173;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:89:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/lap-ke-hoach-cho-may-man-450x450.png\";}s:29:\"woocommerce_gallery_thumbnail\";a:6:{s:4:\"file\";s:36:\"lap-ke-hoach-cho-may-man-100x100.png\";s:5:\"width\";i:100;s:6:\"height\";i:100;s:8:\"filesize\";i:21103;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:89:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/lap-ke-hoach-cho-may-man-100x100.png\";}s:18:\"woocommerce_single\";a:6:{s:4:\"file\";s:36:\"lap-ke-hoach-cho-may-man-600x338.png\";s:5:\"width\";i:600;s:6:\"height\";i:338;s:8:\"filesize\";i:427393;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:89:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/lap-ke-hoach-cho-may-man-600x338.png\";}s:6:\"medium\";a:6:{s:4:\"file\";s:36:\"lap-ke-hoach-cho-may-man-300x169.png\";s:5:\"width\";i:300;s:6:\"height\";i:169;s:8:\"filesize\";i:123431;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:89:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/lap-ke-hoach-cho-may-man-300x169.png\";}s:9:\"thumbnail\";a:6:{s:4:\"file\";s:36:\"lap-ke-hoach-cho-may-man-150x150.png\";s:5:\"width\";i:150;s:6:\"height\";i:150;s:8:\"filesize\";i:54662;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:89:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/lap-ke-hoach-cho-may-man-150x150.png\";}s:12:\"medium_large\";a:6:{s:4:\"file\";s:36:\"lap-ke-hoach-cho-may-man-768x432.png\";s:5:\"width\";i:768;s:6:\"height\";i:432;s:8:\"filesize\";i:803930;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:89:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/lap-ke-hoach-cho-may-man-768x432.png\";}s:14:\"mvp-port-thumb\";a:6:{s:4:\"file\";s:36:\"lap-ke-hoach-cho-may-man-560x450.png\";s:5:\"width\";i:560;s:6:\"height\";i:450;s:8:\"filesize\";i:665248;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:89:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/lap-ke-hoach-cho-may-man-560x450.png\";}s:15:\"mvp-large-thumb\";a:6:{s:4:\"file\";s:36:\"lap-ke-hoach-cho-may-man-590x354.png\";s:5:\"width\";i: