INSERT INTO `cache` VALUES ('kenfinly-cache-wordpress:posts:list:7f568dc69ff3a3da7b156631e4847fa1','a:3:{s:7:\"success\";b:1;s:4:\"data\";a:9:{i:0;a:26:{s:2:\"id\";i:5244;s:4:\"date\";s:19:\"2025-06-19T17:03:13\";s:8:\"date_gmt\";s:19:\"2025-06-19T10:03:13\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=5244\";}s:8:\"modified\";s:19:\"2025-06-19T21:41:41\";s:12:\"modified_gmt\";s:19:\"2025-06-19T14:41:41\";s:4:\"slug\";s:43:\"geoffrey-hinton-va-canh-bao-ve-tuong-lai-ai\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:79:\"https://blog.kenfinly.com/goc-nhin/geoffrey-hinton-va-canh-bao-ve-tuong-lai-ai/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:83:\"Geoffrey Hinton: Cha Đỡ Đầu Của AI Và Những Cảnh Báo Về Tương Lai\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:6016:\"\n<p>Geoffrey Hinton, được mệnh danh là cha đỡ đầu của trí tuệ nhân tạo, đã rời Google để có thể tự do cảnh báo về những rủi ro tiềm ẩn của AI. Ông ước tính có 10-20% khả năng AI sẽ xoá sổ nhân loại, và lo ngại về việc AI trở nên thông minh hơn con người, vũ khí tự động, và tác động đến việc làm.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Giới thiệu</h2>\n\n\n\n<p>Geoffrey Hinton được mệnh danh là cha đỡ đầu của trí tuệ nhân tạo nhờ những đóng góp quan trọng trong lĩnh vực mạng nơ-ron nhân tạo. </p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"704\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/06/kipm-geoffrey-hinton-1024x704.jpg\" alt=\"Geoffrey Hinton #KIPM\" class=\"wp-image-5245\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/06/kipm-geoffrey-hinton-1024x704.jpg 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/06/kipm-geoffrey-hinton-600x413.jpg 600w, https://blog.kenfinly.com/wp-content/uploads/2025/06/kipm-geoffrey-hinton-300x206.jpg 300w, https://blog.kenfinly.com/wp-content/uploads/2025/06/kipm-geoffrey-hinton-768x528.jpg 768w, https://blog.kenfinly.com/wp-content/uploads/2025/06/kipm-geoffrey-hinton.jpg 1309w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /><figcaption class=\"wp-element-caption\"><strong>Geoffrey Hinton.</strong> technologyreview.com</figcaption></figure>\n\n\n\n<p>Với hơn 50 năm nghiên cứu, ông đã đặt nền móng cho sự phát triển của công nghệ học sâu <a href=\"https://en.wikipedia.org/wiki/Deep_learning\">(DEEP LEARNING)</a> &#8211; nền tảng của các hệ thống AI hiện đại. Sau 10 năm làm việc tại Google, Hinton đã quyết định rời đi để tự do cảnh báo về những rủi ro tiềm ẩn của AI. Ông lo ngại rằng trí tuệ nhân tạo có thể trở nên thông minh hơn con người, và ước tính có khoảng 10-20% khả năng AI sẽ xoá sổ nhân loại. </p>\n\n\n\n<p>Những cảnh báo của ông không chỉ giới hạn ở viễn cảnh xa xôi, mà còn bao gồm cả những vấn đề đang diễn ra, như tác động của thuật toán mạng xã hội, vũ khí tự động, và các cuộc tấn công mạng ngày càng tinh vi.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Geo</strong>ffrey Hinton: Nhà Tiên Phong Trong Lĩnh Vực Trí Tuệ Nhân tạo</h2>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"Godfather of AI: I Tried to Warn Them, But We’ve Already Lost Control! Geoffrey Hinton\" width=\"500\" height=\"281\" src=\"https://www.youtube.com/embed/giT0ytynSqg?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\n</div><figcaption class=\"wp-element-caption\">Video gốc của kênh The Diary Of A CEO </figcaption></figure>\n\n\n\n<p><a href=\"https://www.youtube.com/@TheDiaryOfACEO\"><br></a>Video này thuộc về kênh https://www.youtube.com/@TheDiaryOfACEO.</p>\n\n\n\n<p>Bạn có thể xem bản có phụ đề tiếng Việt tại đường link này: <a href=\"https://www.facebook.com/share/v/1Mz6sHwkKb/\">https://www.facebook.com/share/v/1Mz6sHwkKb/</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Trí Tuệ Nhân Tạo Và Tương Lai Của Việc Làm</h2>\n\n\n\n<p>Khi được hỏi về triển vọng nghề nghiệp trong một thế giới siêu thực, Geoffrey Hinton đã đưa ra một câu trả lời đơn giản nhưng đáng suy ngẫm: &#8220;Học sửa ống nước.&#8221;</p>\n\n\n\n<p>AI đang phát triển với tốc độ chóng mặt. Khiến các chuyên gia như Geoffrey Hinton lo ngại về tương lai việc làm. Ông so sánh khoảng cách về trí thông minh giữa con người và AI trong tương lai sẽ giống như khoảng cách giữa con người và thú cưng. &#8220;Tôi đã nghĩ về con chó của mình, Pablo, chú chó Bulldog Pháp khi tôi rời khỏi nhà. Nó không biết tôi sẽ đi đâu&#8230; Và khoảng cách về trí thông minh sẽ như vậy đấy.&#8221;</p>\n\n\n\n<p>Hinton cũng nhấn mạnh tầm quan trọng của việc quản lý và kiểm soát trí tuệ nhân tạo. &#8220;Điều bạn cần làm là chỉ nên giới hạn các công ty lớn để họ kiếm lợi nhuận thì phải làm những việc có ích cho xã hội.&#8221;</p>\n\n\n\n<h2 class=\"wp-block-heading\">Kết luận</h2>\n\n\n\n<p>Geoffrey Hinton, với tư cách là cha đỡ đầu của AI, đã đóng góp to lớn cho sự phát triển của công nghệ này. Nhưng ông cũng là người cảnh báo mạnh mẽ, về những rủi ro tiềm ẩn của nó.</p>\n\n\n\n<p>Những lo ngại về việc AI có thể trở nên thông minh hơn con người, về vũ khí tự động, về tác động của thuật toán mạng xã hội, và về các cuộc tấn công mạng ngày càng tinh vi đều là những vấn đề cần được xem xét nghiêm túc.</p>\n\n\n\n<p>Trong bối cảnh trí tuệ nhân tạo đang phát triển nhanh chóng, việc cân nhắc giữa lợi ích và rủi ro, giữa tiến bộ công nghệ và an toàn xã hội trở nên cấp thiết hơn bao giờ hết. Như Hinton đã nhấn mạnh, chúng ta cần những quy định mạnh mẽ để đảm bảo rằng AI được phát triển và sử dụng một cách có trách nhiệm, vì lợi ích của toàn xã hội. Chỉ khi đó, chúng ta mới có thể tận dụng được tiềm năng to lớn của trí tuệ nhân tạo mà không phải đối mặt với những hậu quả không lường trước được.</p>\n\n\n\n<p>Dieter R. (K.I.P.M)</p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:330:\"<p>Geoffrey Hinton, được mệnh danh là cha đỡ đầu của trí tuệ nhân tạo, đã rời Google để có thể tự do cảnh báo về những rủi ro tiềm ẩn của AI. Ông ước tính có 10-20% khả năng AI sẽ xoá sổ nhân loại, và lo ngại về việc AI trở nên thông minh [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:5239;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:164;}s:4:\"tags\";a:5:{i:0;i:823;i:1;i:474;i:2;i:435;i:3;i:824;i:4;i:65;}s:10:\"class_list\";a:13:{i:0;s:9:\"post-5244\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:18:\"has-post-thumbnail\";i:6;s:6:\"hentry\";i:7;s:17:\"category-goc-nhin\";i:8;s:32:\"tag-dong-gop-cua-geoffrey-hinton\";i:9;s:19:\"tag-geoffrey-hinton\";i:10;s:11:\"tag-hoc-sau\";i:11;s:17:\"tag-nghien-cuu-ai\";i:12;s:20:\"tag-tri-tue-nhan-tao\";}s:6:\"_links\";a:11:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/5244\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=5244\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:2;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/5244/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:5247;s:4:\"hre