.\";s:4:\"link\";s:40:\"https://blog.kenfinly.com/author/dieter/\";s:4:\"slug\";s:6:\"dieter\";s:11:\"avatar_urls\";a:3:{i:24;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24&d=mm&r=g\";i:48;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=48&d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:15:{s:2:\"id\";i:5199;s:4:\"date\";s:19:\"2025-06-13T12:31:11\";s:4:\"slug\";s:27:\"kipm-phat-trien-lanh-dao-v2\";s:4:\"type\";s:10:\"attachment\";s:4:\"link\";s:108:\"https://blog.kenfinly.com/sach/hay-kien-dinh-tro-thanh-nguoi-dan-dau/attachment/kipm-phat-trien-lanh-dao-v2/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:27:\"kipm-phat-trien-lanh-dao-V2\";}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:7:\"caption\";a:1:{s:8:\"rendered\";s:0:\"\";}s:8:\"alt_text\";s:0:\"\";s:10:\"media_type\";s:5:\"image\";s:9:\"mime_type\";s:10:\"image/jpeg\";s:13:\"media_details\";a:6:{s:5:\"width\";i:1472;s:6:\"height\";i:832;s:4:\"file\";s:39:\"2025/06/kipm-phat-trien-lanh-dao-V2.jpg\";s:8:\"filesize\";i:86006;s:5:\"sizes\";a:14:{s:21:\"woocommerce_thumbnail\";a:6:{s:4:\"file\";s:39:\"kipm-phat-trien-lanh-dao-V2-450x450.jpg\";s:5:\"width\";i:450;s:6:\"height\";i:450;s:8:\"filesize\";i:28635;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:92:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/kipm-phat-trien-lanh-dao-V2-450x450.jpg\";}s:29:\"woocommerce_gallery_thumbnail\";a:6:{s:4:\"file\";s:39:\"kipm-phat-trien-lanh-dao-V2-100x100.jpg\";s:5:\"width