:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:44:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=732\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}}}}i:2;a:26:{s:2:\"id\";i:4738;s:4:\"date\";s:19:\"2025-05-12T10:56:57\";s:8:\"date_gmt\";s:19:\"2025-05-12T03:56:57\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=4738\";}s:8:\"modified\";s:19:\"2025-05-12T11:10:17\";s:12:\"modified_gmt\";s:19:\"2025-05-12T04:10:17\";s:4:\"slug\";s:37:\"cuoc-cach-mang-tim-kiem-perplexity-ai\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:69:\"https://blog.kenfinly.com/sach/cuoc-cach-mang-tim-kiem-perplexity-ai/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:103:\"Cuộc Cách Mạng Tìm Kiếm: Perplexity AI và Sự Thay Đổi Quyền Lực trong Thế Giới AI\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:2370:\"\n<p>Hồi 3: Hóa Đơn</p>\n\n\n\n<p>Chương 10: KÍCH THƯỚC QUAN TRỌNG</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"970\" height=\"647\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-48.png\" alt=\"\" class=\"wp-image-4747\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-48.png 970w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-48-600x400.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-48-300x200.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-48-768x512.png 768w\" sizes=\"auto, (max-width: 970px) 100vw, 970px\" /><figcaption class=\"wp-element-caption\"><strong>Aravind Srinivas, CEO Perplexity AI.</strong> observer.com</figcaption></figure>\n\n\n\n<p>Trong thế giới công nghệ luôn biến đổi, một cuộc cách mạng âm thầm đang diễn ra, thách thức sự thống trị lâu đời của các gã khổng lồ tìm kiếm. Câu chuyện này bắt đầu từ một ý tưởng đơn giản nhưng đầy tham vọng: tạo ra một công cụ tìm kiếm thông minh hơn, hiểu người dùng hơn. Đó chính là <a href=\"https://www.perplexity.ai/\"><strong>Perplexity AI</strong></a>, một startup đã làm rung chuyển cả ngành công nghiệp chỉ trong vòng vài năm ngắn ngủi.</p>\n\n\n<p>[videojs_video url=&#8221;https://blog.kenfinly.com/wp-content/uploads/2025/05/758483221-Chapter-11-Of-18.mp4&#8243;]</p>\n\n\n\n<p>Hãy quay ngược thời gian về năm 2021, khi <a href=\"https://en.wikipedia.org/wiki/Aravind_Srinivas\"><strong>Aravind Srinivas</strong></a>, một nhà nghiên cứu AI đầy tài năng, quyết định thành lập <strong><a href=\"https://www.perplexity.ai/\">Perplexity</a></strong>. Ông nhận ra rằng mặc dù Google đã thống trị thị trường tìm kiếm trong nhiều thập kỷ, nhưng vẫn còn nhiều cơ hội để cải thiện trải nghiệm người dùng. Srinivas đã tận dụng sức mạnh của các mô hình ngôn ngữ lớn (LLM) để tạo ra một công cụ tìm kiếm mới, có khả năng hiểu và trả lời các câu hỏi phức tạp một cách tự nhiên hơn.</p>\n\n\n\n<p>Phần trước: <a href=\"https://blog.kenfinly.com/sach/chuong-9-nghich-ly-goliath/\">Chương 9: Nghịch Lý Goliath</a></p>\n\n\n\n<p></p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:241:\"<p>Srinivas đã tận dụng sức mạnh của các mô hình ngôn ngữ lớn (LLM) để tạo ra một công cụ tìm kiếm mới, có khả năng hiểu và trả lời các câu hỏi phức tạp một cách tự nhiên hơn.</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:3213;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:40;}s:4:\"tags\";a:2:{i:0;i:586;i:1;i:585;}s:10:\"class_list\";a:10:{i:0;s:9:\"post-4738\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\