:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=725\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}}}}i:6;a:26:{s:2:\"id\";i:4676;s:4:\"date\";s:19:\"2025-05-09T20:54:07\";s:8:\"date_gmt\";s:19:\"2025-05-09T13:54:07\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=4676\";}s:8:\"modified\";s:19:\"2025-05-09T21:17:07\";s:12:\"modified_gmt\";s:19:\"2025-05-09T14:17:07\";s:4:\"slug\";s:53:\"tang-gia-tri-kinh-doanh-chien-luoc-phuc-vu-khach-hang\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:85:\"https://blog.kenfinly.com/sach/tang-gia-tri-kinh-doanh-chien-luoc-phuc-vu-khach-hang/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:102:\"Gia Tăng Giá Trị Kinh Doanh: Chiến Lược Lắng Nghe và Phục Vụ Khách Hàng Hiệu Quả\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:17176:\"\n<p>Khám phá những bí quyết tạo giá trị vượt trội trong kinh doanh: Làm thế nào để lắng nghe phục vụ khách hàng, cải thiện sản phẩm, và vượt qua đối thủ cạnh tranh một cách thông minh và hiệu quả.</p>\n\n\n\n<figure class=\"wp-block-audio\"><audio controls src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/Gia-Tang-Gia-Tri-Kinh-Doanh.mp3\" loop></audio><figcaption class=\"wp-element-caption\">Nghe đọc bài</figcaption></figure>\n\n\n\n<p>Phần trước: <a href=\"https://blog.kenfinly.com/sach/lam-the-nao-de-dat-duoc-su-doc-lap-tai-chinh-tu-do/\">Làm thế nào để đạt được sự độc lập tài chính và tự do trong cuộc sống</a></p>\n\n\n\n<style>\n.toc-content {\n    color: #000;\n    font-size: 24px;\n    margin-bottom: 20px;\n    display: flex;\n    align-items: center;\n}\n\n#toggleButton_4676 {\n    margin-left: 15px;\n    padding: 3px 8px;\n    background-color: #ffA500;\n    color: #fff;\n    border: none;\n    cursor: pointer;\n    border-radius: 3px;\n    text-transform: uppercase;\n    letter-spacing: 0.5px;\n    opacity: 0.8;\n    transition: opacity 0.3s ease;\n}\n\n#toggleButton_4676:hover {\n    opacity: 1;\n}\n\n#contentList_4676 {\n    display: none;\n    transition: all 0.3s ease;\n}\n\n#contentList_4676 > .toc-item {\n    color: #ffa500;\n    font-size: 16px;\n    margin-bottom: 10px;\n    line-height: 1.5;\n}\n\n#contentList_4676 .toc-subitem {\n    color: #ffA500;\n    font-size: 14px;\n    margin-left: 20px;\n    opacity: 0.8;\n}\n\n#contentList_4676 a {\n    color: #ffA500;\n}\n</style>\n\n<div class=\"toc-content\">\n    Nội dung\n    <button id=\"toggleButton_4676\">Xem</button>\n</div>\n\n<div id=\"contentList_4676\">\n    <div class=\"toc-item\"><a href=\"#create-value\">Tạo Giá Trị Trong Mọi Việc Bạn Làm</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#seven-secrets\">Bảy Bí Mật Tạo Dựng Của Cải</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#work-faster\">Làm Nhanh Hơn</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#improve-quality\">Nâng Cao Chất Lượng</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#value-creation\">Tìm Kiếm Cách Tạo Giá Trị</a></div>\n    \n    <div class=\"toc-item\"><a href=\"#references\">Tài liệu tham khảo</a></div>\n</div>\n\n<script>\nconst toggleButton_4676 = document.getElementById(\"toggleButton_4676\");\nconst contentList_4676 = document.getElementById(\"contentList_4676\");\nlet isVisible = false;\n\ntoggleButton_4676.addEventListener(\'click\', () => {\n    if (!isVisible) {\n        contentList_4676.style.display = \"block\";\n        toggleButton_4676.textContent = \"Ẩn\";\n        isVisible = true;\n    } else {\n        contentList_4676.style.display = \"none\";\n        toggleButton_4676.textContent = \"Xem\";\n        isVisible = false;\n    }\n});\n</script>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"create-value\">Tạo Giá Trị Trong Mọi Việc Bạn Làm</h2>\n\n\n\n<p>Nguyên tắc tạo giá trị là một chìa khóa quan trọng để bạn đạt được thành công tài chính. Nó khẳng định rằng: Tất cả của cải đều phát sinh từ việc gia tăng giá trị theo một cách nào đó.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-32-1024x683.png\" alt=\"\" class=\"wp-image-4679\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-32-1024x683.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-32-600x400.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-32-300x200.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-32-768x512.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-32-1536x1024.png 1536w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-32.png 1600w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></figure>\n\n\n\n<p>Khả năng của bạn trong việc tạo và bổ sung giá trị cho công việc, công ty và khách hàng là chìa khóa để có thu nhập cao và thăng tiến nhanh chóng. Càng nhiều giá trị bạn tạo ra, bạn càng trở nên có giá trị hơn. Khả năng tiếp thu kiến thức, ý tưởng, nhận thức và kỹ năng then chốt, sau đó áp dụng những kỹ năng đó một cách kịp thời để cải thiện cuộc sống hoặc công việc của người khác, cuối cùng sẽ quyết định những phần thưởng tài chính mà bạn sẽ nhận được.</p>\n\n\n\n<p>Nói cách khác, bạn phải luôn tìm kiếm những cách để gia tăng giá trị đóng góp của mình cho thế giới xung quanh. Lợi ích khách hàng, giá trị khách hàng, và việc không ngừng tìm kiếm cách cải thiện cuộc sống của người khác là những nguồn gốc thực sự của giá trị và sự tạo lập của cải bền vững.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"seven-secrets\">Bảy Bí Mật Tạo Dựng Của Cải</h2>\n\n\n\n<p>Có bảy cách xuất sắc để gia tăng giá trị của bạn trong công việc và trong thế giới của bạn. Bất kỳ một trong những ý tưởng này đều có thể tự nó đủ để bạn trở nên thành công về mặt tài chính. Khi bạn kết hợp tất cả những ý tưởng này lại với nhau, bạn sẽ bắt đầu kiếm được nhiều tiền hơn và tiến bước nhanh chóng hơn so với những gì bạn từng nghĩ là có thể.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"Unlocking Value: The Roadmap to Success in Business and Career\" width=\"500\" height=\"281\" src=\"https://www.youtube.com/embed/rLH-dSDwSIM?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\n</div></figure>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"work-faster\">Làm Nhanh Hơn</h2>\n\n\n\n<p>Cách đầu tiên để gia tăng giá trị của bạn là làm mọi thứ nhanh hơn. Tăng tốc độ mà bạn mang đến kết quả cụ thể mà người khác mong muốn. Ngày nay, mọi người đều thiếu kiên nhẫn. Khách hàng không chỉ muốn sản phẩm ngay lập tức mà còn mong muốn được phục vụ trước cả khi nhu cầu được hình thành. Do đó, dường như có mối tương quan trực tiếp giữa tốc độ phục vụ khách hàng và nhận thức của họ về giá trị sản phẩm hay dịch vụ của bạn. Khi bạn làm việc gì đó nhanh chóng, bạn được coi là năng lực hơn so với người làm việc chậm chạp. Sản phẩm của bạn cũng được cho là có chất lượng cao hơn. Tốc độ mang lại cho bạn lợi thế so với đối thủ cạnh tranh trong hầu hết mọi lĩnh vực.</p>\n\n\n\n<p>Mọi đổi mới trong kinh doanh và ngành công nghiệp ngày nay đều nhằm giảm thời gian để đạt được một kết quả cụ thể. Chúng nhắm đến việc tăng tốc độ thỏa mãn khách hàng với những gì họ muốn. Mọi tiến bộ công nghệ đều nhằm đẩy nhanh quá trình và hoàn thành công việc nhanh hơn. Hầu hết các khái niệm quản lý phổ biến được áp dụng ngày nay đều liên quan đến tốc độ và giảm thời gian. Các thực hành như tái kỹ thuật, cơ cấu lại, tổ chức lại và tái tạo đều là những cách để hợp lý hóa quá trình tạo ra và cung cấp giá trị nhanh hơn so với đối thủ cạnh tranh.</p>\n\n\n\n<p>Ngày càng nhiều sự cạnh tranh kinh doanh nhằm vượt qua các công ty khác trong việc tìm ra cách phục vụ khách hàng nhanh hơn. Mỗi kỷ lục về tốc độ phục vụ trở thành thước đo mới mà các đối thủ phải vượt qua để giữ chân khách hàng. Tất cả những gì bạn cần là một ý tưởng phục vụ khách hàng nhanh hơn 10% so với đối thủ cạnh tranh và bạn có thể trên con đường đạt được sự độc lập tài chính. Tom Monaghan đã khởi nghiệp Domino&#8217;s Pizza với ý tưởng đơn giản là giao pizza nhanh hơn bất kỳ ai khác. Ông đã nghỉ hưu gần đây với khối tài sản cá nhân trị giá 1,8 tỷ đô la. Bạn nên suy nghĩ hàng ngày về cách bạn có thể đẩy nhanh quá trình phục vụ khách hàng. Tốc độ là nguồn giá trị thực sự mà mọi người sẽ sẵn lòng chi trả.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"improve-quality\">Nâng Cao Chất Lượng</h2>\n\n\n\n<p>Cách thứ hai để bạn có thể gia tăng giá trị và tạo dựng của cải là cung cấp chất lượng tốt hơn so với đối thủ cạnh tranh với mức giá như nhau. Để cải thiện chất lượng, bạn phải trước hết tìm hiểu khách hàng định nghĩa chất lượng như thế nào, và sau đó tìm cách làm hài lòng khách hàng trong lĩnh vực đó mà không làm tăng chi phí.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-31-1024x683.png\" alt=\"Biểu tượng năm ngôi sao đầy màu sắc, thể hiện mức độ hài lòng tối đa của khách hàng, là minh chứng cho dịch vụ chăm sóc khách hàng xuất sắc và chuyên nghiệp.\" class=\"wp-image-4678\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-31-1024x683.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-31-600x400.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-31-300x200.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-31-768x512.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-31-1536x1024.png 1536w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-31.png 1600w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></figure>\n\n\n\n<p>Nhiều công ty thực sự không biết chắc chắn khách hàng của họ định nghĩa chất lượng như thế nào. Thực tế là chất lượng là bất cứ điều gì mà khách hàng nói đến. Quản lý chất lượng toàn diện có thể được định nghĩa tốt nhất là &#8220;Tìm ra những gì khách hàng thực sự muốn, và sau đó mang đến cho anh ấy nhanh hơn so với đối thủ cạnh tranh.&#8221;</p>\n\n\n\n<p>Chất lượng không chỉ đơn thuần có nghĩa là độ bền lớn hơn hay sự xuất sắc trong thiết kế. Chất lượng trước hết đề cập đến tính hữu dụng, đến nhu cầu cụ thể mà khách hàng có và mục đích sử dụng mà khách hàng dự định dành cho sản phẩm hay dịch vụ. Đó là lợi ích cụ thể mà khách hàng tìm kiếm, và mức độ bạn cung cấp lợi ích đó, sẽ định nghĩa chất lượng trong tâm trí khách hàng.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-30-1024x683.png\" alt=\"\" class=\"wp-image-4677\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-30-1024x683.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-30-600x400.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-30-300x200.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-30-768x512.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-30-1536x1024.png 1536w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-30.png 1600w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></figure>\n\n\n\n<p>Các cuộc phỏng vấn với hàng ngàn khách hàng cho thấy có hai phần trong bất kỳ sản phẩm hay dịch vụ nào. Thứ nhất là sản phẩm hoặc dịch vụ bản thân nó, và thứ hai là cách sản phẩm hoặc dịch vụ được cung cấp. Đây là lý do tại sao người ta có thể nói rằng McDonalds cung cấp chất lượng xuất sắc về việc thỏa mãn mong muốn của khách hàng về tốc độ, giá trị, sự sạch sẽ và giá cả. McDonalds không cố gắng cạnh tranh với các nhà hàng cao cấp. Thay vào đó, họ mang đến cho khách hàng trên toàn thế giới chính xác những gì họ muốn về thức ăn nhanh, với mức giá mà họ sẵn lòng chi trả.</p>\n\n\n\n<p>Liên tục tự hỏi bản thân, &#8220;Làm thế nào tôi có thể nâng cao chất lượng những gì mình làm, theo góc nhìn của khách hàng thực sự muốn?&#8221; Đây là một chiến lược then chốt. Lắng nghe các câu hỏi, đề xuất, và thậm chí là những phàn nàn từ khách hàng. Mời khách hàng của bạn cung cấp phản hồi thường xuyên. Hỏi họ xem có bất kỳ đề xuất nào để cải thiện sản phẩm hoặc dịch vụ của bạn. Nếu bạn mời phản hồi thường xuyên từ khách hàng, họ sẽ cho bạn biết những gì bạn có thể làm để làm hài lòng họ nhiều hơn. Những hiểu biết này có thể mang lại lợi thế cạnh tranh trong thị trường của bạn.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"value-creation\">Tìm Kiếm Cách Tạo Giá Trị</h2>\n\n\n\n<p>Chìa khóa thứ ba để trở nên giàu có là tìm kiếm những cách để gia tăng giá trị cho mọi thứ bạn làm. Nếu muốn nổi bật như một cá nhân hay một công ty, bạn phải bổ sung giá trị cho bất cứ điều gì mình đang làm để khách hàng nhận thức bạn và sản phẩm của bạn là vượt trội so với đối thủ cạnh tranh.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-33-1024x683.png\" alt=\"Bàn tay cầm viên phấn, đang viết cụm từ &quot;create value&quot; trên bảng, biểu tượng cho việc tạo giá trị thông qua dịch vụ khách hàng chuyên nghiệp và tận tâm.\" class=\"wp-image-4680\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-33-1024x683.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-33-600x400.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-33-300x200.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-33-768x512.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-33-1536x1024.png 1536w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-33.png 1600w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></figure>\n\n\n\n<p>Bạn có thể gia tăng giá trị cho một sản phẩm hay dịch vụ bằng cách cải thiện thiết kế để dễ sử dụng hơn. Bạn có thể tăng giá trị của nó bằng cách đơn giản hóa phương thức vận hành. Apple Computers đã làm cả hai điều này cùng một lúc. Họ đã biến đổi ngành máy tính cá nhân bằng cách làm cho chúng dễ sử dụng ngay cả với những người không am hiểu công nghệ. Một trong những nhận xét của nhiều người dùng Apple là họ chưa từng đọc sách hướng dẫn. Các máy tính, thiết bị ngoại vi và chương trình rất dễ dàng để thiết lập và sử dụng đến mức chúng gần như tự giải thích chính mình. Thiết kế tốt hơn và sự đơn giản đã trở thành những nguồn giá trị gia tăng khổng lồ cho Apple, và cho vô số các công ty khác đã theo đuổi con đường tương tự.</p>\n\n\n\n<p>Bạn có thể làm gì để gia tăng giá trị cho những gì mình làm mỗi ngày? Những nhân viên bán hàng gia tăng giá trị bằng cách đặt những câu hỏi tốt hơn, lắng nghe một cách chú ý hơn, và bằng cách cẩn thận điều chỉnh và tùy chỉnh sản phẩm hay dịch vụ của mình sao cho chính xác với những gì khách hàng mong muốn. Kết quả là, khách hàng coi những nhân viên bán hàng này là những nguồn lực có giá trị hơn cho doanh nghiệp của họ so với những nhân viên bán hàng khác không chú ý đến chi tiết như vậy.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"references\"><strong>Tài liệu tham khảo</strong></h2>\n\n\n\n<p>Tracy, B. (2002).&nbsp;<a href=\"https://www.amazon.com/Create-Your-Own-Future-Unlimited/dp/0471251070\"><em>Create Your Own Future</em>.</a>&nbsp;New Jersey: John Wiley &amp; Sons. Chương 8: “Nguyên tắc 7 – Vấn đề Tiền bạc”.</p>\n\n\n\n<p>Bản dịch:&nbsp;Dieter R.</p>\n\n\n\n<p></p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:360:\"<p>Khám phá những bí quyết tạo giá trị vượt trội trong kinh doanh: Làm thế nào để lắng nghe phục vụ khách hàng, cải thiện sản phẩm, và vượt qua đối thủ cạnh tranh một cách thông minh và hiệu quả. Phần trước: Làm thế nào để đạt được sự độc lập tài chính và [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:4681;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:40;}s:4:\"tags\";a:2:{i:0;i:724;i:1;i:725;}s:10:\"class_list\";a:10:{i:0;s:9:\"post-4676\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:18:\"has-post-thumbnail\";i:6;s:6:\"hentry\";i:7;s:13:\"category-sach\";i:8;s:15:\"tag-brian-tracy\";i:9;s:26:\"tag-create-your-own-future\";}s:6:\"_links\";a:11:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4676\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=4676\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:3;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4676/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:4688;s:4:\"href\";s:65:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4676/revisions/4688\";}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/media/4681\";}}s:13:\"wp:attachment\";a:1:{i:0;a:1:{s:4:\"href\";s:57:\"https://blog.kenfinly.com/wp-json/wp/v2/media?parent=4676\";}}s:7:\"wp:term\";a:2:{i:0;a:3:{s:8:\"taxonomy\";s:8:\"category\";s:10:\"embeddable\";b:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/categories?post=4676\";}i:1;a:3:{s:8:\"taxonomy\";s:8:\"post_tag\";s:10:\"embeddable\";b:1;s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/tags?post=4676\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}s:9:\"_embedded\";a:3:{s:6:\"author\";a:1:{i:0;a:8:{s:2:\"id\";i:1;s:4:\"name\";s:9:\"Dieter R.\";s:3:\"url\";s:16:\"http://kenkai.vn\";s:11:\"description\";s:401:\"Xin chào, tôi là Dieter R., một cây bút đam mê tại KenkAI.vn, đang sinh sống và làm việc tại Thành phố Hồ Chí Minh sôi động. Với niềm đam mê mãnh liệt về lĩnh vực lãnh đạo, tâm lý học, trí tuệ nhân tạo, công nghệ và phát triển bản thân, tôi luôn nỗ lực mang đến những nội dung giá trị và sâu sắc cho độc giả.\";s:4:\"link\";s:40:\"https://blog.kenfinly.com/author/dieter/\";s:4:\"slug\";s:6:\"dieter\";s:11:\"avatar_urls\";a:3:{i:24;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24&d=mm&r=g\";i:48;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=48&d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:15:{s:2:\"id\";i:4681;s:4:\"date\";s:19:\"2025-05-09T20:50:19\";s:4:\"slug\";s:18:\"phuc-vu-khach-hang\";s:4:\"type\";s:10:\"attachment\";s:4:\"link\";s:115:\"https://blog.kenfinly.com/sach/tang-gia-tri-kinh-doanh-chien-luoc-phuc-vu-khach-hang/attachment/phuc-vu-khach-hang/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:24:\"phục vụ khách hàng\";}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:7:\"caption\";a:1:{s:8:\"rendered\";s:0:\"\";}s:8:\"alt_text\";s:0:\"\";s:10:\"media_type\";s:5:\"image\";s:9:\"mime_type\";s:9:\"image/png\";s:13:\"media_details\";a:6:{s:5:\"width\";i:640;s:6:\"height\";i:360;s:4:\"file\";s:30:\"2025/05/phuc-vu-khach-hang.png\";s:8:\"filesize\";i:70870;s:5:\"sizes\";a:10:{s:21:\"woocommerce_thumbnail\";a:7:{s:4:\"file\";s:30:\"phuc-vu-khach-hang-450x360.png\";s:5:\"width\";i:450;s:6:\"height\";i:360;s:8:\"filesize\";i:57746;s:9:\"uncropped\";b:0;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:83:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/phuc-vu-khach-hang-450x360.png\";}s:29:\"woocommerce_gallery_thumbnail\";a:6:{s:4:\"file\";s:30:\"phuc-vu-khach-hang-100x100.png\";s:5:\"width\";i:100;s:6:\"height\";i:100;s:8:\"filesize\";i:14075;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:83:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/phuc-vu-khach-hang-100x100.png\";}s:18:\"woocommerce_single\";a:6:{s:4:\"file\";s:30:\"phuc-vu-khach-hang-600x338.png\";s:5:\"width\";i:600;s:6:\"height\";i:338;s:8:\"filesize\";i:239856;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:83:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/phuc-vu-khach-hang-600x338.png\";}s:6:\"medium\";a:6:{s:4:\"file\";s:30:\"phuc-vu-khach-hang-300x169.png\";s:5:\"width\";i:300;s:6:\"height\";i:169;s:8:\"filesize\";i:69276;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:83:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/phuc-vu-khach-hang-300x169.png\";}s:9:\"thumbnail\";a:6:{s:4:\"file\";s:30:\"phuc-vu-khach-hang-150x150.png\";s:5:\"width\";i:150;s:6:\"height\";i:150;s:8:\"filesize\";i:32064;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s