d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:15:{s:2:\"id\";i:5128;s:4:\"date\";s:19:\"2025-06-08T18:57:18\";s:4:\"slug\";s:15:\"tu-duy-tich-cuc\";s:4:\"type\";s:10:\"attachment\";s:4:\"link\";s:115:\"https://blog.kenfinly.com/sach/tu-duy-tich-cuc-suc-manh-thay-doi-cuoc-song-tu-ben-trong/attachment/tu-duy-tich-cuc/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:19:\"TƯ DUY TÍCH CỰC\";}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:7:\"caption\";a:1:{s:8:\"rendered\";s:0:\"\";}s:8:\"alt_text\";s:0:\"\";s:10:\"media_type\";s:5:\"image\";s:9:\"mime_type\";s:9:\"image/png\";s:13:\"media_details\";a:6:{s:5:\"width\";i:800;s:6:\"height\";i:450;s:4:\"file\";s:27:\"2025/06/TU-DUY-TICH-CUC.png\";s:8:\"filesize\";i:131210;s:5:\"sizes\";a:11:{s:21:\"woocommerce_thumbnail\";a:6:{s:4:\"file\";s:27:\"TU-DUY-TICH-CUC-450x450.png\";s:5:\"width\";i:450;s:6:\"height\";i:450;s:8:\"filesize\";i:92607;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:80:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/TU-DUY-TICH-CUC-450x450.png\";}s:29:\"woocommerce_gallery_thumbnail\";a:6:{s:4:\"file\";s:27:\"TU-DUY-TICH-CUC-100x100.png\";s:5:\"width\";i:100;s:6:\"height\";i:100;s:8:\"filesize\";i:15767;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:80:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/TU-DUY-TICH-CUC-100x100.png\";}s:18:\"woocommerce_single\";a:6:{s:4:\"file\";s:27:\"TU-DUY-TICH-CUC-600x338.png\";s:5:\"width\";i:600;s:6:\"height\";i:338;s:8:\"filesize\";i:257012;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:80:\"https://blog.kenfinly.