"width\";i:768;s:6:\"height\";i:432;s:8:\"filesize\";i:60534;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:106:\"https://blog.kenfinly.com/wp-content/uploads/2025/08/phat-trien-ban-than-5-bi-quyet-thanh-cong-768x432.jpg\";}s:9:\"1536x1536\";a:6:{s:4:\"file\";s:54:\"phat-trien-ban-than-5-bi-quyet-thanh-cong-1536x864.jpg\";s:5:\"width\";i:1536;s:6:\"height\";i:864;s:8:\"filesize\";i:197682;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:107:\"https://blog.kenfinly.com/wp-content/uploads/2025/08/phat-trien-ban-than-5-bi-quyet-thanh-cong-1536x864.jpg\";}s:23:\"mailpoet_newsletter_max\";a:6:{s:4:\"file\";s:54:\"phat-trien-ban-than-5-bi-quyet-thanh-cong-1320x743.jpg\";s:5:\"width\";i:1320;s:6:\"height\";i:743;s:8:\"filesize\";i:153274;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:107:\"https://blog.kenfinly.com/wp-content/uploads/2025/08/phat-trien-ban-than-5-bi-quyet-thanh-cong-1320x743.jpg\";}s:21:\"woocommerce_thumbnail\";a:6:{s:4:\"file\";s:53:\"phat-trien-ban-than-5-bi-quyet-thanh-cong-450x450.jpg\";s:5:\"width\";i:450;s:6:\"height\";i:450;s:8:\"filesize\";i:48833;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:106:\"https://blog.kenfinly.com/wp-content/uploads/2025/08/phat-trien-ban-than-5-bi-quyet-thanh-cong-450x450.jpg\";}s:18:\"woocommerce_single\";a:6:{s:4:\"file\";s:53:\"phat-trien-ban-than-5-bi-quyet-thanh-cong-600x338.jpg\";s:5:\"width\";i:600;s:6:\"height\";i:338;s:8:\"filesize\";i:41703;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:106:\"https://blog.kenfinly.com/wp-content/uploads/2025/08/phat-trien-ban-than-5-bi-quyet-thanh-cong-600x338.jpg\";}s:29:\"woocommerce_gallery_thumbnail\";a:6:{s:4:\"file\";s:53:\"phat-trien-ban-than-5-bi-quyet-thanh-cong-100x100.jpg\";s:5:\"width\";i:100;s:6:\"height\";i:100;s:8:\"filesize\";i:7881;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:106:\"https://blog.kenfinly.com/wp-content/uploads/2025/08/phat-trien-ban-than-5-bi-quyet-thanh-cong-100x100.jpg\";}s:4:\"full\";a:5:{s:4:\"file\";s:45:\"phat-trien-ban-than-5-bi-quyet-thanh-cong.jpg\";s:5:\"width\";i:1920;s:6:\"height\";i:1080;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:98:\"https://blog.kenfinly.com/wp-content/uploads/2025/08/phat-trien-ban-than-5-bi-quyet-thanh-cong.jpg\";}}s:10:\"image_meta\";a:12:{s:8:\"aperture\";s:1:\"0\";s:6:\"credit\";s:0:\"\";s:6:\"camera\";s:0:\"\";s:7:\"caption\";s:0:\"\";s:17:\"created_timestamp\";s:1:\"0\";s:9:\"copyright\";s:0:\"\";s:12:\"focal_length\";s:1:\"0\";s:3:\"iso\";s:1:\"0\";s:13:\"shutter_speed\";s:1:\"0\";s:5:\"title\";s:0:\"\";s:11:\"orientation\";s:1:\"1\";s:8:\"keywords\";a:0:{}}}s:10:\"source_url\";s:98:\"https://blog.kenfinly.com/wp-content/uploads/2025/08/phat-trien-ban-than-5-bi-quyet-thanh-cong.jpg\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/media/5642\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/media\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:56:\"https://blog.kenfinly.com/wp-json/wp/v2/types/attachment\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=5642\";}}}}}s:7:\"wp:term\";a:2:{i:0;a:1:{i:0;a:6:{s:2:\"id\";i:4;s:4:\"link\";s:43:\"https://blog.kenfinly.com/category/ky-nang/\";s:4:\"name\";s:10:\"Kỹ năng\";s:4:\"slug\";s:7:\"ky-nang\";s:8:\"taxonomy\";s:8:\"category\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:52:\"https://blog.kenfinly.com/wp-json/wp/v2/categories/4\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/categories\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\