emplated\";b:1;}}}}i:2;a:6:{s:2:\"id\";i:928;s:4:\"link\";s:49:\"https://blog.kenfinly.com/tag/vuot-qua-chi-trich/\";s:4:\"name\";s:24:\"vượt qua chỉ trích\";s:4:\"slug\";s:18:\"vuot-qua-chi-trich\";s:8:\"taxonomy\";s:8:\"post_tag\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:48:\"https://blog.kenfinly.com/wp-json/wp/v2/tags/928\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:44:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=928\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}}}}i:5;a:26:{s:2:\"id\";i:5628;s:4:\"date\";s:19:\"2025-08-20T18:00:49\";s:8:\"date_gmt\";s:19:\"2025-08-20T11:00:49\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=5628\";}s:8:\"modified\";s:19:\"2025-08-20T18:12:09\";s:12:\"modified_gmt\";s:19:\"2025-08-20T11:12:09\";s:4:\"slug\";s:17:\"chu-nghia-khac-ky\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:49:\"https://blog.kenfinly.com/sach/chu-nghia-khac-ky/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:84:\"Chủ nghĩa Khắc kỷ: Bí quyết Làm Chủ Điều Bạn Kiểm Soát Được\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:7933:\"\n<p>Khám phá triết lý sống của chủ nghĩa Khắc kỷ &#8211; nghệ thuật tập trung vào những gì bạn kiểm soát được và chấp nhận mọi điều khác. Epictetus dạy rằng hạnh phúc thực sự đến từ việc phân biệt điều ta có thể thay đổi và điều không thể. Học cách áp dụng nguyên tắc này vào cuộc sống hàng ngày để tìm thấy bình an nội tâm và sức mạnh tinh thần. Như Marcus Aurelius đã nói: “Ai có thể ngăn cản bạn trở nên tốt đẹp và chân thành?”</p>\n\n\n\n<figure class=\"wp-block-audio\"><audio controls src=\"https://blog.kenfinly.com/wp-content/uploads/2025/08/chu-nghia-khac-ky.mp3\" loop></audio><figcaption class=\"wp-element-caption\">Nghe đọc bài</figcaption></figure>\n\n\n\n<p>#ChủNghĩaKhắcKỷ #TriếtLýSống #BìnhAnNộiTâm</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"940\" height=\"788\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/08/Read-A-Book.jpg\" alt=\"Tóm tắt sách về chủ nghĩa khắc kỷ trên nền kệ sách cổ điển với tông màu nâu ấm.\" class=\"wp-image-5629\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/08/Read-A-Book.jpg 940w, https://blog.kenfinly.com/wp-content/uploads/2025/08/Read-A-Book-300x251.jpg 300w, https://blog.kenfinly.com/wp-content/uploads/2025/08/Read-A-Book-768x644.jpg 768w, https://blog.kenfinly.com/wp-content/uploads/2025/08/Read-A-Book-600x503.jpg 600w\" sizes=\"auto, (max-width: 940px) 100vw, 940px\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Tập trung vào những gì bạn kiểm soát được: Chấp nhận bất cứ điều gì xảy ra và tận dụng nó tốt nhất</strong></h2>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p><strong>“Thế nào là được giáo dục đúng đắn? Đó chính là học cách áp dụng những quan niệm tự nhiên của chúng ta vào những điều đúng đắn theo quy luật Tự nhiên, và xa hơn nữa, là phân biệt rõ những gì nằm trong khả năng kiểm soát của chúng ta và những gì không.” – Epictetus</strong></p>\n</blockquote>\n\n\n\n<p>“Có những điều nằm trong tầm kiểm soát của chúng ta, và có những điều không.” Đây là những lời đầu tiên trong tác phẩm Enchiridion của Epictetus.&nbsp;</p>\n\n\n\n<p>Như chúng ta đã biết, Enchiridion có nghĩa là “luôn sẵn sàng trong tầm tay” – như một con dao găm – và sự phân biệt giữa những gì ta có thể kiểm soát và những gì không, là điều chúng ta nên luôn ghi nhớ, sẵn sàng giúp chúng ta đối mặt với bất cứ thử thách nào cuộc sống mang đến.</p>\n\n\n\n<p>Tư tưởng cốt lõi của Epictetus là: có những điều phụ thuộc vào chúng ta và có những điều không; chúng ta nên luôn “tận dụng tối đa những gì trong tầm kiểm soát, và chấp nhận phần còn lại khi nó đến.” Tư tưởng này là nền tảng của triết học Khắc kỷ, và tạo nên góc thứ hai trong Tam giác Hạnh phúc Khắc kỷ của chúng ta.</p>\n\n\n\n<p>Hãy tưởng tượng bạn đang cầm trong tay một con búp bê trông giống hệt bạn – gọi đó là búp bê voodoo. Tuyệt vời. Bây giờ, bạn bước đến cửa sổ, mở ra, và ném con búp bê đó ra đường. Bạn ở lại bên trong và hy vọng một ngày nắng đẹp với những điều may mắn. Bỗng nhiên, cuộc sống trở thành một cảm xúc lên xuống thất thường – mà không có tiếng nói nào từ bạn. Chó pug đánh dấu lên búp bê, người đi đường đá nó lăn lóc, và xe Prius cán qua nó. Ôi… cuộc sống thật tệ!</p>\n\n\n\n<p>Thực ra, không ai lại làm điều đó với búp bê voodoo của chính mình. Nhưng họ có thực sự không làm vậy? Chẳng phải đó chính xác là điều nhiều người đang làm khi lo lắng về những thứ ngoài tầm kiểm soát của mình sao? Đúng vậy, đó chính là nguồn gốc của đau khổ về mặt cảm xúc – lo lắng về những sự kiện bên ngoài.</p>\n\n\n\n<p>“Liệu anh Steven có thích mình không? Mình có được công việc đó không? Tại sao mình không cao hơn/gầy hơn/đẹp hơn?” Trao quyền kiểm soát cảm xúc của mình cho những điều ta không trực tiếp kiểm soát được chính là nguyên nhân gây ra đau khổ. Đây là lý do tại sao các nhà Khắc kỷ khuyên chúng ta hãy lấy lại con búp bê voodoo tưởng tượng đó vào tay mình, và để chính ta quyết định khi nào ta bị tổn thương và khi nào không. Điểm mấu chốt là, các nhà Khắc kỷ muốn chúng ta tập trung vào những gì ta kiểm soát được và để mặc những điều khác xảy ra theo cách của chúng.</p>\n\n\n\n<p>Vậy chúng ta thực sự kiểm soát được điều gì? Chỉ một vài điều – những phán đoán và hành động có ý thức của chúng ta. Chúng ta có thể quyết định ý nghĩa của các sự kiện đối với mình và cách ta muốn phản ứng với chúng. Và với hành động của mình, chúng ta có thể chọn sắp xếp chúng phù hợp với đức hạnh, như đã thảo luận ở phần trước. Tất cả những điều khác đều không nằm trong tầm kiểm soát của chúng ta – từ thời tiết đến người khác và hành động của họ, đến sức khỏe và cơ thể của ta, và thực sự là tất cả mọi thứ xảy ra xung quanh ta.</p>\n\n\n\n<p>Đúng vậy, ngay cả cơ thể chúng ta cũng không hoàn toàn nằm dưới sự kiểm soát của mình. Chắc chắn chúng ta có thể ảnh hưởng đến nó thông qua hành vi – tập tạ, chạy nước rút, ăn bông cải xanh mỗi ngày – nhưng điều này sẽ không làm cho hông ta nhỏ hơn, vai rộng hơn, mũi thẳng hơn, hay mắt xanh hơn. Có những yếu tố ảnh hưởng đến cơ thể mà ta không thể kiểm soát, như gen di truyền, môi trường sớm, hay chấn thương.</p>\n\n\n\n<p>Nguyên lý kiểm soát nhị phân của Khắc kỷ – một số điều tùy thuộc vào chúng ta, những điều khác thì không – thực chất là sự công nhận ba cấp độ ảnh hưởng chúng ta có đối với thế giới:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Ảnh hưởng cao: Sự lựa chọn trong phán đoán và hành động của chúng ta</li>\n\n\n\n<li>Ảnh hưởng một phần: Sức khỏe, tài sản, mối quan hệ, và kết quả từ hành vi của chúng ta</li>\n\n\n\n<li>Không ảnh hưởng: Thời tiết, dân tộc, và hầu hết các hoàn cảnh bên ngoài</li>\n</ul>\n\n\n\n<p>“Điều này hoàn toàn phụ thuộc vào bạn – ai có thể ngăn cản bạn trở nên tốt đẹp và chân thành?” Marcus Aurelius thường tự nhắc nhở mình về sức mạnh mà tự nhiên đã ban tặng – sức mạnh để lựa chọn hành động và kiến tạo tính cách của chính mình.</p>\n\n\n\n<p>Ông nói rằng người ta không thể ngưỡng mộ bạn vì những gì tự nhiên ban tặng, nhưng có rất nhiều phẩm chất khác để trau dồi. “Vì vậy, hãy thể hiện những đức tính hoàn toàn nằm trong quyền lực của bạn – sự chính trực, phẩm giá, chăm chỉ, tự chủ, biết đủ, tiết kiệm, tử tế, độc lập, giản dị, thận trọng, và lòng quảng đại.”</p>\n\n\n\n<p>Chúng ta chính là người duy nhất có thể ngăn cản bản thân trau dồi những phẩm chất này.</p>\n\n\n\n<p>Dieter R.</p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:368:\"<p>Khám phá triết lý sống của chủ nghĩa Khắc kỷ &#8211; nghệ thuật tập trung vào những gì bạn kiểm soát được và chấp nhận mọi điều khác. Epictetus dạy rằng hạnh phúc thực sự đến từ việc phân biệt điều ta có thể thay đổi và điều không thể. Học cách áp dụng nguyên [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:5638;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:40;}s:4:\"tags\";a:10:{i:0;i:920;i:1;i:925;i:2;i:568;i:3;i:924;i:4;i:926;i:5;i:921;i:6;i:468;i:7;i:922;i:8;i:923;i:9;i:861;}s:10:\"class_list\";a:18:{i:0;s:9:\"post-5628\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:18:\"has-post-thumbnail\";i:6;s:6:\"hentry\";i:7;s:13:\"category-sach\";i:8;s:19:\"tag-binh-an-noi-tam\";i:9;s:22:\"tag-chap-nhan-thuc-tai\";i:10;s:21:\"tag-chu-nghia-khac-ky\";i:11;s:16:\"tag-epictetus-vn\";i:12;s:21:\"tag-kiem-soat-cam-xuc\";i:13;s:19:\"tag-marcus-aurelius\";i:14;s:23:\"tag-phat-trien-ban-than\";i:15;s:20:\"tag-song-co-duc-hanh\";i:16;s:22:\"tag-tam-giac-hanh-phuc\";i:17;s:17:\"tag-triet-ly-song\";}s:6:\"_links\";a:11:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/5628\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=5628\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:4;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/5628/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:5636;s:4:\"href\";s:65:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/5628/revisions/5636\";}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/media/5638\";}}s:13:\"wp:attachment\";a:1:{i:0;a:1:{s:4:\"href\";s:57:\"https://blog.kenfinly.com/wp-json/wp/v2/media?parent=5628\";}}s:7:\"wp:term\";a:2:{i:0;a:3:{s:8:\"taxonomy\";s:8:\"category\";s:10:\"embeddable\";b:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/categories?post=5628\";}i:1;a:3:{s:8:\"taxonomy\";s:8:\"post_tag\";s:10:\"embeddable\";b:1;s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/tags?post=5628\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}s:9:\"_embedded\";a:3:{s:6:\"author\";a:1:{i:0;a:8:{s:2:\"id\";i:1;s:4:\"name\";s:9:\"Dieter R.\";s:3:\"url\";s:16:\"http://kenkai.vn\";s:11:\"description\";s:401:\"Xin chào, tôi là Dieter R., một cây bút đam mê tại KenkAI.vn, đang sinh sống và làm việc tại Thành phố Hồ Chí Minh sôi động. Với niềm đam mê mãnh liệt về lĩnh vực lãnh đạo, tâm lý học, trí tuệ nhân tạo, công nghệ và phát triển bản thân, tôi luôn nỗ lực mang đến những nội dung giá trị và sâu sắc cho độc giả.\";s:4:\"link\";s:40:\"https://blog.kenfinly.com/author/dieter/\";s:4:\"slug\";s:6:\"dieter\";s:11:\"avatar_urls\";a:3:{i:24;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24&d=mm&r=g\";i:48;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=48&d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:15:{s:2:\"id\";i:5638;s:4:\"date\";s:19:\"2025-08-20T18:11:41\";s:4:\"slug\";s:40:\"kai_stoicism_chess_strategy_philosophy-2\";s:4:\"type\";s:10:\"attachment\";s:4:\"link\";s:101:\"https://blog.kenfinly.com/sach/chu-nghia-khac-ky/attachment/kai_stoicism_chess_strategy_philosophy-2/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:40:\"KAI_Stoicism_Chess_Strategy_Philosophy-2\";}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:7:\"caption\";a:1:{s:8:\"rendered\";s:344:\"<p>Hình ảnh kết hợp giữa bức tượng của một triết gia cổ đại (đại diện của chủ nghĩa khắc kỷ) với quân cờ vua (một quân tốt trắng đối diện với quân vua đen) tạo nên một phép ẩn dụ mạnh mẽ về chiến lược, sự thông thái và đối đầu với thách thức.</p>\n\";}s:8:\"alt_text\";s:336:\"Hình ảnh kết hợp giữa bức tượng của một triết gia cổ đại (đại diện của chủ nghĩa khắc kỷ) với quân cờ vua (một quân tốt trắng đối diện với quân vua đen) tạo nên một phép ẩn dụ mạnh mẽ về chiến lược, sự thông thái và đối đầu với thách thức.\";s:10:\"media_type\";s:5:\"image\";s:9:\"mime_type\";s:10:\"image/jpeg\";s:13:\"media_details\";a:6:{s:5:\"width\";i:1920;s:6:\"height\";i:1080;s:4:\"file\";s:52:\"2025/08/KAI_Stoicism_Chess_Strategy_Philosophy-2.jpg\";s:8:\"filesize\";i:145626;s:5:\"sizes\";a:10:{s:6:\"medium\";a:6:{s:4:\"file\";s:52:\"KAI_Stoicism_Chess_Strategy_Philosophy-2-300x169.jpg\";s:5:\"width\";i:300;s:6:\"height\";i:169;s:8:\"filesize\";i:12198;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:105:\"https://blog.kenfinly.com/wp-content/uploads/2025/08/KAI_Stoicism_Chess_Strategy_Philosophy-2-300x169.jpg\";}s:5:\"large\";a:6:{s:4:\"file\";s:53:\"KAI_Stoicism_Chess_Strategy_Philosophy-2-1024x576.jpg\";s:5:\"width\";i:1024;s:6:\"height\";i:576;s:8:\"filesize\";i:55492;s:9:\"mime_type\";s:10:\"image/jpeg\";s:10:\"source_url\";s:106:\"https://blog.kenfinly.com/wp-content/uploads