.w.org/{rel}\";s:9:\"templated\";b:1;}}}}i:2;a:6:{s:2:\"id\";i:919;s:4:\"link\";s:46:\"https://blog.kenfinly.com/tag/tien-bo-deu-dan/\";s:4:\"name\";s:25:\"Tiến bộ đều đặn\";s:4:\"slug\";s:15:\"tien-bo-deu-dan\";s:8:\"taxonomy\";s:8:\"post_tag\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:48:\"https://blog.kenfinly.com/wp-json/wp/v2/tags/919\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:44:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=919\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}}}}i:7;a:26:{s:2:\"id\";i:5607;s:4:\"date\";s:19:\"2025-08-14T10:21:10\";s:8:\"date_gmt\";s:19:\"2025-08-14T03:21:10\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=5607\";}s:8:\"modified\";s:19:\"2025-08-19T09:29:24\";s:12:\"modified_gmt\";s:19:\"2025-08-19T02:29:24\";s:4:\"slug\";s:25:\"phuong-phap-ryan-petersen\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:60:\"https://blog.kenfinly.com/ky-nang/phuong-phap-ryan-petersen/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:73:\"Growth Mindset: Bài Học Phát Triển Cá Nhân Từ CEO Ryan Petersen\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:13797:\"\n<p>Khám phá growth mindset và phương pháp phát triển cá nhân từ CEO Ryan Petersen. Học hỏi nguyên tắc lãnh đạo hiệu quả để nâng cao sự nghiệp và cuộc sống của bạn.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"410\" height=\"1024\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/08/KAI_TienBoMoiNgay_RyanPetersen-410x1024.jpg\" alt=\"Infographic minh họa 5 phương pháp phát triển Growth Mindset hàng ngày theo Ryan Petersen, bao gồm duy trì thói quen, viết thường xuyên, tự đánh giá và xây dựng mối quan hệ có ý nghĩa.\" class=\"wp-image-5609\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/08/KAI_TienBoMoiNgay_RyanPetersen-410x1024.jpg 410w, https://blog.kenfinly.com/wp-content/uploads/2025/08/KAI_TienBoMoiNgay_RyanPetersen-120x300.jpg 120w, https://blog.kenfinly.com/wp-content/uploads/2025/08/KAI_TienBoMoiNgay_RyanPetersen-768x1920.jpg 768w, https://blog.kenfinly.com/wp-content/uploads/2025/08/KAI_TienBoMoiNgay_RyanPetersen-600x1500.jpg 600w, https://blog.kenfinly.com/wp-content/uploads/2025/08/KAI_TienBoMoiNgay_RyanPetersen.jpg 800w\" sizes=\"auto, (max-width: 410px) 100vw, 410px\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Giới thiệu</h2>\n\n\n\n<p>Xây dựng growth mindset là nền tảng quan trọng cho sự phát triển cá nhân và sự nghiệp lâu dài. Trong thế giới kinh doanh đầy biến động, khả năng thích nghi và phát triển liên tục không còn là lựa chọn mà đã trở thành yêu cầu bắt buộc.</p>\n\n\n\n<p>Ryan Petersen &#8211; CEO của Flexport, một công ty logistics trị giá hàng tỷ đô, là minh chứng sống động cho sức mạnh của personal growth và tư duy không ngừng học hỏi. </p>\n\n\n\n<p>Ông đã xây dựng sự nghiệp đáng nể không chỉ nhờ tầm nhìn kinh doanh sắc bén mà còn bởi cam kết mạnh mẽ với việc phát triển bản thân. Bài viết này sẽ khám phá những nguyên tắc phát triển cá nhân cốt lõi từ Ryan Petersen, cách áp dụng chúng vào môi trường làm việc của bạn, và làm thế nào để bạn có thể xây dựng con đường phát triển cá nhân hiệu quả cho chính mình.</p>\n\n\n\n<p>Nội dung của bài viết được lấy cảm hứng từ một video của The Knowledge Project, bạn có thể xem lại dưới đây.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"Ryan Petersen: Tariffs, Y Combinator, and the Future of Global Logistics | The Knowledge Project\" width=\"500\" height=\"281\" src=\"https://www.youtube.com/embed/zaNPnEZGhvA?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\n</div></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Ryan Petersen và Hành Trình Xây Dựng Flexport</h2>\n\n\n\n<p><a href=\"https://forbes.vn/tag/ryan-petersen/\">Ryan Petersen</a> là người sáng lập và CEO của <a href=\"https://www.flexport.com/\">Flexport</a> &#8211; một nền tảng công nghệ hàng đầu trong lĩnh vực vận chuyển hàng hóa quốc tế. Với tầm nhìn xây dựng một nền tảng công nghệ “asset light” (nhẹ về tài sản) cho ngành logistics, Petersen đã biến Flexport thành công ty tiên phong về công nghệ trong ngành này.</p>\n\n\n\n<p>Điều thú vị là Petersen đã phát hiện ra rằng trong logistics, chất lượng thực sự giúp tiết kiệm chi phí &#8211; một quan điểm ngược với trực giác thông thường.</p>\n\n\n\n<p>Ông giải thích: “Trong logistics, tất cả chi phí đến từ việc bạn mắc sai lầm. Ví dụ, nếu bạn khai báo hải quan với mã phân loại sai, bạn sẽ tốn hàng tuần để giải quyết vấn đề đó.”</p>\n\n\n\n<p>Hành trình của Petersen không phải lúc nào cũng suôn sẻ. Ông từng phải đối mặt với quyết định khó khăn khi từ chức CEO, chỉ để sau đó quay trở lại khi công ty gặp khủng hoảng. Trải nghiệm này đã dạy cho ông những bài học quý giá về leadership development và tầm quan trọng của việc <strong><a href=\"https://blog.kenfinly.com/ky-nang/chi-tiet-dung-dan/\">chú ý đến từng chi tiết</a></strong>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Nguyên Tắc Personal Growth Cốt Lõi Từ Ryan Petersen</h2>\n\n\n\n<h3 class=\"wp-block-heading\">Tò mò và Trung thực</h3>\n\n\n\n<p>Cam kết với personal growth là điều mà Ryan Petersen luôn đặt lên hàng đầu trong hành trình lãnh đạo của mình.</p>\n\n\n\n<p>Ông xây dựng văn hóa doanh nghiệp dựa trên sự tò mò không ngừng và tính trung thực tuyệt đối. Petersen tin rằng việc liên tục đặt câu hỏi và sẵn sàng thừa nhận những điều mình không biết là chìa khóa để phát triển.</p>\n\n\n\n<p>“Đây là một ngành công nghiệp gây nghiện. Nó luôn hoạt động, luôn khác biệt. Mỗi ngày đều độc đáo. Bạn thấy những gì đang xảy ra trên thế giới ở mức độ điên rồ,” Petersen chia sẻ, thể hiện niềm đam mê học hỏi không ngừng của mình.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Chủ động và Có Mục Đích</h3>\n\n\n\n<p>Quá trình self-growth đòi hỏi sự kiên nhẫn và cam kết lâu dài với việc học hỏi liên tục. Petersen không chỉ nói về điều này mà còn thực hành nó hàng ngày. Ông tập trung vào hành động có chủ đích và tạo giá trị thực tế, luôn đặt câu hỏi: “Làm thế nào để improve myself mỗi ngày?”</p>\n\n\n\n<p>Thay vì chỉ phản ứng với các vấn đề, Petersen chủ động tìm kiếm cơ hội cải thiện và đổi mới. Ông tin rằng mỗi thách thức đều là cơ hội để học hỏi và phát triển, một nguyên tắc cốt lõi của growth mindset.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Phát triển Đội ngũ</h3>\n\n\n\n<p>Ryan Petersen đã xây dựng văn hóa doanh nghiệp khuyến khích self-growth cho mọi nhân viên.</p>\n\n\n\n<p>Ông hiểu rằng sự phát triển cá nhân của mình gắn liền với sự phát triển của đội ngũ. Thông qua chương trình “Learning Leader Team of Coaches”, Petersen đầu tư vào việc phát triển kỹ năng và tiềm năng của nhân viên.</p>\n\n\n\n<p>“Khi bạn cam kết improve myself, bạn đang đầu tư vào tài sản quý giá nhất của mình,” Petersen thường nhắc nhở đội ngũ của mình.</p>\n\n\n\n<p>Ông tin rằng văn hóa học hỏi liên tục không chỉ mang lại lợi ích cho cá nhân mà còn tạo ra một tổ chức mạnh mẽ và linh hoạt hơn.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Tạo Giá trị</h3>\n\n\n\n<p>Các nhà lãnh đạo thành công đều hiểu rằng personal growth không phải là đích đến mà là một hành trình liên tục. Petersen áp dụng triết lý này vào việc tạo giá trị cho khách hàng. </p>\n\n\n\n<p>Ông cam kết mang lại giá trị gấp 10 lần cho khách hàng, một mục tiêu đầy tham vọng đòi hỏi sự đổi mới và cải tiến không ngừng.</p>\n\n\n\n<p>Trong môi trường kinh doanh cạnh tranh, growth mindset giúp nhà lãnh đạo liên tục đổi mới và thích nghi. Petersen hiểu rằng để <strong>tạo ra giá trị vượt trội</strong>, ông và đội ngũ của mình phải <strong>liên tục học hỏi, thử nghiệm và cải tiến</strong>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Phương Pháp Self-Development Hiệu Quả Trong Kinh Doanh</h2>\n\n\n\n<h3 class=\"wp-block-heading\">Front Line Obsession</h3>\n\n\n\n<p>Một trong những phương pháp self-development độc đáo của Petersen là “Front Line Obsession” &#8211; sự tập trung mạnh mẽ vào tuyến đầu.</p>\n\n\n\n<p>Phương pháp này dựa trên nguyên tắc “Gemba walks” của Nhật Bản, tập trung vào:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Quan sát trực tiếp quy trình làm việc</li>\n\n\n\n<li>Tương tác với nhân viên tuyến đầu</li>\n\n\n\n<li>Xác định cơ hội cải thiện</li>\n\n\n\n<li>Trao quyền cho nhân viên đóng góp vào thành công của công ty</li>\n</ul>\n\n\n\n<p>Thói quen self-development hàng ngày đã giúp Ryan Petersen duy trì sự sáng tạo và năng lượng tích cực. Ông thường xuyên dành thời gian tại các kho hàng, cảng biển và trung tâm phân phối để hiểu rõ hơn về hoạt động thực tế của công ty.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Thực Hành Viết Thường Xuyên</h3>\n\n\n\n<p>Thói quen viết lách hàng ngày là một trong những cách hiệu quả để improve myself theo phương pháp của Ryan Petersen.</p>\n\n\n\n<p>Ông dành thời gian mỗi ngày để viết, sắp xếp suy nghĩ và phát triển ý tưởng mới. Việc này không chỉ giúp ông làm rõ tư duy mà còn là công cụ để phản ánh và học hỏi từ trải nghiệm.</p>\n\n\n\n<p>Đầu tư vào self-development là cách hiệu quả nhất để nâng cao giá trị bản thân trong thị trường lao động cạnh tranh.</p>\n\n\n\n<p>Petersen khuyến khích đội ngũ của mình áp dụng thói quen viết lách như một phương tiện để phát triển tư duy phản biện và khả năng giải quyết vấn đề.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Áp Dụng Self-Growth Trong Môi Trường Làm Việc Việt Nam</h2>\n\n\n\n<p>Tại Việt Nam, ngày càng nhiều doanh nghiệp đang chú trọng vào personal growth cho đội ngũ nhân viên.</p>\n\n\n\n<p>Các chương trình như <a href=\"https://www.facebook.com/watch/?v=2018027748965154\">HR Growth Path 2025</a> đang được triển khai với các mô-đun như <a href=\"https://www.facebook.com/groups/hrdigest/posts/1048931346995915/\">People Advocacy</a> và Execution Excellence, tập trung vào:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Xây dựng văn hóa hiệu suất bền vững</li>\n\n\n\n<li>Cân bằng lợi ích tổ chức và nhân viên</li>\n\n\n\n<li>Đo lường văn hóa bằng dữ liệu</li>\n\n\n\n<li>Giải quyết vấn đề có hệ thống</li>\n\n\n\n<li>Sử dụng công cụ phân tích như 5 Whys</li>\n\n\n\n<li>Đảm bảo giải pháp bền vững</li>\n</ul>\n\n\n\n<p>Áp dụng các nguyên tắc self-growth có thể giúp bạn vượt qua giới hạn của bản thân.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Tầm Quan Trọng Của Mindfulness In Workplace Đối Với Nhà Lãnh Đạo</h2>\n\n\n\n<p>Xu hướng mindfulness (chánh niệm) đang ngày càng phổ biến trong môi trường công sở. Các lợi ích chính của mindfulness bao gồm:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Giảm stress và cải thiện sức khỏe tinh thần</li>\n\n\n\n<li>Tăng cường mối quan hệ đồng nghiệp</li>\n\n\n\n<li>Cải thiện hiệu suất công việc</li>\n\n\n\n<li>Xây dựng văn hóa công ty tích cực</li>\n</ul>\n\n\n\n<p>Ryan Petersen, dù không trực tiếp đề cập đến mindfulness, đã thực hành nhiều nguyên tắc tương tự thông qua việc <strong>tập trung vào hiện tại</strong>, quan sát kỹ lưỡng và lắng nghe tích cực.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Kết luận</h2>\n\n\n\n<p>Growth mindset không chỉ là một khái niệm trừu tượng mà là một phương pháp sống và làm việc đã được chứng minh hiệu quả qua hành trình của Ryan Petersen.</p>\n\n\n\n<p>Từ việc xây dựng Flexport thành công ty logistics hàng tỷ đô đến việc vượt qua những thách thức cá nhân, Petersen đã minh chứng rằng cam kết với personal growth là nền tảng của thành công bền vững.</p>\n\n\n\n<h2 class=\"wp-block-heading\" id=\"1c762c13-57e5-4c1c-8cf6-fb07d1ec332b\">5 Điểm Cần Nhớ</h2>\n\n\n\n<ol class=\"wp-block-list\">\n<li><strong>Xây dựng growth mindset</strong> là nền tảng cho sự phát triển cá nhân và thành công trong kinh doanh.</li>\n\n\n\n<li><strong>Tò mò và trung thực</strong> là hai giá trị cốt lõi giúp duy trì quá trình học hỏi liên tục.</li>\n\n\n\n<li><strong>Front Line Obsession</strong> &#8211; tập trung vào tuyến đầu giúp hiểu rõ thực tế và phát hiện cơ hội cải thiện.</li>\n\n\n\n<li><strong>Thói quen viết lách hàng ngày</strong> là công cụ hiệu quả để phát triển tư duy và sáng tạo.</li>\n\n\n\n<li><strong>Personal growth là hành trình không điểm dừng</strong> &#8211; cần kiên trì và cam kết lâu dài.</li>\n</ol>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"Flexport Logistics: Bí Quyết Cách Mạng Hóa Chuỗi Cung Ứng Toàn Cầu #kiptuduy #baihockinhdoanh\" width=\"500\" height=\"281\" src=\"https://www.youtube.com/embed/SH9Qp6RgmZk?start=2358&#038;feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\n</div></figure>\n\n\n\n<p>Bài viết liên quan: <a href=\"https://blog.kenfinly.com/ky-nang/suc-manh-truc-giac/\">Sức mạnh của trực giác.</a></p>\n\n\n\n<p>Dieter R.</p>\n\n\n\n<p></p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:358:\"<p>Khám phá growth mindset và phương pháp phát triển cá nhân từ CEO Ryan Petersen. Học hỏi nguyên tắc lãnh đạo hiệu quả để nâng cao sự nghiệp và cuộc sống của bạn. Giới thiệu Xây dựng growth mindset là nền tảng quan trọng cho sự phát triển cá nhân và sự nghiệp lâu dài. [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:5610;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:4;}s:4:\"tags\";a:3:{i:0;i:911;i:1;i:912;i:2;i:913;}s:10:\"class_list\";a:11:{i:0;s:9:\"post-5607\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:18:\"has-post-thumbnail\";i:6;s:6:\"hentry\";i:7;s:16:\"category-ky-nang\";i:8;s:18:\"tag-growth-mindset\";i:9;s:19:\"tag-personal-growth\";i:10;s:20:\"tag-self-development\";}s:6:\"_links\";a:11:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/5607\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=5607\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:4;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/5607/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:5627;s:4:\"href\";s:65:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/5607/revisions/5627\";}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/media/5610\";}}s:13:\"wp:attachment\";a:1:{i:0;a:1:{s:4:\"href\";s:57:\"https://blog.kenfinly.com/wp-json/wp/v2/media?parent=5607\";}}s:7:\"wp:term\";a:2:{i:0;a:3:{s:8:\"taxonomy\";s:8:\"category\";s:10:\"embeddable\";b:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/categories?post=5607\";}i:1;a:3:{s:8:\"taxonomy\";s:8:\"post_tag\";s:1