mb\";a:6:{s:4:\"file\";s:21:\"long-tham-1-80x80.png\";s:5:\"width\";i:80;s:6:\"height\";i:80;s:8:\"filesize\";i:14586;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:74:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/long-tham-1-80x80.png\";}s:4:\"full\";a:5:{s:4:\"file\";s:15:\"long-tham-1.png\";s:5:\"width\";i:640;s:6:\"height\";i:360;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:68:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/long-tham-1.png\";}}s:10:\"image_meta\";a:12:{s:8:\"aperture\";s:1:\"0\";s:6:\"credit\";s:0:\"\";s:6:\"camera\";s:0:\"\";s:7:\"caption\";s:0:\"\";s:17:\"created_timestamp\";s:1:\"0\";s:9:\"copyright\";s:0:\"\";s:12:\"focal_length\";s:1:\"0\";s:3:\"iso\";s:1:\"0\";s:13:\"shutter_speed\";s:1:\"0\";s:5:\"title\";s:0:\"\";s:11:\"orientation\";s:1:\"0\";s:8:\"keywords\";a:0:{}}}s:10:\"source_url\";s:68:\"https://blog.kenfinly.com/wp-content/uploads/2025/05/long-tham-1.png\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/media/4956\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/media\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:56:\"https://blog.kenfinly.com/wp-json/wp/v2/types/attachment\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=4956\";}}}}}s:7:\"wp:term\";a:2:{i:0;a:1:{i:0;a:6:{s:2:\"id\";i:40;s:4:\"link\";s:40:\"https://blog.kenfinly.com/category/sach/\";s:4:\"name\";s:5:\"Sách\";s:4:\"slug\";s:4:\"sach\";s:8:\"taxonomy\";s:8:\"category\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:53:\"https://blog.kenfinly.com/wp-json/wp/v2/categories/40\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}