ly.com/wp-json/wp/v2/tags/758\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:44:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=758\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}i:4;a:6:{s:2:\"id\";i:764;s:4:\"link\";s:39:\"https://blog.kenfinly.com/tag/that-bai/\";s:4:\"name\";s:12:\"thất bại\";s:4:\"slug\";s:8:\"that-bai\";s:8:\"taxonomy\";s:8:\"post_tag\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:48:\"https://blog.kenfinly.com/wp-json/wp/v2/tags/764\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:44:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=764\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}}}}i:7;a:26:{s:2:\"id\";i:4879;s:4:\"date\";s:19:\"2025-05-20T20:13:06\";s:8:\"date_gmt\";s:19:\"2025-05-20T13:13:06\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=4879\";}s:8:\"modified\";s:19:\"2025-05-20T20:13:31\";s:12:\"modified_gmt\";s:19:\"2025-05-20T13:13:31\";s:4:\"slug\";s:24:\"con-duong-den-thanh-cong\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:56:\"https://blog.kenfinly.com/sach/con-duong-den-thanh-cong/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:109:\"Con Đường Đến Thành Công: Bài Học Từ Rockeffeler Về Ước Mơ, Thất Bại và Nghị Lực\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:12665:\"\n<p>Khám phá bí quyết thành công qua lời dạy của người Rockeffeler: &#8220;Ước mơ + Thất bại + Thử thách = Thành công&#8221;. Biến thất bại thành bậc thang, không phải bia mộ trên hành trình chinh phục.</p>\n\n\n\n<figure class=\"wp-block-audio\"><audio controls src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/chao_mung_ban_den_voi_kenkaivn_kham_pha_tin_tuc_cbdb52a1-3c08-4933-963a-e959d6c56345.mp3\"></audio></figure>\n\n\n\n<p>Ngày 19 tháng 11 năm 1899</p>\n\n\n\n<p>Thân gửi John:</p>\n\n\n\n<p>Tâm trạng của con gần đây rất buồn, điều đó khiến cha buồn. Cha thực sự cảm nhận được rằng con vẫn cảm thấy xấu hổ và nhục nhã từ khoản đầu tư đã khiến con mất một triệu đô la. Điều này khiến con cảm thấy chán nản và lo lắng suốt cả ngày. Tuy nhiên, điều này là không cần thiết, một thất bại không thể hiện điều gì cả, và sẽ không gắn nhãn bất tài lên trán con đâu.</p>\n\n\n\n<p>Hãy vui lên, con trai của ta. Con cần biết rằng không ai trên thế giới này có cuộc sống suôn sẻ; ngược lại, họ sống song song với thất bại. Có lẽ chính vì có quá nhiều thất bại bất lực trên thế giới này mà việc theo đuổi sự xuất sắc trở nên hấp dẫn; nó vẫn khiến người ta theo đuổi nó, ngay cả khi phải đánh đổi bằng cả mạng sống. Dù vậy, thất bại vẫn đến.</p>\n\n\n\n<p>Số phận của chúng ta đều giống nhau. Chỉ là không giống như một số người, cha coi thất bại như một ly rượu mạnh. Nó đắng khi uống vào, nhưng nó mang lại cho con rất nhiều sinh lực.</p>\n\n\n\n<p>Khi cha lần đầu bước chân vào thế giới kinh doanh và cầu nguyện Chúa phù hộ cho công ty mới của chúng ta, một cơn bão thảm khốc đã ập đến. Lúc đó, chúng ta đã ký hợp đồng mua một lượng lớn đậu và chuẩn bị kiếm được rất nhiều tiền, nhưng chúng ta không ngờ rằng một “chuyến thăm” bất ngờ từ sương giá sẽ đến và phá tan giấc mơ ngọt ngào của chúng ta. Một nửa số đậu chúng ta nhận được đã bị phá hủy, và một số nhà cung cấp vô lương tâm còn thêm cát, đậu nhỏ và rơm vào. Việc kinh doanh này đã được định sẵn là sẽ thất bại. Nhưng cha biết rằng cha không thể chán nản, càng không thể đắm chìm trong thất bại, nếu không, cha sẽ càng trôi xa hơn khỏi mục tiêu và ước mơ của mình.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"812\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-73-1024x812.png\" alt=\"\" class=\"wp-image-4881\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-73-1024x812.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-73-600x476.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-73-300x238.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-73-768x609.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-73.png 1034w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></figure>\n\n\n\n<p>Không có bữa trưa nào miễn phí trên thế giới này, và càng không thể duy trì nguyên trạng. Nếu con đứng yên, con sẽ tụt lùi, nhưng để tiến lên phía trước, con phải sẵn sàng đưa ra quyết định và chấp nhận rủi ro. Sau khi việc kinh doanh đó thất bại, cha lại vay tiền từ cha của cha, mặc dù cha không quá miễn cưỡng khi làm điều đó. Hơn nữa, để làm cho mình vượt trội trong việc quản lý kinh doanh, cha đã nói với đối tác của mình, ông Clark, rằng chúng ta phải quảng bá bản thân và để những khách hàng tiềm năng của chúng ta biết thông qua quảng cáo trên báo rằng chúng ta có thể cung cấp các khoản trả trước lớn và có thể cung cấp số lượng lớn sản phẩm nông nghiệp trước.</p>\n\n\n\n<p>Kết quả là, lòng can đảm và sự chăm chỉ đã cứu chúng ta. Trong năm đó, thay vì bị ảnh hưởng bởi “sự cố đậu”, chúng ta đã thu được một khoản lợi nhuận ròng đáng kể.</p>\n\n\n\n<p>Mọi người đều ghét thất bại. Tuy nhiên, một khi việc tránh thất bại trở thành động lực để con làm mọi việc, con đã bước vào con đường của sự lười biếng và bất lực. Điều này thật khủng khiếp, đặc biệt là đối với một thảm họa như vậy. Bởi vì điều này báo hiệu khả năng con người có thể mất đi những cơ hội mà họ có thể có.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"673\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-74-1024x673.png\" alt=\"\" class=\"wp-image-4882\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-74-1024x673.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-74-600x394.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-74-300x197.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-74-768x505.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-74.png 1236w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></figure>\n\n\n\n<p>Con trai, cơ hội là một thứ hiếm có. Người ta thịnh vượng và giàu có là nhờ cơ hội. Nhìn vào những người nghèo khó và con sẽ biết rằng họ không phải là người bất tài hay ngu ngốc, họ cũng không phải là người không chăm chỉ. Họ bị tước đoạt cơ hội. Con cần biết rằng chúng ta sống trong một khu rừng nơi kẻ yếu là con mồi của kẻ mạnh, nơi con hoặc là ăn thịt người khác hoặc có nguy cơ bị người khác ăn thịt. Né tránh rủi ro gần như là một sự đảm bảo cho việc phá sản; nhưng khi con tận dụng cơ hội, con đang tước đoạt cơ hội của người khác chỉ để đảm bảo cho chính mình.</p>\n\n\n\n<p>Nếu con sợ thất bại, con sẽ không dám chấp nhận rủi ro và sau đó mất đi những cơ hội được đặt ngay trước mặt con. Vì vậy, con trai của ta, để tránh mất cơ hội và giữ lại tư cách cạnh tranh của mình, việc trả giá cho những thất bại và trở ngại của chúng ta là đáng giá!</p>\n\n\n\n<p>Thất bại là khởi đầu của hành trình đến một vị trí cao hơn. Cha có thể nói rằng những gì cha đã đạt được ngày hôm nay là từ việc leo lên cái thang xoắn ốc của thất bại và sau đó vươn lên từ đó. Cha là một “kẻ thua cuộc” khôn ngoan. Cha biết học hỏi từ những thất bại, rút ra các yếu tố thành công từ kinh nghiệm thất bại của mình, và sử dụng những phương pháp sáng tạo mà cha chưa từng nghĩ đến trước đây để bắt đầu một sự nghiệp mới. Vì vậy, cha muốn nói rằng thất bại là một điều tốt miễn là nó không trở thành một thói quen.</p>\n\n\n\n<p>Phương châm của cha là: Con người luôn phải duy trì năng lượng của mình, giữ vững và kiên trì, bất kể gặp phải những thất bại và trở ngại nào, đây là điều duy nhất cha có thể làm. Bản thân cha có thể hiểu được những gì cha nên làm để khiến mình cảm thấy hạnh phúc, và điều gì đáng để cha nỗ lực. Những kỳ vọng cơ bản, như một cây chổi trong tay người dọn dẹp, sẽ quét sạch tất cả những rác rưởi mà con gặp phải trên con đường đến thành công. Con trai, những kỳ vọng cơ bản của con là gì? Miễn là con không vứt bỏ nó, thành công chắc chắn sẽ đến.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"664\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-75-1024x664.png\" alt=\"\" class=\"wp-image-4883\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-75-1024x664.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-75-600x389.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-75-300x195.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-75-768x498.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-75.png 1233w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></figure>\n\n\n\n<p>Người lạc quan sẽ nhìn thấy cơ hội trong đau khổ, và người bi quan sẽ nhìn thấy đau khổ trong cơ hội. Con trai, hãy nhớ công thức thành công mà cha tin tưởng:</p>\n\n\n\n<p>Ước mơ + Thất bại + Thử thách = Thành công</p>\n\n\n\n<p>Tất nhiên, thất bại có sức mạnh chết người của nó, nó có thể khiến người ta chán nản suy đồi, mất tinh thần chiến đấu và ý chí. Điều quan trọng là con nhìn nhận thất bại như thế nào. Nhà phát minh thiên tài Thomas Edison, trước khi thắp sáng văn phòng của ông Morgan bằng đèn điện, đã tiến hành tổng cộng hơn 10.000 thí nghiệm. Đối với ông, thất bại là một bãi thử nghiệm cho thành công.</p>\n\n\n\n<p>Mười năm trước, một phóng viên trẻ từ tờ The New York Sun đã phỏng vấn ông và hỏi: “Thưa ông Edison, phát minh hiện tại của ông đã thất bại 10.000 lần. Ông nghĩ gì về điều này?” Edison rất miễn nhiễm với từ thất bại. Ông nói với phóng viên một cách khôn ngoan: “Chàng trai trẻ, hành trình cuộc đời của cậu mới chỉ bắt đầu, vì vậy tôi nói với cậu điều này sẽ giúp ích rất nhiều cho cậu trong tương lai. Tôi không thất bại 10.000 lần, tôi chỉ phát minh ra 10.000 phương pháp không hoạt động.” Sức mạnh của tinh thần luôn lớn lao như vậy.</p>\n\n\n\n<p>Con trai, nếu con tuyên bố phá sản về tinh thần/tâm trí, con sẽ mất tất cả. Con cần biết rằng con đường sự nghiệp giống như một con sóng. Nếu con bước lên con sóng, công trạng sẽ theo sau; và nếu con mắc sai lầm, con sẽ bị mắc kẹt trong vùng nước nông và buồn phiền suốt phần đời còn lại. Thất bại là một trải nghiệm học hỏi. Con có thể biến nó thành một bia mộ hoặc một bậc thang.</p>\n\n\n\n<p>Không có thành công nào mà không có thử thách. Đừng dừng lại vì một thất bại và hãy vượt qua chính mình. Con là người chiến thắng lớn nhất!</p>\n\n\n\n<p>Cha có niềm tin lớn vào con.</p>\n\n\n\n<p>Yêu thương,</p>\n\n\n\n<p>Cha của con</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-76-1024x683.png\" alt=\"\" class=\"wp-image-4884\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/05/image-76-1024x683.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-76-600x400.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-76-300x200.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-76-768x512.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-76-1536x1024.png 1536w, https://blog.kenfinly.com/wp-content/uploads/2025/05/image-76.png 1600w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></figure>\n\n\n\n<p>Bạn đọc vừa theo dõi bức thư thứ bảy – “Con Đường Đến Thành Công”, được trích từ cuốn sách “<a href=\"https://www.amazon.com/Letters-J-D-Rockefeller-his-son-ebook/dp/B08HM8G5VD\">The 38 Letters from J.D. Rockefeller to his son: Perspectives, Ideology, and Wisdom</a>“, 38 lá thư Rockefeller viết cho con trai để truyền đạt quan điểm, hệ tư tưởng và trí của của mình cho con trai.</p>\n\n\n\n<p>Bức thư thứ sáu: <a href=\"https://blog.kenfinly.com/sach/vay-tien-ngan-hang-uy-tin-hieu-qua/\">Khái niệm vay tiền&#8230;</a></p>\n\n\n\n<p>Bản dịch: Dieter R.</p>\n\n\n\n<p></p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:104:\"<p>&#8220;Thất bại là một bãi thử nghiệm cho thành công.&#8221; &#8211; Thomas Edison</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:4886;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:40;}s:4:\"tags\";a:4:{i:0;i:759;i:1;i:749;i:2;i:760;i:3;i:758;}s:10:\"class_list\";a:12:{i:0;s:9:\"post-4879\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:18:\"has-post-thumbnail\";i:6;s:6:\"hentry\";i:7;s:13:\"category-sach\";i:8;s:10:\"tag-co-hoi\";i:9;s:15:\"tag-rockeffeler\";i:10;s:10:\"tag-rui-ro\";i:11;s:14:\"tag-thanh-cong\";}s:6:\"_links\";a:11:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4879\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-js