4:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=579\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}i:2;a:6:{s:2:\"id\";i:741;s:4:\"link\";s:42:\"https://blog.kenfinly.com/tag/rockefeller/\";s:4:\"name\";s:11:\"Rockefeller\";s:4:\"slug\";s:11:\"rockefeller\";s:8:\"taxonomy\";s:8:\"post_tag\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:48:\"https://blog.kenfinly.com/wp-json/wp/v2/tags/741\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:44:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=741\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}i:3;a:6:{s:2:\"id\";i:601;s:4:\"link\";s:48:\"https://blog.kenfinly.com/tag/tu-duy-thanh-cong/\";s:4:\"name\";s:20:\"Tư duy thành công\";s:4:\"slug\";s:17:\"tu-duy-thanh-cong\";s:8:\"taxonomy\";s:8:\"post_tag\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:48:\"https://blog.kenfinly.com/wp-json/wp/v2/tags/601\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:44:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=601\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}}}}i:1;a:26:{s:2:\"id\";i:5281;s:4:\"date\";s:19:\"2025-06-25T09:00:00\";s:8:\"date_gmt\";s:19:\"2025-06-25T02:00:00\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=5281\";}s:8:\"modified\";s:19:\"2025-06-26T09:50:23\";s:12:\"modified_gmt\";s:19:\"2025-06-26T02:50:23\";s:4:\"slug\";s:49:\"kien-nhan-trong-kinh-doanh-bai-hoc-tu-rockefeller\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:81:\"https://blog.kenfinly.com/sach/kien-nhan-trong-kinh-doanh-bai-hoc-tu-rockefeller/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:74:\"Kiên Nhẫn Trong Kinh Doanh: Bài Học Chiến Lược Từ Rockefeller\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:13374:\"\n<p>Khám phá sức mạnh của sự kiên nhẫn trong kinh doanh qua bài học từ Rockefeller. Tìm hiểu cách kiên nhẫn trở thành chiến lược, giúp các nhà lãnh đạo vượt qua thử thách, kiểm soát cảm xúc và đạt thành công dài hạn.</p>\n\n\n\n<p>Bài viết thiết thực cho startup, doanh nghiệp nhỏ và người học hỏi không ngừng.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Giới thiệu</h2>\n\n\n\n<p>Trong thế giới kinh doanh đầy biến động, kiên nhẫn không chỉ là một đức tính mà còn là một chiến lược sống còn.</p>\n\n\n\n<p>Doanh nhân thành công John D. Rockefeller (1893 -1937) đã khẳng định: &#8220;Kiên nhẫn là chiến lược. Bốc đồng luôn là kẻ thù tồi tệ nhất của chúng ta.&#8221;</p>\n\n\n\n<p>Khi đối mặt với áp lực phải đưa ra quyết định nhanh chóng, nhiều người thường bỏ qua sức mạnh của sự &#8220;kiên nhẫn&#8221;. </p>\n\n\n\n<p>Họ không nhận ra rằng khả năng chịu đựng những gì người khác không thể, chính là chìa khóa để làm được những điều mà người khác không thể làm.</p>\n\n\n\n<p>Bài viết này, qua bức thư số 26, sẽ khám phá cách Rockefeller đã biến kiên nhẫn thành một chiến lược kinh doanh hiệu quả.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Bức thư số 26: Kiên nhẫn Là Chiến lược</h2>\n\n\n\n<p>Bốc đồng luôn là kẻ thù tồi tệ nhất của chúng ta.<br>Chỉ khi bạn có thể chịu đựng những gì người khác không thể, bạn mới có thể làm những điều người khác không thể làm.</p>\n\n\n\n<p></p>\n\n\n\n<p>Ngày 2 tháng 9 năm 1902</p>\n\n\n\n<p>John thân mến,</p>\n\n\n\n<p>Cha đánh giá cao sự tin tưởng của con khi thông báo cho cha về việc rút khỏi hội đồng quản trị của Citibank. </p>\n\n\n\n<p>Thất nhiên, cha hiểu tại sao con làm điều này. </p>\n\n\n\n<p>Con không thể tiếp tục chịu đựng một số hành vi của các đồng nghiệp, chứ đừng nói đến khuất phục họ.</p>\n\n\n\n<p>Tuy nhiên, liệu quyết định của con có khôn ngoan hay không vẫn chưa được xác nhận.</p>\n\n\n\n<p>Lý do rất đơn giản.</p>\n\n\n\n<p>Nếu con không chủ động từ bỏ vị trí giám đốc Citibank, mà thay vào đó chọn ở lại đó, con có thể đã đạt được nhiều hơn.</p>\n\n\n\n<p>Cha biết rằng, sự phục tùng là kẻ thù của tư duy và là người cai tù của tự do. </p>\n\n\n\n<p>Tuy nhiên, đối với một người tham vọng, việc duy trì sự vâng lời và kiên nhẫn cần thiết chính xác là một chiến lược thành công đã được thử nghiệm và kiểm chứng.</p>\n\n\n\n<p>Nhìn lại quá khứ, cha đã chịu đựng rất nhiều, và cha đã đạt được rất nhiều nhờ sự kiên nhẫn.</p>\n\n\n\n<p>Khi bắt đầu kinh doanh, do thiếu vốn, đối tác của cha, ông Clark, đã mời đồng nghiệp cũ của ông, ông Gardner, tham gia. Cha đồng ý với điều này. Bởi vì với sự bổ sung của người giàu có này, điều đó có nghĩa là tất cả mọi người có thể làm những gì mọi thành viên muốn làm, miễn là có đủ tiền để làm điều đó.</p>\n\n\n\n<p>Tuy nhiên, làm cha ngạc nhiên, với lời mời của Clark đối với một nhà đầu tư, nó đã mang lại cho cha sự sỉ nhục cùng một lúc. Họ muốn đổi tên Công ty Clark-Rockefeller thành Công ty Clark-Gardner. Lý do cho việc thay đổi tên công ty là: Gardner đến từ một gia đình nổi tiếng; họ của ông có thể thu hút nhiều khách hàng hơn.</p>\n\n\n\n<p>Đây là một lý do đâm sâu vào danh dự của cha! Cha tức giận! Cha cũng là một đối tác, và Gardner chỉ đóng góp phần vốn của ông ấy. </p>\n\n\n\n<p>Điều này có nghĩa là việc là một quý tộc đã cho ông ấy tước đoạt vị thế xứng đáng của cha?!</p>\n\n\n\n<p>Tuy nhiên, cha đã chịu đựng, và cha tự nhủ: &#8220;Ngươi phải kiểm soát bản thân, ngươi phải giữ tâm trí bình tĩnh, đây chỉ là sự khởi đầu, còn một chặng đường dài phía trước!&#8221;</p>\n\n\n\n<p>Cha giả vờ bình tĩnh và nói với Clark, &#8220;Không sao đâu.&#8221;</p>\n\n\n\n<p>Trên thực tế, đây là một lời nói dối.</p>\n\n\n\n<p>Hãy nghĩ xem, làm sao một người phải chịu đựng sự bất công và tổn thương lòng tự trọng lại có thể khoan dung như vậy!</p>\n\n\n\n<p>Tuy nhiên, cha đã sử dụng lý trí để dập tắt cơn giận đang bùng cháy trong lòng mình, vì cha biết nó sẽ mang lại lợi ích cho cha.</p>\n\n\n\n<p>Kiên nhẫn không phải là sự khoan dung mù quáng. Con cần bình tĩnh, xem xét lại tình hình và biết liệu quyết định của con có đi chệch hướng hoặc gây hại cho các mục tiêu của con không. </p>\n\n\n\n<p>Không chỉ là đáng xấu hổ nếu cha tức giận với Clark, mà quan trọng hơn, nó sẽ tạo ra rạn nứt trong sự hợp tác của tất cả mọi người, và khiến cha phải bắt đầu lại từ đầu.</p>\n\n\n\n<p>Thay vào đó, sự đoàn kết có thể tạo nên một lực lượng chung, cho phép sự nghiệp của tất cả mọi người phát triển lớn hơn, và đồng thời, nó cũng sẽ cho phép sức mạnh và lợi ích cá nhân của cha phát triển.</p>\n\n\n\n<p>Cha biết mình đang đi đâu. Sau đó, cha tiếp tục làm việc không mệt mỏi và nhiệt tình như mọi khi. </p>\n\n\n\n<p>Vào năm thứ ba, cha cuối cùng cũng đã loại trừ được ông Gardner xa hoa ra khỏi công ty, và thương hiệu Clark-Rockefeller được tái lập! Lúc đó, mọi người bắt đầu tôn trọng cha như ông Rockefeller, và cha trở thành một người giàu có.</p>\n\n\n\n<p>Trong mắt cha, kiên nhẫn không có nghĩa là nuốt giận, cũng không phải là khiêm tốn. Kiên nhẫn là một chiến lược, và nó cũng rèn luyện tính cách của con. Những gì nó nuôi dưỡng là một trái tim cạnh tranh. Đây là những gì cha học được trong quá trình hợp tác với ông Clark.</p>\n\n\n\n<p>Cha ngưỡng mộ sự bình đẳng và ghét những mệnh lệnh từ trên cao.</p>\n\n\n\n<p>Tuy nhiên, ông Clark luôn tỏ ra kiêu căng trước mặt cha, điều này khiến cha rất ghê tởm.</p>\n\n\n\n<p>Ông ấy dường như không bao giờ chú ý đến cha mà chỉ coi cha như một thư ký nhỏ bé thiển cận, và thậm chí coi thường cha vì cha không có khả năng làm gì ngoài việc ghi sổ sách và quản lý tiền bạc.  Không có ông ấy, cha sẽ vô giá trị. </p>\n\n\n\n<p>Đây là một sự khiêu khích trắng trợn, nhưng cha giả vờ làm ngơ.</p>\n\n\n\n<p>Cha biết rằng tôn trọng bản thân quan trọng hơn bất cứ điều gì khác. Tuy nhiên, cha đã chiến đấu với ông ấy trong lòng. </p>\n\n\n\n<p>Cha đã tự nhủ đi nhủ lại: vượt qua ông ấy, sức mạnh của ngươi sẽ là sự sỉ nhục lớn nhất đối với ông ấy, giống như cho ông ấy một cái tát mạnh nhất vào mặt.</p>\n\n\n\n<p>Như con biết, Công ty Clark-Rockefeller đã mãi mãi trở thành lịch sử. Công ty Rockefeller-Andrews đã thay thế nó, và cha đã lên chuyến tàu tốc hành để trở thành một tỷ phú. </p>\n\n\n\n<p>Chỉ có thể chịu đựng những gì người khác không thể chịu đựng, con mới có thể làm những gì người khác không thể làm.</p>\n\n\n\n<p>Bốc đồng là kẻ thù tồi tệ nhất của chúng ta bất cứ lúc nào.</p>\n\n\n\n<p>Nếu kiên nhẫn có thể giải quyết các xung đột không nên xảy ra, kiên nhẫn như vậy sẽ luôn đáng giá; nhưng nếu con ngoan cố bướng bỉnh đi theo con đường của riêng mình, không chỉ không giải quyết được cuộc khủng hoảng, mà còn mang lại những thảm họa lớn hơn. Ông Andrews dường như không hiểu sự thật này.</p>\n\n\n\n<p> Ông Andrews là một người tự cho mình là đúng mà không có khả năng kinh doanh. Ông ấy <a href=\"https://blog.kenfinly.com/giai-tri/thieu-tham-vong/\">thiếu tham vọng</a> trở thành một người doanh nhân vĩ đại, nhưng có những thành kiến xấu xa. </p>\n\n\n\n<p>Không có gì ngạc nhiên khi loại người này sẽ xung đột với cha.</p>\n\n\n\n<p>Xung đột dẫn đến cha và ông ấy chia tay nhau do việc chia cổ tức cho cổ đông của công ty. Tất cả mọi người đã làm tốt công việc năm đó và kiếm được nhiều tiền, nhưng cha không muốn để các cổ đông mang về tất cả số tiền mà công ty kiếm được. </p>\n\n\n\n<p>Cha hi vọng tái đầu tư một nửa số tiền thu được vào hoạt động của công ty. Nhưng Andrews kiên quyết phản đối ý tưởng này. </p>\n\n\n\n<p>Gã ích kỷ này muốn chia số tiền tất cả mọi người kiếm được, và thậm chí còn tức giận đe dọa cha rằng ông ấy không muốn tiếp tục làm việc trong công ty.</p>\n\n\n\n<p>Cha không thể chịu đựng bất kỳ ý tưởng nào ngăn cản công ty trở nên mạnh hơn. Cha chỉ có thể lật ngửa bài, và yêu cầu ông ấy đưa ra giá cho phần cổ phiếu của ông ấy. Ông ấy nói một triệu, và cha nói đồng ý.</p>\n\n\n\n<p>Cha đã mua nó với giá một triệu vào ngày hôm sau.</p>\n\n\n\n<p>Andrews đã rất phấn khích khi nhận được tiền. Ông ấy nghĩ rằng mình đã trúng số, và cổ phiếu của ông ấy nắm giữ không đáng một triệu đô la. </p>\n\n\n\n<p>Nhưng ông ấy không ngờ rằng cha đã kiếm được 300.000 đô la ngay sau khi cha thay đổi chủ sở hữu.</p>\n\n\n\n<p>Khi tin tức đến tai ông ấy, ông ấy thực sự gọi cha là đáng kinh. Cha không muốn kiếm được danh tiếng xấu xa chỉ vì 300.000 đô la, vì vậy cha đã gửi người đến nói với ông ấy rằng ông ấy có thể lấy lại nó với giá ban đầu. </p>\n\n\n\n<p>Nhưng Andrews, người đang bực bội, đã từ chối lòng tốt của cha. Trên thực tế, những gì ông ấy từ chối là cơ hội trở thành một người giàu có ở Hoa Kỳ. Nếu ông ấy có thể giữ cổ phiếu giá một triệu cho đến ngày nay, ông ấy sẽ trở thành một triệu phú đương nhiên.</p>\n\n\n\n<p>Nhưng do một khoảnh khắc bốc đồng, ông ấy đã đánh mất cơ hội của cả đời mà ông ấy không bao giờ có thể nắm bắt lại được.</p>\n\n\n\n<p>John à, có quá nhiều người và điều đòi hỏi chúng ta phải kiên nhẫn trong thế giới này, và họ dụ dỗ chúng ta trở nên xúc động. Do đó, con phải rèn luyện khả năng quản lý cảm xúc và kiểm soát cảm xúc của mình. Và con nên cẩn thận để không bị ảnh hưởng bởi cảm xúc khi đưa ra quyết định, mà thay vào đó, hãy đưa ra quyết định dựa trên nhu cầu của con, và luôn biết mình muốn gì. </p>\n\n\n\n<p>Con cũng cần biết rằng trong thế giới của cơ hội, không có quá nhiều cơ hội để tranh đấu.</p>\n\n\n\n<p>Nếu con thực sự muốn thành công, con phải nắm bắt và bảo vệ cơ hội của riêng mình, và cố gắng nắm bắt cơ hội của người khác.</p>\n\n\n\n<p>Hãy nhớ, con phải có sự kiên nhẫn trong cuộc sống hàng ngày. Nó sẽ mang lại cho con hạnh phúc, cơ hội, và thành công.</p>\n\n\n\n<p>Yêu thương,</p>\n\n\n\n<p>Cha của con.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Kết luận</h2>\n\n\n\n<p>Kiên nhẫn không phải là sự thụ động hay cam chịu, mà là chiến lược được tính toán kỹ lưỡng.</p>\n\n\n\n<p>Như Rockefeller đã chứng minh, kiên nhẫn giúp bạn nhìn xa hơn những khó khăn trước mắt, kiểm soát cảm xúc, và đưa ra quyết định sáng suốt dựa trên mục tiêu dài hạn.</p>\n\n\n\n<p>Nhà lãnh đạo thực sự xuất sắc biết khi nào cần kiên nhẫn chờ đợi và khi nào cần hành động quyết đoán. </p>\n\n\n\n<p>Họ hiểu rằng kiên nhẫn không chỉ rèn luyện tính cách mà còn nuôi dưỡng một trái tim cạnh tranh.</p>\n\n\n\n<p>Khi bạn áp dụng chiến lược kiên nhẫn vào doanh nghiệp của mình, bạn không chỉ tránh được những sai lầm do hấp tấp. Mà bạn còn tạo nền tảng vững chắc cho thành công bền vững.</p>\n\n\n\n<p>&#8220;Chỉ khi bạn có thể chịu đựng những gì người khác không thể, bạn mới có thể làm những điều người khác không thể làm.&#8221; Hãy nhớ lời này của tỷ phú Rockefeller. </p>\n\n\n\n<p>Nếu bạn thấy bài này hay, xin hãy like và share để ủng hộ cho team mình nhé.</p>\n\n\n\n<p>Xin cám ơn.</p>\n\n\n\n<p></p>\n\n\n\n<p></p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:366:\"<p>Khám phá sức mạnh của sự kiên nhẫn trong kinh doanh qua bài học từ Rockefeller. Tìm hiểu cách kiên nhẫn trở thành chiến lược, giúp các nhà lãnh đạo vượt qua thử thách, kiểm soát cảm xúc và đạt thành công dài hạn. Bài viết thiết thực cho startup, doanh nghiệp nhỏ và người [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:5298;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"form