\";a:1:{i:0;a:1:{s:4:\"href\";s:44:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=828\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}i:3;a:6:{s:2:\"id\";i:827;s:4:\"link\";s:61:\"https://blog.kenfinly.com/tag/ung-dung-ai-trong-doanh-nghiep/\";s:4:\"name\";s:36:\"ứng dụng AI trong doanh nghiệp\";s:4:\"slug\";s:30:\"ung-dung-ai-trong-doanh-nghiep\";s:8:\"taxonomy\";s:8:\"post_tag\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:48:\"https://blog.kenfinly.com/wp-json/wp/v2/tags/827\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:44:\"https://blog.kenfinly.com/wp-json/wp/v2/tags\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/post_tag\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?tags=827\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}}}}i:4;a:26:{s:2:\"id\";i:5273;s:4:\"date\";s:19:\"2025-06-22T19:00:00\";s:8:\"date_gmt\";s:19:\"2025-06-22T12:00:00\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=5273\";}s:8:\"modified\";s:19:\"2025-06-29T17:42:37\";s:12:\"modified_gmt\";s:19:\"2025-06-29T10:42:37\";s:4:\"slug\";s:43:\"3-bai-hoc-lanh-dao-hieu-qua-tu-anna-wintour\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:78:\"https://blog.kenfinly.com/ky-nang/3-bai-hoc-lanh-dao-hieu-qua-tu-anna-wintour/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:99:\"3 Bài Học Lãnh Đạo Hiệu Quả Từ Anna Wintour &#8211; Biểu Tượng Thời Trang Vogue\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:10658:\"\n<p>Khám phá 3 bài học kỹ năng lãnh đạo hiệu quả từ Anna Wintour, Tổng biên tập Vogue: hành động quyết đoán, không quan tâm đến ý kiến tiêu cực và giao tiếp rõ ràng. </p>\n\n\n\n<p>Những nguyên tắc này đã giúp bà duy trì vị trí đầu ngành thời trang trong suốt bốn thập kỷ, và có thể áp dụng vào sự nghiệp của bạn.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"614\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/06/image-16-1024x614.png\" alt=\"\" class=\"wp-image-5274\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/06/image-16-1024x614.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/06/image-16-600x360.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/06/image-16-300x180.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/06/image-16-768x461.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/06/image-16-1000x600.png 1000w, https://blog.kenfinly.com/wp-content/uploads/2025/06/image-16-590x354.png 590w, https://blog.kenfinly.com/wp-content/uploads/2025/06/image-16-400x240.png 400w, https://blog.kenfinly.com/wp-content/uploads/2025/06/image-16.png 1200w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /><figcaption class=\"wp-element-caption\"><strong>Anna Wintour.</strong> Arturo Holmes/Getty Images</figcaption></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Giới thiệu</h2>\n\n\n\n<p>Thế giới nhiều biến động, càng cần những người lãnh đạo mãnh mẽ dẫn dắt. Kỹ năng lãnh đạo hiệu quả là yếu tố quyết định giữa thành công và thất bại. Anna Wintour &#8211; người phụ nữ đã dẫn dắt tạp chí Vogue suốt bốn thập kỷ trong một ngành công nghiệp tự làm mới mình mỗi năm năm &#8211; là minh chứng sống động cho điều này.</p>\n\n\n\n<p>Bà không chỉ là một biểu tượng thời trang mà còn là hình mẫu về khả năng lãnh đạo xuất chúng.</p>\n\n\n\n<p>Qua chương trình The Knowledge Project, chúng tôi được tiếp cận những bài học vô giá từ hành trình của Anna Wintour đến đỉnh cao sự nghiệp.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"3 Bài Học Lãnh Đạo Hiệu Quả Từ Anna Wintour | Tín Hiệu Không Nhiễu #kipmtuduy #annawintour\" width=\"500\" height=\"281\" src=\"https://www.youtube.com/embed/cq7yi1mQu2c?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\n</div></figure>\n\n\n\n<p>Bài viết này sẽ khám phá ba nguyên tắc lãnh đạo cốt lõi đã giúp bà không chỉ đạt đến vị trí cao nhất mà còn duy trì nó trong một thời gian dài đáng kinh ngạc.</p>\n\n\n\n<p>Những bài học này không chỉ áp dụng trong ngành thời trang, mà còn có giá trị trong mọi lĩnh vực kinh doanh và phát triển bản thân.</p>\n\n\n\n<h2 class=\"wp-block-heading\">1. Tính Chủ Động Cao (High Agency) &#8211; Hành Động Thay Vì Phàn Nàn</h2>\n\n\n\n<p>Một trong những phẩm chất nổi bật nhất của Anna Wintour là khả năng hành động quyết đoán khi đối mặt với trở ngại.</p>\n\n\n\n<p>Đây là yếu tố cốt lõi của kỹ năng lãnh đạo hiệu quả mà nhiều người còn thiếu.</p>\n\n\n\n<p>Khi bà làm việc tại Harper&#8217;s, mặc dù thực hiện công việc của một biên tập viên thời trang nhưng Anna không được thăng chức vào vị trí này.</p>\n\n\n\n<p>Thay vì phàn nàn hay cố gắng thương lượng, bà đã hành động ngay lập tức: Từ chức, và mang theo cả trợ lý của mình.</p>\n\n\n\n<p>Bà chuyển đến New York, mà không có công việc nào chờ sẵn, đặt cược cả vào tầm nhìn của mình.</p>\n\n\n\n<p>Bài học ở đây là: hệ thống sẽ không tự điều chỉnh vì bạn.</p>\n\n\n\n<p>Khi năng lực gặp phải chính trị nội bộ, hãy chọn ra đi thay vì tranh cãi.</p>\n\n\n\n<p>Đây là biểu hiện của tính chủ động cao &#8211; không chờ đợi cơ hội mà tự tạo ra cơ hội.</p>\n\n\n\n<h2 class=\"wp-block-heading\">2. Không Quan Tâm Đến Ý Kiến Của Người Khác &#8211; Dám Làm Điều Khác Biệt</h2>\n\n\n\n<p>Yếu tố thứ hai trong kỹ năng lãnh đạo hiệu quả của Anna Wintour là khả năng không bị ảnh hưởng bởi ý kiến của người khác, khi bà tin vào tầm nhìn của mình.</p>\n\n\n\n<p>Năm 1989, quyết định đưa Madonna lên trang bìa Vogue của bà đã khiến giới thời trang kinh hoàng. </p>\n\n\n\n<p>Thời điểm đó, Madonna vừa mất hợp đồng tài trợ với Pepsi, vì một video gây tranh cãi.</p>\n\n\n\n<p>Các nhóm tôn giáo đang kêu gọi tẩy chay cô. </p>\n\n\n\n<p>Tuy nhiên, Anna vẫn quyết định thực hiện điều đó. </p>\n\n\n\n<p>Một phần vì một doanh nhân trên máy bay đã nói rằng Vogue <a href=\"https://fs.blog/knowledge-project-podcast/outliers-anna-wintour/\">&#8220;không bao giờ&#8221; đưa Madonna lên trang bìa</a>. </p>\n\n\n\n<p>Kết quả? Số báo đó đã bán thêm được 200.000 bản.</p>\n\n\n\n<p><strong>Bài học lãnh đạo</strong> ở đây rất rõ ràng: Khi mọi người đồng ý rằng điều gì đó là &#8220;không bao giờ&#8221; có thể thực hiện được, đó chính xác là lúc nó sẽ thành công. Sự đồng thuận có thể giết chết đổi mới.</p>\n\n\n\n<h2 class=\"wp-block-heading\">3. Tín Hiệu Không Nhiễu (Signal Without Static) &#8211; Giao Tiếp Rõ Ràng Và Trực Tiếp</h2>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"Anna Wintour: Bí Mật Quyền Lực Tại Tạp Chí Vogue #kipmtuduy  #annawintour\" width=\"500\" height=\"281\" src=\"https://www.youtube.com/embed/6riiIeCKNcI?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\n</div></figure>\n\n\n\n<p>Yếu tố thứ ba là khả năng giao tiếp với sự rõ ràng tuyệt đối &#8211; điều mà bài viết này gọi là &#8220;Signal Without Static): (Tín hiệu không nhiễu)</p>\n\n\n\n<p>Khi Grace Mirabella hỏi Anna muốn giữ vị trí nào tại Vogue, câu trả lời của bà chỉ có một từ: &#8220;yours&#8221; (nghĩa là &#8220;của bà&#8221;).</p>\n\n\n\n<p>Cuộc họp kết thúc ngay lập tức.</p>\n\n\n\n<p>Tuy nhiên, Anna vẫn nhận được vị trí đó.</p>\n\n\n\n<p>Đây chính là món quà của Anna: sự rõ ràng như phẫu thuật.</p>\n\n\n\n<p>Không có &#8220;có thể&#8221;. </p>\n\n\n\n<p>Không có uỷ ban.</p>\n\n\n\n<p>&#8220;Mọi người làm việc tốt hơn khi phản hồi nhanh chóng, trực tiếp và trung thực,&#8221; bà nói.</p>\n\n\n\n<p>Một đồng nghiệp từng nhận xét về Anna: &#8220;Bà ấy tốt bụng nhưng không phải lúc nào cũng dễ chịu.&#8221;</p>\n\n\n\n<p>Người dễ chịu thường làm mềm sự từ chối bằng hy vọng giả tạo. </p>\n\n\n\n<p>Người tốt bụng nói &#8220;không&#8221; và bạn tiếp tục.</p>\n\n\n\n<p>Sự rõ ràng không phải là tàn nhẫn. Đó là món quà đắt giá nhất bạn có thể trao tặng.</p>\n\n\n\n<h2 class=\"wp-block-heading\">4. Áp Dụng Các Nguyên Tắc Lãnh Đạo Của Anna Wintour Trong Bối Cảnh Việt Nam</h2>\n\n\n\n<p>Tôi nghĩ những bài học từ Anna Wintour có thể được áp dụng hiệu quả trong môi trường kinh doanh Việt Nam. Nếu bạn đang là một người chủ doanh nghiệp, bạn sẽ trả lời những câu hỏi này như thế nào? </p>\n\n\n\n<p>Câu hỏi 1: <strong>Làm thế nào để xây dựng văn hoá chấp nhận rủi ro trong một môi trường doanh nghiệp vốn đề cao sự đồng thuận và an toàn?</strong> Liệu bạn có thể tạo ra không gian an toàn cho việc thử nghiệm và thất bại trong tổ chức của mình không?</p>\n\n\n\n<p>Câu hỏi 2: <strong>Trong quá trình chuyển đổi số và áp dụng công nghệ mới, làm thế nào để doanh nghiệp của bạn có thể &#8220;đổi mới có trách nhiệm&#8221; &#8211; vừa đón đầu xu hướng, vừa không đánh mất bản sắc văn hoá? </strong>Theo định hướng của Chính phủ, chuyển đổi số, kinh tế xanh và công nghệ cao là ba ưu tiên hàng đầu trong phát triển kinh tế Việt Nam. Tuy nhiên, quá trình này không chỉ đơn thuần là áp dụng công nghệ mới, mà còn liên quan đến việc thay đổi tư duy và văn hoá làm việc. Làm thế nào để bạn có thể thúc đẩy đổi mới công nghệ mà không tạo ra sự chia rẽ giữa các thế hệ trong công ty?</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"577\" src=\"https://blog.kenfinly.com/wp-content/uploads/2025/06/image-17-1024x577.png\" alt=\"\" class=\"wp-image-5279\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2025/06/image-17-1024x577.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2025/06/image-17-600x338.png 600w, https://blog.kenfinly.com/wp-content/uploads/2025/06/image-17-300x169.png 300w, https://blog.kenfinly.com/wp-content/uploads/2025/06/image-17-768x433.png 768w, https://blog.kenfinly.com/wp-content/uploads/2025/06/image-17.png 1120w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Kết luận</h2>\n\n\n\n<p>Những bài học kỹ năng lãnh đạo hiệu quả từ Anna Wintour không chỉ là những nguyên tắc giúp bà thành công trong ngành thời trang, mà còn là những công cụ giá trị cho bất kỳ nhà lãnh đạo nào trong mọi lĩnh vực.</p>\n\n\n\n<p>Trong bối cảnh Việt Nam đang ngày càng hội nhập với thế giới, những nguyên tắc này &#8211; Tính chủ động cao; dám làm điều khác biệt; và giao tiếp rõ ràng &#8211; càng trở nên quan trọng.</p>\n\n\n\n<p></p>\n\n\n\n<p></p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:347:\"<p>Khám phá 3 bài học kỹ năng lãnh đạo hiệu quả từ Anna Wintour, Tổng biên tập Vogue: hành động quyết đoán, không quan tâm đến ý kiến tiêu cực và giao tiếp rõ ràng. Những nguyên tắc này đã giúp bà duy trì vị trí đầu ngành thời trang trong suốt bốn thập kỷ, [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:5276;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:4;}s:4:\"tags\";a:5:{i:0;i:834;i:1;i:832;i:2;i:833;i:3;i:623;i:4;i:835;}s:10:\"class_list\";a:13:{i:0;s:9:\"post-5273\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:18:\"has-post-thumbnail\";i:6;s:6:\"hentry\";i:7;s:16:\"category-ky-nang\";i:8;s:16:\"tag-anna-wintour\";i:9;s:32:\"tag-bi-quyet-lanh-dao-thanh-cong\";i:10;s:23:\"tag-dan-dat-su-thay-doi\";i:11;s:12:\"tag-lanh-dao\";i:12;s:17:\"tag-tap-chi-vogue\";}s:6:\"_links\";a:11:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/5273\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=5273\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:5;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/5273/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:5315;s:4:\"href\";s:65:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/5273/revisions/5315\";}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/media/5276\";}}s:13:\"wp:attachment\";a:1:{i:0;a:1:{s:4:\"href\";s:57:\"https://blog.kenfinly.com/wp-json/wp/v2/media?parent=5273\";}}s:7:\"wp:term\";a:2:{i:0;a:3:{s:8:\"taxonomy\";s:8:\"category\";s:10:\"embeddable\";b:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/categories?post=5273\";}i:1;a:3:{s:8:\"taxonomy\";s:8:\"post_tag\";s:10:\"embeddable\";b:1;s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/tags?post=5273\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}s:9:\"_embedded\";a:3:{s:6:\"author\";a:1:{i:0;a:8:{s:2:\"id\";i:1;s:4:\"name\";s:9:\"Dieter R.\";s:3:\"url\";s:16:\"http://kenkai.vn\";s:11:\"description\";s:401:\"Xin chào, tôi là Dieter R., một cây bút đam mê tại KenkAI.vn, đang sinh sống và làm việc tại Thành phố Hồ Chí Minh sôi động. Với niềm đam mê mãnh liệt về lĩnh vực lãnh đạo, tâm lý học, trí tuệ nhân tạo, công nghệ và phát triển bản thân, tôi luôn nỗ lực mang đến những nội dung giá trị và sâu sắc cho độc giả.\";s:4:\"link\";s:40:\"https://blog.kenfinly.com/author/dieter/\";s:4:\"slug\";s:6:\"dieter\";s:11:\"avatar_urls\";a:3:{i:24;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24&d=mm&r=g\";i:48;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=48&d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:15:{s:2:\"id\";i:5276;s:4:\"date\";s:19:\"2025-06-22T20:12:58\";s:4:\"slug\";s:35:\"ky-nang-lanh-dao-hieu-qua-kipmtuduy\";s:4:\"type\";s:10:\"attachment\";s:4:\"link\";s:125:\"https://blog.kenfinly.com/ky-nang/3-bai-hoc-lanh-dao-hieu-qua-tu-anna-wintour/attachment/ky-nang-lanh-dao-hieu-qua-kipmtuduy/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:54:\"kỹ năng lãnh đạo hiệu quả &#8211; kipmtuduy\";}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:7:\"caption\";a:1:{s:8:\"rendered\";s:161:\"<p>Nghệ thuật kết nối chiến lược, tài chính, hỗ trợ kinh doanh, ra quyết định và làm việc nhóm để dẫn dắt doanh nghiệp</p>\n\";}s:8:\"alt_text\";s:323:\"Hình ảnh minh họa kỹ năng lãnh đạo hiệu quả (effective leadership skills) thông qua một mạng lưới các yếu tố kinh doanh quan trọng như chiến lược, tài chính, làm việc nhóm và ra quyết định, được kết nối xung quanh khái niệm trung tâm \"Leadership\" (Lãnh đạo).\";s:10:\"media_type\";s:5:\"image\";s:9:\"mime_type\";s:9:\"image/png\";s:13:\"media_details\";a:6:{s:5:\"width\";i:800;s:6:\"height\";i:450;s:4:\"file\";s:47:\"2025/06/ky-nang-lanh-dao-hieu-qua-kipmtuduy.png\";s:8:\"filesize\";i:120179;s:5:\"sizes\";a:11:{s:21:\"woocommerce_thumbnail\";a:6:{s:4:\"file\";s:47:\"ky-nang-lanh-dao-hieu-qua-kipmtuduy-450x450.png\";s:5:\"width\";i:450;s:6:\"height\";i:450;s:8:\"filesize\";i:83144;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:100:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/ky-nang-lanh-dao-hieu-qua-kipmtuduy-450x450.png\";}s:29:\"woocommerce_gallery_thumbnail\";a:6:{s:4:\"file\";s:47:\"ky-nang-lanh-dao-hieu-qua-kipmtuduy-100x100.png\";s:5:\"width\";i:100;s:6:\"height\";i:100;s:8:\"filesize\";i:17444;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:100:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/ky-nang-lanh-dao-hieu-qua-kipmtuduy-100x100.png\";}s:18:\"woocommerce_single\";a:6:{s:4:\"file\";s:47:\"ky-nang-lanh-dao-hieu-qua-kipmtuduy-600x338.png\";s:5:\"width\";i:600;s:6:\"height\";i:338;s:8:\"filesize\";i:257488;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:100:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/ky-nang-lanh-dao-hieu-qua-kipmtuduy-600x338.png\";}s:6:\"medium\";a:6:{s:4:\"file\";s:47:\"ky-nang-lanh-dao-hieu-qua-kipmtuduy-300x169.png\";s:5:\"width\";i:300;s:6:\"height\";i:169;s:8:\"filesize\";i:87687;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:100:\"https://blog.kenfinly.com/wp-content/uploads/2025/06/ky-nang-lanh-dao-hieu-qua-kipmtuduy-300x169.png\";}s:9:\"thumbnail\";a:6:{s:4:\"file\";s:47:\"ky-nang-lanh-dao-hieu-qua-kipmtuduy-