ề lĩnh vực lãnh đạo, tâm lý học, trí tuệ nhân tạo, công nghệ và phát triển bản thân, tôi luôn nỗ lực mang đến những nội dung giá trị và sâu sắc cho độc giả.\";s:4:\"link\";s:40:\"https://blog.kenfinly.com/author/dieter/\";s:4:\"slug\";s:6:\"dieter\";s:11:\"avatar_urls\";a:3:{i:24;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24&d=mm&r=g\";i:48;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=48&d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:15:{s:2:\"id\";i:5239;s:4:\"date\";s:19:\"2025-06-19T13:35:36\";s:4:\"slug\";s:27:\"kipm-important-announcement\";s:4:\"type\";s:10:\"attachment\";s:4:\"link\";s:149:\"https://blog.kenfinly.com/sach/su-si-nhuc-la-dong-luc-cach-bien-nghich-canh-thanh-suc-manh-phat-trien-ca-nhan/attachment/kipm-important-announcement/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:35:\"KIPM &#8211; IMPORTANT ANNOUNCEMENT\";}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:7:\"caption\";a:1:{s:8:\"rendered\";s:100:\"<p>Đây là hình đại diện mặc định. Chúng tôi sẽ cập nhật lại hình sớm</p>\n\";}s:8:\"alt_text\";s:18:\"KIPM - Thông Báo\";s:10:\"media_type\";s:5:\"image\";s:9:\"mime_type\";s:10:\"image/jpeg\";s:13:\"media_details\";a:6:{s:5:\"width\";i:1920;s:6:\"height\";i:1080;s:4:\"file\";s:39:\"2025/06/KIPM-IMPORTANT-ANNOUNCEMENT.jpg\";s:8:\"filesize\";i:163368;s:5:\"sizes\";a:15:{s:21:\"woocommerce_thumbnail\";a:6:{s:4:\"file\";s:39:\"KIPM-IMPORTANT-ANNOUNCEMENT-450x450.jpg\";s:5:\"width\";i:450;s:6:\"height\";i:450;s:8: