m/wp-json/wp/v2/categories/164\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/categories\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/category\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?categories=164\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}i:1;a:0:{}}}}s:7:\"headers\";a:2:{s:5:\"total\";s:1:\"1\";s:11:\"total_pages\";s:1:\"1\";}}',1769951159),('kenfinly-cache-wordpress:posts:slug:cac-trieu-chung-cua-su-thieu-kien-tri:d751713988987e9331980363e24189ce','a:3:{s:7:\"success\";b:1;s:4:\"data\";a:26:{s:2:\"id\";i:4165;s:4:\"date\";s:19:\"2025-04-13T11:42:29\";s:8:\"date_gmt\";s:19:\"2025-04-13T04:42:29\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=4165\";}s:8:\"modified\";s:19:\"2025-04-13T11:42:30\";s:12:\"modified_gmt\";s:19:\"2025-04-13T04:42:30\";s:4:\"slug\";s:37:\"cac-trieu-chung-cua-su-thieu-kien-tri\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:69:\"https://blog.kenfinly.com/sach/cac-trieu-chung-cua-su-thieu-kien-tri/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:50:\"Các triệu chứng của sự thiếu kiên trì\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:14976:\"\n<p>Tại đây, bạn sẽ tìm thấy những kẻ thù thực sự đứng giữa bạn và những thành tựu đáng chú ý. Tại đây, bạn sẽ tìm thấy không chỉ những “triệu chứng” cho thấy sự yếu kém của TÍNH KIÊN TRÌ, mà còn là những nguyên nhân sâu kín trong tiềm thức của sự yếu kém này. Hãy nghiên cứu danh sách một cách cẩn thận, và đối mặt với chính mình một cách thẳng thắn NẾU BẠN THỰC SỰ MUỐN BIẾT BẠN LÀ AI VÀ BẠN CÓ THỂ LÀM ĐƯỢC NHỮNG GÌ.</p>\n\n\n\n<p>Đây là những điểm yếu mà những người tích lũy của cải phải nắm vượt qua:</p>\n\n\n\n<ol class=\"wp-block-list\">\n<li>Thất bại trong việc nhận ra và xác định rõ ràng chính xác những gì mình muốn.</li>\n\n\n\n<li>Tính trì hoãn, có hoặc không có nguyên do. (Thường được hỗ trợ bởi một loạt các lý do và biện minh hùng hồ).</li>\n\n\n\n<li>Thiếu quan tâm đến việc tích lũy kiến thức chuyên sâu.</li>\n\n\n\n<li>Tính do dự, thói quen “đẩy trách nhiệm” trong mọi trường hợp, thay vì đối mặt trực tiếp với vấn đề. (Cũng được hỗ trợ bởi các biện minh).</li>\n\n\n\n<li>Thói quen dựa vào các biện minh thay vì tạo ra các kế hoạch cụ thể để giải quyết vấn đề.</li>\n\n\n\n<li>Sự tự mãn. Chỉ có rất ít phương thuốc cho chứng bệnh này, và không có hy vọng cho những người mắc phải.</li>\n\n\n\n<li>Sự thờ ơ, thường được thể hiện qua sự sẵn sàng thỏa hiệp trong mọi trường hợp, thay vì đối mặt và chiến đấu với sự chống đối.</li>\n\n\n\n<li>Thói quen đổ lỗi cho người khác về những sai lầm của mình, và chấp nhận những hoàn cảnh bất lợi như là không thể tránh khỏi.</li>\n\n\n\n<li>SỰ YẾU KÉM CỦA MONG MUỐN, do sự bỏ bê trong việc lựa chọn ĐỘNG LỰC thúc đẩy hành động.</li>\n\n\n\n<li>Sự sẵn lòng, thậm chí là háo hức bỏ cuộc ngay từ dấu hiệu đầu tiên của thất bại. (Dựa trên một hoặc nhiều hơn 6 nỗi sợ cơ bản).</li>\n\n\n\n<li>Thiếu các KẾ HOẠCH ĐƯỢC TỔ CHỨC, được đặt thành văn bản để có thể phân tích.</li>\n\n\n\n<li>Thói quen bỏ qua các ý tưởng, hoặc bỏ lỡ cơ hội khi nó xuất hiện.</li>\n\n\n\n<li>ƯỚC MUỐN thay vì QUYẾT TÂM.</li>\n\n\n\n<li>Thói quen thỏa hiệp với SỰ NGHÈO KHÓ thay vì nhắm đến của cải. Sự vắng mặt chung của khát vọng để trở thành, để làm, và để sở hữu.</li>\n\n\n\n<li>Tìm kiếm tất cả các lối tắt đến của cải, cố gắng LẤY mà không CHO một giá trị tương đương, thường được phản ánh trong thói quen đánh bạc, cố gắng thực hiện những thương vụ “sắc sảo”.</li>\n\n\n\n<li>NỖI SỢ BỊ PHÊ BÌNH, thất bại trong việc tạo ra các kế hoạch và đưa chúng vào hành động, bởi vì những gì người khác sẽ nghĩ, làm hoặc nói. Kẻ thù này thuộc về đầu danh sách, bởi vì nó thường tồn tại trong tiềm thức của một người, nơi mà sự hiện diện của nó không được nhận ra.</li>\n</ol>\n\n\n\n<p>Hãy cùng xem xét một số triệu chứng của Nỗi Sợ Bị Phê Bình. Đa số mọi người cho phép người thân, bạn bè và công chúng ảnh hưởng đến mức họ không thể sống cuộc đời của chính mình, bởi vì họ sợ bị phê bình.</p>\n\n\n\n<p>Số lượng lớn người mắc sai lầm trong hôn nhân, vẫn giữ nguyên cam kết, và trải qua cuộc sống khổ sở và không hạnh phúc, bởi vì họ sợ những phê bình có thể xảy ra nếu họ sửa sai. (Bất kỳ ai đã chịu hình thức sợ hãi này đều biết những thiệt hại không thể khắc phục mà nó gây ra, bằng cách phá hủy hoài bão, sự tự tin và mong muốn đạt được).</p>\n\n\n\n<p>Hàng triệu người bỏ qua việc học tập bổ sung sau khi rời trường, bởi vì họ sợ bị phê bình. Vô số nam và nữ, cả trẻ và già, cho phép người thân phá hủy cuộc đời của họ dưới danh nghĩa TRÁCH NHIỆM, bởi vì họ sợ bị phê bình. (Trách nhiệm không yêu cầu bất kỳ ai phải chấp nhận sự hủy hoại các hoài bão cá nhân và quyền sống cuộc đời của riêng mình theo cách của mình).</p>\n\n\n\n<p>Mọi người từ chối mạo hiểm trong kinh doanh, bởi vì họ sợ những phê bình có thể xảy ra nếu thất bại. Nỗi sợ bị phê bình, trong những trường hợp như vậy, mạnh hơn MONG MUỐN thành công.</p>\n\n\n\n<p>Quá nhiều người từ chối đặt ra những mục tiêu cao cho bản thân, hoặc thậm chí bỏ qua việc lựa chọn nghề nghiệp, bởi vì họ sợ sự phê bình của người thân và “bạn bè” có thể &nbsp;nói “Đừng nhắm cao quá, mọi người sẽ nghĩ bạn điên”.</p>\n\n\n\n<p>Khi Andrew Carnegie gợi ý tôi dành hai mươi năm để tổ chức một triết lý về thành tựu cá nhân, ý nghĩ đầu tiên của tôi là sợ hãi về những gì mọi người có thể nói. Đề xuất đó đặt ra một mục tiêu vượt xa bất kỳ điều gì tôi từng hình dung. Nhanh như chớp, tâm trí tôi bắt đầu tạo ra những lời biện minh và lý do, tất cả đều có thể truy nguồn từ NỖI SỢ BỊ PHÊ BÌNH bẩm sinh. Một cái gì đó bên trong tôi nói, “Bạn không thể làm được &#8211; công việc quá lớn, và đòi hỏi quá nhiều thời gian &#8211; gia đình bạn sẽ nghĩ gì về bạn? &#8211; bạn sẽ kiếm sống như thế nào? &#8211; chưa từng có ai tổ chức một triết lý về thành công, bạn có quyền gì để tin rằng mình có thể làm được? &#8211; bạn là ai chứ, để dám nhắm cao như vậy? &#8211; &nbsp;hãy nhớ lại xuất thân khiêm tốn của bạn &#8211; bạn biết gì về triết học &#8211; mọi người sẽ nghĩ bạn điên (và họ đã nghĩ vậy) &#8211; tại sao trước đến giờ chưa có người nào khác làm điều này?”</p>\n\n\n\n<p>Những câu hỏi này, và nhiều câu hỏi khác, đã lóe lên trong tâm trí tôi và đòi hỏi sự chú ý. Dường như cả thế giới đã bỗng nhiên chú ý đến tôi với mục đích chế giễu để buộc tôi từ bỏ mọi mong muốn thực hiện đề xuất của ông Carnegie.</p>\n\n\n\n<p>Tôi có một cơ hội tuyệt vời, ngay lúc đó, để dập tắt hoài bão trước khi nó kiểm soát tôi. Về sau trong cuộc đời, sau khi phân tích hàng ngàn người, tôi khám phá ra rằng PHẦN LỚN Ý TƯỞNG CHẾT YỂU, VÀ CẦN ĐƯỢC TIẾP THÊM SỨC SỐNG THÔNG QUA CÁC KẾ HOẠCH CỤ THỂ VÀ HÀNH ĐỘNG NGAY LẬP TỨC. Thời điểm nuôi dưỡng một ý tưởng là ngay lúc nó ra đời. Mỗi phút nó tồn tại, càng tăng cơ hội sống sót. NỖI SỢ BỊ PHÊ BÌNH nằm ở gốc rễ của sự hủy diệt hầu hết các ý tưởng không bao giờ đạt đến giai đoạn LẬP KẾ HOẠCH và HÀNH ĐỘNG.</p>\n\n\n\n<p>Nhiều người tin rằng thành công vật chất là kết quả của những “cơ hội” thuận lợi. Có một phần cơ sở cho niềm tin này, nhưng những người hoàn toàn phụ thuộc vào may mắn, hầu như luôn bị thất vọng, bởi vì họ bỏ qua một yếu tố quan trọng khác phải hiện diện trước khi một người có thể chắc chắn về sự thành công. Đó là kiến thức để tạo ra những “cơ hội” thuận lợi.</p>\n\n\n\n<p>Trong thời kỳ suy thoái, W. C. Fields, diễn viên hài, đã mất hết tiền bạc, và thấy mình không có thu nhập, không có việc làm, và phương tiện kiếm sống của ông (vaudeville) không còn tồn tại nữa. Hơn nữa, ông đã ngoài sáu mươi tuổi, khi nhiều người coi mình đã “già”. Ông rất háo hức muốn quay trở lại sự nghiệp đến mức đã sẵn sàng làm việc không lương trong một lĩnh vực mới (điện ảnh). Ngoài những rắc rối khác, ông còn bị ngã và làm tổn thương cổ. Đối với nhiều người, đó sẽ là lúc từ bỏ và DỪNG LẠI. Nhưng Fields đã KIÊN TRÌ. Ông biết rằng nếu tiếp tục, ông sẽ có được những “cơ hội” sớm hay muộn, và ông đã có được chúng, nhưng không phải do may mắn.</p>\n\n\n\n<p>Marie Dressler thấy mình xuống dốc, hết tiền, không có việc làm, khi bà gần sáu mươi tuổi. Bà cũng đã đuổi theo những “cơ hội”, và đã có được chúng. Sự KIÊN TRÌ của bà đã mang lại một chiến thắng ngoạn mục vào cuối đời, ở độ tuổi mà hầu hết nam và nữ đã từ bỏ hoài bão.</p>\n\n\n\n<p>Eddie Cantor mất tiền trong cuộc suy thoái chứng khoán năm 1929, nhưng ông vẫn còn sự KIÊN TRÌ và lòng can đảm của mình. Với những điều này, cộng thêm đôi mắt nổi bật, ông đã tự quảng bá bản thân trở lại với mức thu nhập 10.000 đô la một tuần! Quả thực, nếu một người có KIÊN TRÌ, người đó có thể rất tốt mà không cần nhiều phẩm chất khác. Đó là “cơ hội” duy nhất mà bất kỳ ai cũng có thể dựa vào &#8211; một “cơ hội” do chính mình tạo ra. Những cơ hội này đến thông qua việc áp dụng TÍNH KIÊN TRÌ. Điểm khởi đầu là SỰ XÁC ĐỊNH MỤC ĐÍCH.</p>\n\n\n\n<p>Hãy kiểm tra 100 người đầu tiên bạn gặp, hỏi họ điều gì là mong muốn lớn nhất trong cuộc đời, và 98 người trong số họ sẽ không thể nói cho bạn biết. Nếu bạn ép buộc họ trả lời, một số sẽ nói &#8211; AN TOÀN, nhiều người sẽ nói &#8211; TIỀN BẠC, một số ít sẽ nói &#8211; HẠNH PHÚC, những người khác sẽ nói &#8211; DANH VỌNG VÀ QUYỀN LỰC, và một số khác nữa sẽ nói &#8211; CÔNG NHẬN XÃ HỘI, CUỘC SỐNG DỄ DÀNG, KHẢ NĂNG HÁT, NHẢY, hoặc VIẾT, nhưng không ai trong số họ có thể định nghĩa những thuật ngữ này, hoặc đưa ra dù chỉ là một dấu hiệu nhỏ nhất về KẾ HOẠCH mà họ hy vọng sẽ đạt được những mong ước mơ hồ này. Của cải không đáp ứng với những ước muốn. Chúng chỉ đáp ứng với những kế hoạch cụ thể, được hỗ trợ bởi những mong muốn xác định, thông qua sự KIÊN TRÌ liên tục.</p>\n\n\n\n<p>Dieter R.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Credit</h2>\n\n\n\n<p>Nguồn: <a href=\"https://www.amazon.com/Think-Grow-Rich-Landmark-Bestseller/dp/1585424331\">Think and Grow Rich</a> – Chapter: Symptoms Of Lack Of Persistence</p>\n\n\n\n<p>Cuốn sách này có thể chia thành 39 phần như thế này. Chúng ta sẽ cùng đọc xong trong 1 tháng nhé.</p>\n\n\n\n<p>Mục lục Think and Grow Rich!</p>\n\n\n\n<figure class=\"wp-block-table\"><table><tbody><tr><td>1.</td><td>Introduction</td></tr><tr><td>2.</td><td>Three Feet From Gold</td></tr><tr><td>3.</td><td>A Fifty-Cent Lesson In Persistence</td></tr><tr><td>4.</td><td><a href=\"https://blog.kenfinly.com/2025/03/sach/khat-vong-chia-khoa-lam-giau/\">Desire – The First Step toward Riches</a></td></tr><tr><td>5.</td><td>Desire Outwits Mother Nature</td></tr><tr><td>6.</td><td>Faith – The Second Step toward Riches</td></tr><tr><td>7.</td><td>Self-Confidence Formula</td></tr><tr><td>8.</td><td><a href=\"https://blog.kenfinly.com/2025/03/sach/nghi-giau-lam-giau-nghe-thuat-bien-y-tuong-thanh-hien-thuc/\">The Power of an Idea</a></td></tr><tr><td>9.</td><td><a href=\"https://blog.kenfinly.com/2025/03/sach/suc-manh-tam-tri-tiem-thuc-huong-toi-su-giau-co/\">Auto-Suggestion – The Third Step toward Riches</a></td></tr><tr><td>10.</td><td>Summary of Instructions</td></tr><tr><td>11.</td><td><a href=\"https://blog.kenfinly.com/2025/03/sach/kien-thuc-chuyen-mon-kinh-nghiem/\">Specialized Knowledge – The Fourth Step Toward Riches</a></td></tr><tr><td>12.</td><td><a href=\"https://blog.kenfinly.com/2025/04/giai-tri/thieu-tham-vong/\">Lack of Ambition</a></td></tr><tr><td>13.</td><td><a href=\"https://blog.kenfinly.com/2025/04/sach/tri-tuong-tuong-buoc-thu-nam-huong-toi-su-giau-co/\">Imagination – The Fifth Step toward Riches</a></td></tr><tr><td>14.</td><td>How To Make Practical Use Of Imagination</td></tr><tr><td>15.</td><td><a href=\"https://blog.kenfinly.com/2025/04/giao-duc/phat-trien-ban-than-bi-quyet-bien-uoc-mo-thanh-hien-thuc/\">What Would I Do If I Had A Million Dollars</a></td></tr><tr><td>16.</td><td>Organized Planning – The Sixth Step toward Riches</td></tr><tr><td>17.</td><td>When And How To Apply For A Position</td></tr><tr><td>18.</td><td>The Capital Value Of Your Services</td></tr><tr><td>19.</td><td>Take Inventory Of Yourself</td></tr><tr><td>20.</td><td><a href=\"https://blog.kenfinly.com/2025/04/sach/phep-mau-tu-ban-napoleon-hill/\">The “Miracle” That Has Provided These Blessings</a></td></tr><tr><td>21.</td><td><a href=\"https://blog.kenfinly.com/2025/04/giao-duc/quyet-doan-nghi-giau-lam-giau/\">Decision – The Seventh Step Toward Riches</a></td></tr><tr><td>22.</td><td><a href=\"https://blog.kenfinly.com/2025/04/sach/quyet-dinh-lich-su-triet-ly-napoleon-hill/\">Power</a></td></tr><tr><td>23.</td><td>The Sustained Effort Necessary To Induce Faith</td></tr><tr><td>24.</td><td>Symptoms Of Lack Of Persistence</td></tr><tr><td>25.</td><td>How To Develop Persistence</td></tr><tr><td>26.</td><td>Power – The Ninth Step toward Riches</td></tr><tr><td>27.</td><td>Transmutation – The Tenth Step Toward Riches</td></tr><tr><td>28.</td><td>Why Men Seldom Succeed Before Forty</td></tr><tr><td>29.</td><td>The Subconscious Mind – The Eleventh Step Toward Riches</td></tr><tr><td>30.</td><td>Emotion</td></tr><tr><td>31.</td><td>The Brain – The Twelfth Step Toward Riches</td></tr><tr><td>32.</td><td>The Dramatic Story Of The Brain</td></tr><tr><td>33.</td><td>The Sixth Sense – The Thirteenth Step Toward Riches</td></tr><tr><td>34.</td><td>Building Character Through Auto-Suggestion</td></tr><tr><td>35.</td><td>How To Outwit The Six Ghosts Of Fear</td></tr><tr><td>36.</td><td>The Fear Of Criticism</td></tr><tr><td>37.</td><td>Old Man Worry</td></tr><tr><td>38.</td><td>Self-Analysis Test Questions</td></tr><tr><td>39.</td><td>“Fifty-Seven” Famous Alibis</td></tr></tbody></table></figure>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:358:\"<p>Tại đây, bạn sẽ tìm thấy những kẻ thù thực sự đứng giữa bạn và những thành tựu đáng chú ý. Tại đây, bạn sẽ tìm thấy không chỉ những “triệu chứng” cho thấy sự yếu kém của TÍNH KIÊN TRÌ, mà còn là những nguyên nhân sâu kín trong tiềm thức của sự yếu [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:4151;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:40;}s:4:\"tags\";a:1:{i:0;i:706;}s:10:\"class_list\";a:9:{i:0;s:9:\"post-4165\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:18:\"has-post-thumbnail\";i:6;s:6:\"hentry\";i:7;s:13:\"category-sach\";i:8;s:23:\"tag-think-and-grow-rich\";}s:6:\"_links\";a:11:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4165\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=4165\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4165/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:4166;s:4:\"href\";s:65:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/4165/revisions/4166\";}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/media/4151\";}}s:13:\"wp:attachment\";a:1:{i:0;a:1:{s:4:\"href\";s:57:\"https://blog.kenfinly.com/wp-json/wp/v2/media?parent=4165\";}}s:7:\"wp:term\";a:2:{i:0;a:3:{s:8:\"taxonomy\";s:8:\"category\";s:10:\"embeddable\";b:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/categories?post=4165\";}i:1;a:3:{s:8:\"taxonomy\";s:8:\"post_tag\";s:10:\"embeddable\";b:1;s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/tags?post=4165\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}s:9:\"_embedded\";a:3:{s:6:\"author\";a:1:{i:0;a:8:{s:2:\"id\";i:1;s:4:\"name\";s:9:\"Dieter R.\";s:3:\"url\";s:16:\"http://kenkai.vn\";s:11:\"description\";s:401:\"Xin chào, tôi là Dieter R., một cây bút đam mê tại KenkAI.vn, đang sinh sống và làm việc tại Thành phố Hồ Chí Minh sôi động. Với niềm đam mê mãnh liệt về lĩnh vực lãnh đạo, tâm lý học, trí tuệ nhân tạo, công nghệ và phát triển bản thân, tôi luôn nỗ lực mang đến những nội dung giá trị và sâu sắc cho độc giả.\";s:4:\"link\";s:40:\"https://blog.kenfinly.com/author/dieter/\";s:4:\"slug\";s:6:\"dieter\";s:11:\"avatar_urls\";a:3:{i:24;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24&d=mm&r=g\";i:48;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=48&d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:15:{s:2:\"id\";i:4151;s:4:\"date\";s:19:\"2025-04-12T12:45:27\";s:4:\"slug\";s:11:\"kien-tri-02\";s:4:\"type\";s:10:\"attachment\";s:4:\"link\";s:69:\"https://blog.kenfinly.com/sach/niem-tin-la-gi/attachment/kien-tri-02/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:13:\"kiên trì 02\";}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:7:\"caption\";a:1:{s:8:\"rendered\";s:0:\"\";}s:8:\"al