v2/posts?categories=6\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}i:1;a:0:{}}}}s:7:\"headers\";a:2:{s:5:\"total\";s:1:\"1\";s:11:\"total_pages\";s:1:\"1\";}}',1769906758),('kenfinly-cache-wordpress:posts:slug:hoa-hoc-khac-toan-hoc-cho-nao:d751713988987e9331980363e24189ce','a:3:{s:7:\"success\";b:1;s:4:\"data\";a:26:{s:2:\"id\";i:61;s:4:\"date\";s:19:\"2024-08-13T08:33:51\";s:8:\"date_gmt\";s:19:\"2024-08-13T08:33:51\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:31:\"https://blog.kenfinly.com/?p=61\";}s:8:\"modified\";s:19:\"2024-08-13T08:34:04\";s:12:\"modified_gmt\";s:19:\"2024-08-13T08:34:04\";s:4:\"slug\";s:29:\"hoa-hoc-khac-toan-hoc-cho-nao\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:67:\"https://blog.kenfinly.com/chuyen-vui/hoa-hoc-khac-toan-hoc-cho-nao/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:40:\"HÓA HỌC KHÁC TOÁN HỌC CHỖ NÀO?\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:1160:\"\n<p class=\"has-system-serif-font-family\">&nbsp; Một hôm, nhà toán học Đức Karl Gauss tranh luận với nhà hóa học Ý Avogadro. Ông Gauss tỏ ra khinh thường hóa học và cho rằng chỉ có toán học mới có các định luật, còn hóa học chỉ là người phục vụ cho toán học mà thôi.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Avogadro dẫn Gauss vào phòng thí nghiệm và tự mình làm phản ứng: Cho một thề tích O<sub>2</sub>&nbsp;tác dụng với hai thể tích H<sub>2</sub>&nbsp;để tạo thành hai thể tích H<sub>2</sub>O ở dạng hơi:</p>\n\n\n\n<p class=\"has-system-serif-font-family\">2H<sub>2&nbsp;</sub>(k) + O<sub>2&nbsp;</sub>(k) –&gt; 2H<sub>2</sub>O (h)</p>\n\n\n\n<p class=\"has-system-serif-font-family\">&nbsp; &nbsp; &nbsp; &nbsp;Lúc đó nhà hóa học mới mỉm cười bảo nhà toán học rằng:</p>\n\n\n\n<p class=\"has-system-serif-font-family\">&nbsp; &nbsp; &nbsp; &nbsp;&#8211; Ngài thấy chưa! Nếu hóa học đã muốn thì toán học phải chào thua. Hai cộng một, bất chấp toán học cũng vẫn chỉ là hai đấy thôi.</p>\n\n\n\n<p></p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:341:\"<p>&nbsp; Một hôm, nhà toán học Đức Karl Gauss tranh luận với nhà hóa học Ý Avogadro. Ông Gauss tỏ ra khinh thường hóa học và cho rằng chỉ có toán học mới có các định luật, còn hóa học chỉ là người phục vụ cho toán học mà thôi. Avogadro dẫn Gauss vào phòng [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:3;}s:4:\"tags\";a:0:{}s:10:\"class_list\";a:7:{i:0;s:7:\"post-61\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:6:\"hentry\";i:6;s:19:\"category-chuyen-vui\";}s:6:\"_links\";a:10:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:48:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/61\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:56:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=61\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:2;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/61/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:63;s:4:\"href\";s:61:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/61/revisions/63\";}}s:13:\"wp:attachment\";a:1:{i:0;a:1:{s:4:\"href\";s:55:\"https://blog.kenfinly.com/wp-json/wp/v2/media?parent=61\";}}s:7:\"wp:term\";a:2:{i:0;a:3:{s:8:\"taxonomy\";s:8:\"category\";