Luat-Rung-dong.mp4&#8243;]</p>\n\n\n\n<p>Nguồn: <a href=\"https://www.youtube.com/watch?v=iGSiD1tRQzQ\">https://www.youtube.com/watch?v=iGSiD1tRQzQ</a></p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:158:\"<p>Chúng ta sẽ cùng nhau tìm hiểu cách mà suy nghĩ, cảm xúc, và ngay cả vật thể xung quanh ta đều là những dạng rung động.</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:3467;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:3:{i:0;i:9;i:1;i:5;i:2;i:164;}s:4:\"tags\";a:1:{i:0;i:657;}s:10:\"class_list\";a:11:{i:0;s:9:\"post-3466\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:18:\"has-post-thumbnail\";i:6;s:6:\"hentry\";i:7;s:17:\"category-giai-tri\";i:8;s:17:\"category-giao-duc\";i:9;s:17:\"category-goc-nhin\";i:10;s:18:\"tag-luat-rung-dong\";}s:6:\"_links\";a:11:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/3466\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=3466\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/3466/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:3468;s:4:\"href\";s:65:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/3466/revisions/3468\";}}s:16:\"wp:featuredmedi