:74;s:4:\"date\";s:19:\"2024-08-13T08:40:51\";s:8:\"date_gmt\";s:19:\"2024-08-13T08:40:51\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:31:\"https://blog.kenfinly.com/?p=74\";}s:8:\"modified\";s:19:\"2024-08-13T08:40:51\";s:12:\"modified_gmt\";s:19:\"2024-08-13T08:40:51\";s:4:\"slug\";s:29:\"nha-hoa-hoc-va-cac-nganh-khac\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:67:\"https://blog.kenfinly.com/chuyen-vui/nha-hoa-hoc-va-cac-nganh-khac/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:37:\"NHÀ HÓA HỌC VÀ CÁC NGÀNH KHÁC\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:1857:\"\n<p class=\"has-system-serif-font-family\">Langmuir – người đề xuất lý thuyết hấp thụ hiện đại gắn cả cuộc đời với môn leo núi và trượt băng.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Seaborg – người phát minh và nghiên cứu hàng loạt nguyên tố mới họ siêu uran là cầu thủ hockey kiệt xuất.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Nhà hóa học cao phân tử hàng đầu Ziegler say mê sưu tầm và nuôi cá vàng. Đồng nghiệp nổi tiếng của ông là Cargin là người câu cá thiện nghệ và sưu tầm tem lớn.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Chuyên gia hàng đầu về khí hiếm Aston lại là một nhà biểu diễn vionlonxen bậc thầy (đồng thời phát minh ra đồng vị phóng xạ). Cũng như vậy, các nhà hóa học khác như Meyer, Perkin Anbuzov – đều có phản ứng mang tên mình và là những nhạc công vĩ cầm tuyệt vời.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Ramsay – ông tổ của khí trơ cũng như Carothers – ông tổ của tơ sợi tổng hợp là các ca sĩ lẫy lừng.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Borodin – nhà hóa học kiêm nhà soạn nhạc Nga lẫy lừng.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Nhà hóa học đặt nền móng cho hóa lý Ostwald hàng năm đều có triển lãm tranh cá nhân. Còn Kekule – ông tổ của hợp chất thơm lại có khiếu ngoại ngữ và hội họa hiếm có.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Davy, Vant Hoff nổi tiếng cả về hóa học lẫn các tác phẩm thơ ca, ngôn ngữ. Haber là nhà viết kịch. Lomonosov kiêm cả sử học, ngôn ngữ, họa sĩ. Còn Mendeleyev gắn với nghề đóng vali cổ truyền!</p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:353:\"<p>Langmuir – người đề xuất lý thuyết hấp thụ hiện đại gắn cả cuộc đời với môn leo núi và trượt băng. Seaborg – người phát minh và nghiên cứu hàng loạt nguyên tố mới họ siêu uran là cầu thủ hockey kiệt xuất. Nhà hóa học cao phân tử hàng đầu Ziegler say mê [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:1:{i:0;i:3;}s:4:\"tags\";a:0:{}s:10:\"class_list\";a:7:{i:0;s:7:\"post-74\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:6:\"hentry\";i:6;s:19:\"category-chuyen-vui\";}s:6:\"_links\";a:10:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:48:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/74\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:56:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=74\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/74/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:75;s:4:\"href\";s:61:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/74/revisions/75\";}}s:13:\"wp:attachment\";a:1:{i:0;a:1:{s:4:\"href\";s:55:\"https://blog.kenfinly.com/wp-json/wp/v2/media?parent=74\";}}s:7:\"wp:term\";a:2:{i:0;a:3:{s:8:\"taxonomy\";s:8:\"category\";s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/categories?post=74\";}i:1;a:3:{s:8:\"taxonomy\";s:8:\"post_tag\";s:10:\"embeddable\";b:1;s:4:\"href\";s:52:\"https://blog.kenfinly.com/wp-json/wp/v2/tags?post=74\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}s:9:\"_embedded\";a:2:{s:6:\"author\";a:1:{i:0;a:8:{s:2:\"id\";i:1;s:4:\"name\";s:9:\"Dieter R.\";s:3:\"url\";s:16:\"http://kenkai.vn\";s:11:\"description\";s:401:\"Xin chào, tôi là Dieter R., một cây bút đam mê tại KenkAI.vn, đang sinh sống và làm việc tại Thành phố Hồ Chí Minh sôi động. Với niềm đam mê mãnh liệt về lĩnh vực lãnh đạo, tâm lý học, trí tuệ nhân tạo, công nghệ và phát triển bản thân, tôi luôn nỗ lực mang đến những nội dung giá trị và sâu sắc cho độc giả.\";s:4:\"link\";s:40:\"https://blog.kenfinly.com/author/dieter/\";s:4:\"slug\";s:6:\"dieter\";s:11:\"avatar_urls\";a:3:{i:24;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24&d=mm&r=g\";i:48;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=48&d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:7:\"wp:term\";a:2:{i:0;a:1:{i:0;a:6:{s:2:\"id\";i:3;s:4:\"link\";s:46:\"https://blog.kenfinly.com/category/chuyen-vui/\";s:4:\"name\";s:12:\"Chuyện vui\";s:4:\"slug\";s:10:\"chuyen-vui\";s:8:\"taxonomy\";s:8:\"category\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:52:\"https://blog.kenfinly.com/wp-json/wp/v2/categories/3\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/categories\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/category\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?categories=3\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}i:1;a:0:{}}}}s:7:\"headers\";a:2:{s:5:\"total\";s:1:\"1\";s:11:\"total_pages\";s:1:\"1\";}}',1769982052),('kenfinly-cache-wordpress:posts:slug:nha-sang-lap-ty-phu-cua-duolingo-dang-dat-cuoc-tat-ca-vao-ai:d751713988987e9331980363e24189ce','a:3:{s:7:\"success\";b:1;s:4:\"data\";a:26:{s:2:\"id\";i:950;s:4:\"date\";s:19:\"2024-09-24T19:57:07\";s:8:\"date_gmt\";s:19:\"2024-09-24T12:57:07\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:32:\"https://blog.kenfinly.com/?p=950\";}s:8:\"modified\";s:19:\"2024-09-24T19:57:07\";s:12:\"modified_gmt\";s:19:\"2024-09-24T12:57:07\";s:4:\"slug\";s:60:\"nha-sang-lap-ty-phu-cua-duolingo-dang-dat-cuoc-tat-ca-vao-ai\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:96:\"https://blog.kenfinly.com/giao-duc/nha-sang-lap-ty-phu-cua-duolingo-dang-dat-cuoc-tat-ca-vao-ai/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:81:\"Nhà sáng lập tỷ phú của Duolingo đang đặt cược tất cả vào AI\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:8747:\"\n<p class=\"has-system-serif-font-family\">Luis von Ahn, người lớn lên trong cảnh nghèo khó ở Guatemala, đang nhắm tới việc biến đổi ứng dụng học ngôn ngữ phổ biến thành một gia sư AI tự động.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"624\" height=\"624\" src=\"https://blog.kenfinly.com/wp-content/uploads/2024/09/Picture1.jpg\" alt=\"\" class=\"wp-image-952\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2024/09/Picture1.jpg 624w, https://blog.kenfinly.com/wp-content/uploads/2024/09/Picture1-450x450.jpg 450w, https://blog.kenfinly.com/wp-content/uploads/2024/09/Picture1-100x100.jpg 100w, https://blog.kenfinly.com/wp-content/uploads/2024/09/Picture1-600x600.jpg 600w, https://blog.kenfinly.com/wp-content/uploads/2024/09/Picture1-300x300.jpg 300w, https://blog.kenfinly.com/wp-content/uploads/2024/09/Picture1-150x150.jpg 150w\" sizes=\"auto, (max-width: 624px) 100vw, 624px\" /><figcaption class=\"wp-element-caption\">Luis von Ahn, <strong>Nhà sáng lập tỷ phú của Duolingo</strong></figcaption></figure>\n\n\n\n<p class=\"has-system-serif-font-family\">Luis von Ahn, người lớn lên trong cảnh nghèo khó ở Guatemala, đang nhắm tới việc biến đổi ứng dụng học ngôn ngữ phổ biến thành một gia sư AI tự động.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Ngồi trong Duo&#8217;s Taqueria, một nhà hàng Mexico cao cấp ánh sáng mờ ở Pittsburgh, Luis von Ahn suy ngẫm về sự kết thúc của công việc như chúng ta biết.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Giữa những miếng tacos al pastor và những ngụm margarita, Von Ahn, người sáng lập và CEO của ứng dụng học ngôn ngữ Duolingo, nói về việc AI sẽ khiến một số công việc biến mất, và người lao động sẽ cần được đào tạo lại.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Ông nói từ kinh nghiệm: Cuối năm ngoái, Duolingo đã quyết định không gia hạn hợp đồng với khoảng 10% lực lượng lao động hợp đồng làm công việc dịch thuật và viết bài học, thay vào đó lựa chọn sử dụng AI cho những nhiệm vụ này trong một số trường hợp.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">&#8220;Quan điểm của chúng tôi với tư cách là một công ty là nếu chúng tôi có thể tự động hóa điều gì đó, chúng tôi sẽ làm,&#8221; von Ahn nói về việc sa thải. &#8220;Công việc của một nhân viên toàn thời gian rất khó tự động hóa. Nhưng chúng tôi có một số nhân viên hợp đồng theo giờ đang làm những công việc khá máy móc.&#8221;</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Mặc dù ông tin chắc rằng đó là quyết định đúng đắn cho công ty của mình, ông nhận thức được những vấn đề rộng lớn hơn mà AI sẽ mang lại. &#8220;Đó là một tình huống khó khăn sẽ ảnh hưởng đến người nghèo, người ít học,&#8221; ông nói. &#8220;Và không chỉ ở Mỹ, mà còn ở các nước nghèo.&#8221;</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Từ một bàn ở cuối nhà hàng, vốn được Duolingo thiết kế ban đầu như một nơi thực khách có thể thực hành tiếng Tây Ban Nha, ông lưu ý rằng sẽ cần có quy định thông minh từ các chính phủ trên thế giới để đảm bảo AI công bằng. Nhưng ông không có nhiều niềm tin vào Mỹ, nước này sẽ phải &#8220;lấy đầu ra khỏi mông&#8221; để làm điều đó. &#8220;Thật khó để tưởng tượng rằng Mỹ sẽ lập pháp tốt về vấn đề này, khi họ không thể đồng ý về bất cứ điều gì.&#8221;</p>\n\n\n\n<p class=\"has-system-serif-font-family\">&#8220;Nó có thể khiến các gia sư cá nhân mất việc. Tôi hiểu điều đó. Nhưng tôi nghĩ cuối cùng sẽ tốt hơn nếu mọi người đều có quyền tiếp cận một gia sư.&#8221;</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Nhưng về lâu dài, von Ahn lạc quan rằng AI có thể mở ra những khả năng mới cho việc học tập, mang giáo dục chất lượng cao đến với đại chúng.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Ông nghĩ ngôn ngữ có thể giúp người ta thoát khỏi đói nghèo, lưu ý rằng, đối với người không nói tiếng mẹ đẻ, việc học tiếng Anh ngay lập tức mở rộng tiềm năng kiếm tiền của một người và mở ra một thế giới công việc hoàn toàn mới. Ông thấy Duolingo đang đi đầu trong quá trình chuyển đổi sang học tập bằng AI, với mục tiêu cuối cùng là tạo ra một gia sư AI tự động có thể dạy bất kỳ ai một ngoại ngữ.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">&#8220;Điều đó sẽ tốt cho thế giới nói chung,&#8221; ông nói. &#8220;Nó có thể khiến các gia sư cá nhân mất việc. Tôi hiểu điều đó. Nhưng tôi nghĩ cuối cùng sẽ tốt hơn nếu mọi người đều có quyền tiếp cận một gia sư.&#8221;</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Von Ahn không ngại bày tỏ những ý kiến mạnh mẽ. Ông thích thú với những meme về việc linh vật cú của Duolingo (tên là Duo) có thể đột nhập vào nhà của người dùng bỏ lỡ bài học ngôn ngữ, một thương hiệu doanh nghiệp mà ông gọi là &#8220;lành mạnh nhưng điên rồ&#8221;. Ông là một nhà phê bình gay gắt đối với Alejandro Giammattei, cựu tổng thống của quê hương Guatemala, người mà ông tố cáo là tham nhũng (ông cũng là nhà tài trợ lớn nhất cho người thay thế Giammattei là Bernardo Arévalo, người nhậm chức vào tháng 1). Và ông đã nói rằng ông nghĩ AI sẽ khiến máy tính trở thành giáo viên tốt hơn con người.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Vào thứ Ba, Duolingo đã ra mắt bước đầu tiên theo hướng đó: Một tính năng tương tác trong đó người dùng tham gia vào &#8220;cuộc gọi video&#8221; với Lily, một trong những linh vật được yêu thích của Duolingo &#8211; một phụ nữ hoạt hình với mái tóc tím và tính cách châm biếm. Trò chuyện với Lily cho phép mọi người thực hành giao tiếp bằng các ngôn ngữ khác như thể đang FaceTime với một người bạn AI, với đoạn hội thoại được tạo ra bởi mô hình GPT-4o của OpenAI. Đây là một phần của gói đăng ký 30 đô la một tháng, gọi là Duolingo Max, mà công ty đã ra mắt năm ngoái cho các tính năng AI cao cấp của mình, bao gồm cả tính năng cho biết tại sao người dùng trả lời sai một câu hỏi trong bài học.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Một bổ sung AI mới khác là trò chơi nhỏ có tên Adventures, đặt người dùng vào các tình huống tương tác để thực hành kỹ năng ngôn ngữ của họ, như đặt cà phê từ một quán café hoặc kiểm tra hộ chiếu.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Các tính năng mới là làn sóng mới nhất của các công cụ từ nỗ lực AI tạo sinh mà công ty đã bắt đầu từ năm ngoái. &#8220;Trong tâm trí tôi, gia sư AI cá nhân hóa không giống như một tính năng cụ thể mà chúng tôi đang xây dựng,&#8221; Klinton Bicknell, người đứng đầu bộ phận AI của Duolingo, nói với Forbes. &#8220;Mà nó giống như một tầm nhìn về việc toàn bộ ứng dụng sẽ trở thành gì.&#8221;</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Sự đẩy mạnh AI của Duolingo, công ty đã niêm yết công khai vào năm 2022, đã dẫn đến sự gia tăng về người dùng và doanh thu: Gần 104 triệu người học ngôn ngữ, toán học và âm nhạc trên ứng dụng mỗi tháng, tăng 40% so với năm trước. Quý vừa qua, doanh thu đạt 178,3 triệu đô la, tăng 41% so với năm ngoái. Cổ phiếu của công ty đạt mức cao kỷ lục vào thứ Hai là 270 đô la, đưa giá trị vốn hóa thị trường của công ty lên 11,75 tỷ đô la. Von Ahn, người sở hữu khoảng 10% công ty, giờ đã trở thành tỷ phú, cùng với đồng sáng lập Severin Hacker.</p>\n\n\n\n<p class=\"has-system-serif-font-family\"><em>(&#8230; to be continued)</em></p>\n\n\n\n<p></p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:359:\"<p>Luis von Ahn, người lớn lên trong cảnh nghèo khó ở Guatemala, đang nhắm tới việc biến đổi ứng dụng học ngôn ngữ phổ biến thành một gia sư AI tự động. Luis von Ahn, người lớn lên trong cảnh nghèo khó ở Guatemala, đang nhắm tới việc biến đổi ứng dụng học ngôn ngữ [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:951;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:2:{i:0;i:5;i:1;i:6;}s:4:\"tags\";a:1:{i:0;i:108;}s:10:\"class_list\";a:10:{i:0;s:8:\"post-950\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:18:\"has-post-thumbnail\";i:6;s:6:\"hentry\";i:7;s:17:\"category-giao-duc\";i:8;s:16:\"category-tin-tuc\";i:9;s:12:\"tag-duolingo\";}s:6:\"_links\";a:11:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:49:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/950\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:57:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=950\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:1;s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/950/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:953;s:4:\"href\";s:63:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/950/revisions/953\";}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:49:\"https://blog.kenfinly.com/wp-json/wp/v2/media/951\";}}s:13:\"wp:attachment\";a:1:{i:0;a:1:{s:4:\"href\";s:56:\"https://blog.kenfinly.com/wp-json/wp/v2/media?parent=950\";}}s:7:\"wp:term\";a:2:{i:0;a:3:{s:8:\"taxonomy\";s:8:\"category\";s:10:\"embeddable\";b:1;s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/categories?post=950\";}i:1;a:3:{s:8:\"taxonomy\";s:8:\"post_tag\";s:10:\"embeddable\";b:1;s:4:\"href\";s:53:\"https://blog.kenfinly.com/wp-json/wp/v2/tags?post=950\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}s:9:\"_embedded\";a:3:{s:6:\"author\";a:1:{i:0;a:8:{s:2:\"id\";i:1;s:4:\"name\";s:9:\"Dieter R.\";s:3:\"url\";s:16:\"http://kenkai.vn\";s:11:\"description\";s:401:\"Xin chào, tôi là Dieter R., một cây bút đam mê tại KenkAI.vn, đang sinh sống và làm việc tại Thành phố Hồ Chí Minh sôi động. Với niềm đam mê mãnh liệt về lĩnh vực lãnh đạo, tâm lý học, trí tuệ nhân tạo, công nghệ và phát triển bản thân, tôi luôn nỗ lực mang đến những nội dung giá trị và sâu sắc cho độc giả.\";s:4:\"link\";s:40:\"https://blog.kenfinly.com/author/dieter/\";s:4:\"slug\";s:6:\"dieter\";s:11:\"avatar_urls\";a:3:{i:24;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24&d=mm&r=g\";i:48;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=48&d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:15:{s:2:\"id\";i:951;s:4:\"date\";s:19:\"2024-09-24T19:50:23\";s:4:\"slug\";s:32:\"nha-sang-lap-ty-phu-cua-duolingo\";s:4:\"type\";s:10:\"attachment\";s:4:\"link\";s:140:\"https://blog.kenfinly.com/giao-duc/nha-sang-lap-ty-phu-cua-duolingo-dang-dat-cuoc-tat-ca-vao-ai/attachment/nha-sang-lap-ty-phu-cua-duolingo/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:41:\"Nhà sáng lập tỷ phú của Duolingo\";}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:7:\"caption\";a:1:{s:8:\"rendered\";s:0:\"\";}s:8:\"alt_text\";s:0:\"\";s:10:\"media_type\";s:5:\"image\";s:9:\"mime_type\";s:9:\"image/png\";s:13:\"media_details\";a:6:{s:5:\"width\";i:1025;s:6:\"height\";i:578;s:4:\"file\";s:44:\"2024/09/Nha-sang-lap-ty-phu-cua-Duolingo.png\";s:8:\"filesize\";i:148404;s:5:\"sizes\";a:7:{s:21:\"woocommerce_thumbnail\";a:6:{s:4:\"file\";s:44:\"Nha-sang-lap-ty-phu-cua-Duolingo-450x450.png\";s:5:\"width\";i:450;s:6:\"height\";i:450;s:8:\"filesize\";i:168069;s:9:\"mime_type\";s:9:\"image/png\";s:10:\"source_url\";s:97:\"https://blog.kenfinly.com/wp-content/uploads/2024/09/Nha-sang-lap-ty-phu-cua-Duolingo-450x450.png\";}s:29:\"woocommerce_gallery_thumbnail\";a:6:{s:4:\"file\";s:44:\"Nha-sang-lap-ty-phu-cua-Duolingo-100x100.png\";s:5:\"wid