:{i:0;a:1:{i:0;a:6:{s:2:\"id\";i:40;s:4:\"link\";s:40:\"https://blog.kenfinly.com/category/sach/\";s:4:\"name\";s:5:\"Sách\";s:4:\"slug\";s:4:\"sach\";s:8:\"taxonomy\";s:8:\"category\";s:6:\"_links\";a:5:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:53:\"https://blog.kenfinly.com/wp-json/wp/v2/categories/40\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/categories\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/taxonomies/category\";}}s:12:\"wp:post_type\";a:1:{i:0;a:1:{s:4:\"href\";s:59:\"https://blog.kenfinly.com/wp-json/wp/v2/posts?categories=40\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}}}i:1;a:0:{}}}}s:7:\"headers\";a:2:{s:5:\"total\";s:1:\"1\";s:11:\"total_pages\";s:1:\"1\";}}',1769912757),('kenfinly-cache-wordpress:posts:slug:tu-oc-vit-den-tham-vong-tro-thanh-san-linh-kien-hang-dau-viet-nam:d751713988987e9331980363e24189ce','a:3:{s:7:\"success\";b:1;s:4:\"data\";a:26:{s:2:\"id\";i:1550;s:4:\"date\";s:19:\"2024-11-14T10:09:24\";s:8:\"date_gmt\";s:19:\"2024-11-14T03:09:24\";s:4:\"guid\";a:1:{s:8:\"rendered\";s:33:\"https://blog.kenfinly.com/?p=1550\";}s:8:\"modified\";s:19:\"2024-11-14T10:09:24\";s:12:\"modified_gmt\";s:19:\"2024-11-14T03:09:24\";s:4:\"slug\";s:65:\"tu-oc-vit-den-tham-vong-tro-thanh-san-linh-kien-hang-dau-viet-nam\";s:6:\"status\";s:7:\"publish\";s:4:\"type\";s:4:\"post\";s:4:\"link\";s:101:\"https://blog.kenfinly.com/giao-duc/tu-oc-vit-den-tham-vong-tro-thanh-san-linh-kien-hang-dau-viet-nam/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:87:\"Từ ốc vít đến tham vọng trở thành sàn linh kiện hàng đầu Việt Nam\";}s:7:\"content\";a:2:{s:8:\"rendered\";s:10994:\"\n<p class=\"has-system-serif-font-family\"><em>Hồi còn đi học cấp 3, rồi Đại học, mình thường được nghe đến câu chuyện Việt Nam không làm nổi được cái ốc vít &#8230; Lúc đó, và kể cả gần đây mình tò mò, tự đặt câu hỏi là, &#8220;tại sao?&#8221; , nếu như vậy thì tại sao không có ai khởi nghiệp, làm thật tốt việc đó đi? Chế tạo tên lửa, chế tạo máy bay khó hơn mà?</em></p>\n\n\n\n<p class=\"has-system-serif-font-family\">&#8220;Nếu bạn tìm một sản phẩm với số lượng lớn, giá trị cao thì Mecsu có thể không phải lựa chọn duy nhất, nhưng nếu bạn cần 100 sản phẩm với số lượng một vài con thì chính xác Mecsu.vn là sự lựa chọn rất đáng cân nhắc.&#8221;</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"640\" height=\"400\" src=\"https://blog.kenfinly.com/wp-content/uploads/2024/11/image-34.png\" alt=\"\" class=\"wp-image-1551\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2024/11/image-34.png 640w, https://blog.kenfinly.com/wp-content/uploads/2024/11/image-34-600x375.png 600w, https://blog.kenfinly.com/wp-content/uploads/2024/11/image-34-300x188.png 300w\" sizes=\"auto, (max-width: 640px) 100vw, 640px\" /></figure>\n\n\n\n<p class=\"has-system-serif-font-family\">Hành trình của Mecsu bắt đầu từ những khó khăn của một kỹ sư, khi tìm kiếm linh kiện và vật tư công nghiệp tại các chợ truyền thống Việt Nam nhằm phục vụ cho các dự án thiết kế robot. Qua gần một thập kỷ, Mecsu đã tích lũy nhiều kinh nghiệm quý báu và hướng đến trở thành nền tảng thương mại điện tử hàng đầu về linh kiện và vật tư công nghiệp phụ trợ tại Việt Nam.</p>\n\n\n\n<h3 class=\"wp-block-heading has-system-serif-font-family\"><strong>Nhìn thấy cơ hội từ những vấn đề nhức nhối</strong></h3>\n\n\n\n<p class=\"has-system-serif-font-family\">Trước đó, anh Trương Quang Thạnh &#8211; một kỹ sư thiết kế đang làm việc trong ngành bán dẫn tại Mỹ nhận thấy những bất cập trong việc tìm kiếm phụ tùng và dụng cụ công nghiệp tại các chợ truyền thống Việt Nam. Đồng thời, trong quá trình sinh sống và làm việc tại nước ngoài, anh không khỏi choáng ngợp trước hệ thống tìm kiếm và mua sắm linh kiện, vật tư vừa chuyên nghiệp vừa hiện đại dành cho ngành công nghiệp.</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Đặt biệt, giai đoạn 2015-2016, Việt Nam chứng kiến những bước tiến mới trong ngành công nghiệp nói riêng và nền kinh tế nói chung. Khi hàng loạt những tập đoàn đa quốc gia lựa chọn Việt Nam là nơi đặt nhà máy phục vụ cho quá trình sản xuất. Sự phát triển của ngành công nghiệp là cơ hội và thách thức lớn cho ngành công nghiệp phụ trợ còn non trẻ tại Việt Nam.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"602\" height=\"376\" src=\"https://blog.kenfinly.com/wp-content/uploads/2024/11/image-35.png\" alt=\"\" class=\"wp-image-1552\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2024/11/image-35.png 602w, https://blog.kenfinly.com/wp-content/uploads/2024/11/image-35-600x375.png 600w, https://blog.kenfinly.com/wp-content/uploads/2024/11/image-35-300x187.png 300w\" sizes=\"auto, (max-width: 602px) 100vw, 602px\" /><figcaption class=\"wp-element-caption\">Logo của thương hiệu Mecsu lần đầu tiên xuất hiện tại quận Tân Phú, TP HCM</figcaption></figure>\n\n\n\n<p class=\"has-system-serif-font-family\">Đứng trước những trăn trở cá nhân và nhu cầu cấp thiết của thị trường, người kỹ sư trẻ cùng anh bạn đại học &#8211; Lê Trần Phúc Đại đã nhen nhóm ý tưởng xây dựng một nền tảng mua sắm dành riêng cho linh kiện và vật tư công nghiệp. Nền tảng này kỳ vọng sẽ thay đổi thói quen mua hàng kém hiệu quả tại các chợ truyền thống Việt Nam sang hình thức mua sắm trực tuyến.</p>\n\n\n\n<h3 class=\"wp-block-heading has-system-serif-font-family\"><strong>Khởi đầu từ ốc vít đến những bước tiến lớn</strong></h3>\n\n\n\n<p class=\"has-system-serif-font-family\">Những ngày đầu khởi nghiệp, các nhà sáng lập và cộng sự tại Mecsu đã chọn con đường <strong>&#8220;nghĩ lớn và làm từ những điều nhỏ nhất.&#8221;</strong> Họ nhanh chóng nhận ra cơ hội trong thị trường bulong &#8211; con tán, sản phẩm nhỏ với giá trị thấp nên ít được chú ý nhưng không thể thiếu trong mọi nhà máy. <strong>Với quyết tâm khai thác giá trị từ những thứ cơ bản nhất</strong>, <strong>Mecsu bấy giờ tin rằng nếu quản lý và phát triển được ốc vít, thì mọi thứ khác sẽ trở nên dễ dàng hơn</strong>. Tinh thần &#8220;Hoàn thành mục tiêu lớn từ những điều nhỏ nhất&#8221; đã trở thành kim chỉ nam cho toàn bộ đội ngũ từ khởi đầu đến ngày hôm nay.</p>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"602\" height=\"376\" src=\"https://blog.kenfinly.com/wp-content/uploads/2024/11/image-36.png\" alt=\"\" class=\"wp-image-1553\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2024/11/image-36.png 602w, https://blog.kenfinly.com/wp-content/uploads/2024/11/image-36-600x375.png 600w, https://blog.kenfinly.com/wp-content/uploads/2024/11/image-36-300x187.png 300w\" sizes=\"auto, (max-width: 602px) 100vw, 602px\" /><figcaption class=\"wp-element-caption\">Mecsu.vn được thành lập vào năm 2014</figcaption></figure>\n\n\n\n<p class=\"has-system-serif-font-family\">Dù khởi nghiệp đầy thách thức, các nhà sáng lập Mecsu đã vượt qua khó khăn để xây dựng nền tảng mua sắm hàng đầu trong ngành công nghiệp phụ trợ, phục vụ hơn 10.000 khách hàng. Ngay từ đầu, Mecsu đã áp dụng ERP và CRM để tối ưu quy trình vận hành. Đáng chú ý, toàn bộ hệ thống quản lý, từ thiết kế đến triển khai, đều do đội ngũ kỹ sư của công ty phát triển, <strong>tạo nền tảng vững chắc cho những tham vọng lớn trong tương lai</strong>.</p>\n\n\n\n<h3 class=\"wp-block-heading has-system-serif-font-family\"><strong>Những thách thức trong chuỗi cung cứng công nghiệp phụ trợ</strong></h3>\n\n\n\n<figure class=\"wp-block-image size-full\"><img loading=\"lazy\" decoding=\"async\" width=\"602\" height=\"376\" src=\"https://blog.kenfinly.com/wp-content/uploads/2024/11/image-37.png\" alt=\"\" class=\"wp-image-1554\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2024/11/image-37.png 602w, https://blog.kenfinly.com/wp-content/uploads/2024/11/image-37-600x375.png 600w, https://blog.kenfinly.com/wp-content/uploads/2024/11/image-37-300x187.png 300w\" sizes=\"auto, (max-width: 602px) 100vw, 602px\" /><figcaption class=\"wp-element-caption\">Kho hàng Mecsu với diện tích lớn lên đến 2000m2</figcaption></figure>\n\n\n\n<p class=\"has-system-serif-font-family\">Trong quá trình phát triển, Mecsu nhận thấy các doanh nghiệp Việt Nam gặp nhiều thách thức trong chuỗi cung ứng công nghiệp phụ trợ. Sự phụ thuộc vào nhà cung cấp nước ngoài và quy trình quản lý thủ công đã làm tăng chi phí và ảnh hưởng đến tính ổn định của hoạt động sản xuất. Từ năm 2024, với những thành tựu đã đạt được và đội ngũ trẻ tài năng, Mecsu &#8211; một công ty do người Việt xây dựng &#8211; đặt mục tiêu trở thành nền tảng thay thế các kênh truyền thống trong ngành công nghiệp phụ trợ với mốc thời gian 5-10 năm tới.</p>\n\n\n\n<h3 class=\"wp-block-heading has-system-serif-font-family\"><strong>Tham vọng trở thành sàn B2B lớn nhất Việt Nam</strong></h3>\n\n\n\n<figure class=\"wp-block-image size-large\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"640\" src=\"https://blog.kenfinly.com/wp-content/uploads/2024/11/image-38-1024x640.png\" alt=\"\" class=\"wp-image-1555\" srcset=\"https://blog.kenfinly.com/wp-content/uploads/2024/11/image-38-1024x640.png 1024w, https://blog.kenfinly.com/wp-content/uploads/2024/11/image-38-600x375.png 600w, https://blog.kenfinly.com/wp-content/uploads/2024/11/image-38-300x188.png 300w, https://blog.kenfinly.com/wp-content/uploads/2024/11/image-38-768x480.png 768w, https://blog.kenfinly.com/wp-content/uploads/2024/11/image-38-1536x960.png 1536w, https://blog.kenfinly.com/wp-content/uploads/2024/11/image-38.png 2000w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /><figcaption class=\"wp-element-caption\">Mecsu.vn &#8211; Hướng đến trở thành sàn thương mại điện tử Việt Nam hàng đầu chuyên cung cấp linh kiện và vật tư cho ngành công nghiệp phụ trợ</figcaption></figure>\n\n\n\n<p class=\"has-system-serif-font-family\">Sau gần 10 năm làm nghề, và thử nghiệm nhiều mô hình kinh doanh, các nhà sáng lập Mecsu đã tự hỏi: Nếu Nhật, Mỹ, Hàn Quốc đã xây dựng được những nền tảng thương mại công nghiệp trị giá hàng tỷ đô, tại sao Việt Nam vẫn chưa có? Mecsu sẽ đóng góp ra sao cho ngành công nghiệp phụ trợ nói riêng và ngành công nghiệp Việt Nam nói chung?</p>\n\n\n\n<p class=\"has-system-serif-font-family\">Những trăn trở đó chính là nguồn động lực để Mecsu không ngừng phấn đấu mỗi ngày. Với tầm nhìn rõ ràng, đội ngũ Mecsu quyết tâm hoàn thiện từng bước nhỏ để đi đến tham vọng lớn. Dù 5, 10 hay 30 năm, chúng tôi phải trở thành người tiên phong trong việc chuyển đối mua sắm của ngành công nghiệp và là đối trọng lớn của các tập đoàn đa quốc gia tại Việt Nam.</p>\n\n\n\n<p></p>\n\n\n\n<p class=\"has-system-serif-font-family\"><strong>Quay trở lại với &#8220;mình&#8221;. Việt Nam đã làm được ốc vít rồi, câu nói xưa đã trở nên outdated-lỗi thời. Điều tiếp theo sẽ là gì?</strong></p>\n\n\n\n<p class=\"has-text-align-right has-system-serif-font-family\"><em>Dieter R, nguồn: <a href=\"https://phunuso.baophunuthudo.vn/tu-oc-vit-den-tham-vong-tro-thanh-san-linh-kien-hang-dau-viet-nam-193241112170902182.htm\" data-type=\"link\" data-id=\"https://phunuso.baophunuthudo.vn/tu-oc-vit-den-tham-vong-tro-thanh-san-linh-kien-hang-dau-viet-nam-193241112170902182.htm\">https://phunuso.baophunuthudo.vn/tu-oc-vit-den-tham-vong-tro-thanh-san-linh-kien-hang-dau-viet-nam-193241112170902182.htm</a></em></p>\n\n\n\n<p></p>\n\";s:9:\"protected\";b:0;}s:7:\"excerpt\";a:2:{s:8:\"rendered\";s:350:\"<p>Hồi còn đi học cấp 3, rồi Đại học, mình thường được nghe đến câu chuyện Việt Nam không làm nổi được cái ốc vít &#8230; Lúc đó, và kể cả gần đây mình tò mò, tự đặt câu hỏi là, &#8220;tại sao?&#8221; , nếu như vậy thì tại sao không có ai khởi nghiệp, [&hellip;]</p>\n\";s:9:\"protected\";b:0;}s:6:\"author\";i:1;s:14:\"featured_media\";i:1556;s:14:\"comment_status\";s:4:\"open\";s:11:\"ping_status\";s:4:\"open\";s:6:\"sticky\";b:0;s:8:\"template\";s:0:\"\";s:6:\"format\";s:8:\"standard\";s:4:\"meta\";a:1:{s:9:\"footnotes\";s:0:\"\";}s:10:\"categories\";a:2:{i:0;i:5;i:1;i:6;}s:4:\"tags\";a:2:{i:0;i:230;i:1;i:229;}s:10:\"class_list\";a:11:{i:0;s:9:\"post-1550\";i:1;s:4:\"post\";i:2;s:9:\"type-post\";i:3;s:14:\"status-publish\";i:4;s:15:\"format-standard\";i:5;s:18:\"has-post-thumbnail\";i:6;s:6:\"hentry\";i:7;s:17:\"category-giao-duc\";i:8;s:16:\"category-tin-tuc\";i:9;s:9:\"tag-mecsu\";i:10;s:35:\"tag-san-linh-kien-hang-dau-viet-nam\";}s:6:\"_links\";a:11:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/1550\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/posts\";}}s:5:\"about\";a:1:{i:0;a:1:{s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/types/post\";}}s:6:\"author\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";}}s:7:\"replies\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:58:\"https://blog.kenfinly.com/wp-json/wp/v2/comments?post=1550\";}}s:15:\"version-history\";a:1:{i:0;a:2:{s:5:\"count\";i:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/1550/revisions\";}}s:19:\"predecessor-version\";a:1:{i:0;a:2:{s:2:\"id\";i:1557;s:4:\"href\";s:65:\"https://blog.kenfinly.com/wp-json/wp/v2/posts/1550/revisions/1557\";}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:2:{s:10:\"embeddable\";b:1;s:4:\"href\";s:50:\"https://blog.kenfinly.com/wp-json/wp/v2/media/1556\";}}s:13:\"wp:attachment\";a:1:{i:0;a:1:{s:4:\"href\";s:57:\"https://blog.kenfinly.com/wp-json/wp/v2/media?parent=1550\";}}s:7:\"wp:term\";a:2:{i:0;a:3:{s:8:\"taxonomy\";s:8:\"category\";s:10:\"embeddable\";b:1;s:4:\"href\";s:60:\"https://blog.kenfinly.com/wp-json/wp/v2/categories?post=1550\";}i:1;a:3:{s:8:\"taxonomy\";s:8:\"post_tag\";s:10:\"embeddable\";b:1;s:4:\"href\";s:54:\"https://blog.kenfinly.com/wp-json/wp/v2/tags?post=1550\";}}s:6:\"curies\";a:1:{i:0;a:3:{s:4:\"name\";s:2:\"wp\";s:4:\"href\";s:23:\"https://api.w.org/{rel}\";s:9:\"templated\";b:1;}}}s:9:\"_embedded\";a:3:{s:6:\"author\";a:1:{i:0;a:8:{s:2:\"id\";i:1;s:4:\"name\";s:9:\"Dieter R.\";s:3:\"url\";s:16:\"http://kenkai.vn\";s:11:\"description\";s:401:\"Xin chào, tôi là Dieter R., một cây bút đam mê tại KenkAI.vn, đang sinh sống và làm việc tại Thành phố Hồ Chí Minh sôi động. Với niềm đam mê mãnh liệt về lĩnh vực lãnh đạo, tâm lý học, trí tuệ nhân tạo, công nghệ và phát triển bản thân, tôi luôn nỗ lực mang đến những nội dung giá trị và sâu sắc cho độc giả.\";s:4:\"link\";s:40:\"https://blog.kenfinly.com/author/dieter/\";s:4:\"slug\";s:6:\"dieter\";s:11:\"avatar_urls\";a:3:{i:24;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=24&d=mm&r=g\";i:48;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=48&d=mm&r=g\";i:96;s:113:\"https://secure.gravatar.com/avatar/ae239d95a06b5ae3ab1be67ca43ed70bd28405966d4e3e2cb18c7bec0635ba0e?s=96&d=mm&r=g\";}s:6:\"_links\";a:2:{s:4:\"self\";a:1:{i:0;a:2:{s:4:\"href\";s:47:\"https://blog.kenfinly.com/wp-json/wp/v2/users/1\";s:11:\"targetHints\";a:1:{s:5:\"allow\";a:1:{i:0;s:3:\"GET\";}}}}s:10:\"collection\";a:1:{i:0;a:1:{s:4:\"href\";s:45:\"https://blog.kenfinly.com/wp-json/wp/v2/users\";}}}}}s:16:\"wp:featuredmedia\";a:1:{i:0;a:15:{s:2:\"id\";i:1556;s:4:\"date\";s:19:\"2024-11-14T10:09:06\";s:4:\"slug\";s:6:\"oc-vit\";s:4:\"type\";s:10:\"attachment\";s:4:\"link\";s:119:\"https://blog.kenfinly.com/giao-duc/tu-oc-vit-den-tham-vong-tro-thanh-san-linh-kien-hang-dau-viet-nam/attachment/oc-vit/\";s:5:\"title\";a:1:{s:8:\"rendered\";s:6:\"oc-vit\";}s:6:\"author\";i:1;s:14:\"featured_media\";i:0;s:7:\"caption\";a:1:{s:8:\"rendered\";s:95:\"<p>Từ ốc vít đến tham vọng trở thành sàn linh kiện hàng đầu Việt Nam</p>\n\";}s:8:\"alt_text\";